-- 07_dml_update_poi_content.sql
-- Backfills/normalizes poi.summary and poi.description for all POIs whose content
-- was missing or out of spec (summary 1-3 sentences; description <= 300 words).
-- Idempotent: UPDATE-by-slug, touches only these two columns. Safe to re-run.
-- Generated from backend/db/poi_content_review.md. Run AFTER 03_dml_seed_poi_table.sql.

BEGIN;

UPDATE poi SET
  summary = 'The National September 11 Memorial & Museum sits at the World Trade Center site in Lower Manhattan, commemorating the victims of the September 11, 2001 and 1993 attacks. Its memorial features twin reflecting pools set within the footprints of the destroyed Twin Towers, ringed by the names of the nearly 3,000 victims, while an underground museum documents the events and their aftermath.',
  description = 'The National September 11 Memorial & Museum is a memorial and museum at the World Trade Center in Lower Manhattan, honoring the 2,977 people killed in the September 11, 2001 attacks and the six killed in the 1993 World Trade Center bombing. The memorial, designed by architect Michael Arad with landscape architect Peter Walker, opened on the tenth anniversary of the attacks in 2011. It centers on two large recessed reflecting pools, each nearly an acre, set within the footprints of the original Twin Towers, with water cascading down their sides into the largest man-made waterfalls in North America. Bronze parapets around the pools are inscribed with the names of every victim of both attacks. Surrounding the pools is a plaza planted with hundreds of swamp white oak trees, including the "Survivor Tree," a pear tree that lived through the attacks. The associated museum, opened in 2014, lies largely below ground within the archaeological heart of the site, between the tower footprints. Its exhibitions trace the events of the day, the history of the World Trade Center, and the response and recovery, displaying artifacts such as damaged emergency vehicles, remnants of the towers'' structure, and personal effects. The memorial and museum are among the most-visited sites in New York, serving both as a place of mourning and as a public record of the attacks.'
WHERE slug = '9-11-memorial-museum';

UPDATE poi SET
  summary = 'The Al Hirschfeld Theatre is a Broadway theater at 302 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1924 as the Martin Beck Theatre and renamed in 2003 for the caricaturist Al Hirschfeld, it seats about 1,400 and is operated by ATG Entertainment.',
  description = 'The Al Hirschfeld Theatre is a Broadway house at 302 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1924 as the Martin Beck Theatre—built by and named for the vaudeville impresario Martin Beck—it was designed by architect G. Albert Lansburgh in a distinctive Byzantine and Moorish-influenced style unusual among Broadway houses. Seating roughly 1,400, it was renamed in 2003 to honor Al Hirschfeld, the celebrated caricaturist whose line drawings of Broadway performers appeared for decades in The New York Times. The theater is operated by ATG Entertainment, which absorbed Jujamcyn Theaters in 2023. Over its long history it has premiered and hosted major plays and musicals, including works by leading playwrights and long-running productions. Its ornate interior and facade contribute to the architectural richness of the Theater District, and the Al Hirschfeld remains an active venue for Broadway musicals.'
WHERE slug = 'al-hirschfeld-theatre';

UPDATE poi SET
  summary = 'Alamo Drafthouse Cinema is a dine-in movie theater in Lower Manhattan, part of the Alamo Drafthouse chain known for in-theater food and drink service and a strict no-talking, no-texting policy. It screens new releases, independent films, and special repertory programming.',
  description = 'Alamo Drafthouse Cinema Lower Manhattan is a dine-in movie theater in the Financial District of Lower Manhattan, an outpost of the Austin-founded Alamo Drafthouse chain. Like others in the chain, it is known for combining a full menu of food and drinks—served to viewers at their seats during the film—with a serious cinephile ethos, including a well-enforced policy against talking and phone use during screenings. Its programming blends mainstream new releases with independent and foreign films, cult classics, themed events, and repertory series, often accompanied by special menus or pre-show content curated to match the movie. The theater''s multiple auditoriums and adjoining bar make it both a place to see a film and a social destination. Part of a wave of upscale, experience-focused cinemas, Alamo Drafthouse Lower Manhattan offers moviegoers a comfortable, food-and-drink-oriented alternative to conventional multiplexes in a busy part of downtown.'
WHERE slug = 'alamo-drafthouse-cinema-lower-manhattan';

UPDATE poi SET
  summary = 'The Ambassador Theatre is a Broadway theater at 219 West 49th Street in the Theater District of Midtown Manhattan. Opened in 1921 and designed by Herbert J. Krapp for the Shubert brothers, it seats about 1,100 and is operated by the Shubert Organization.',
  description = 'The Ambassador Theatre is a Broadway house at 219 West 49th Street in the Theater District of Midtown Manhattan. Opened in 1921 and designed by architect Herbert J. Krapp for the Shubert brothers, it was built diagonally on its lot—an unusual arrangement that allowed a larger seating capacity of roughly 1,100 on the available land. Operated by the Shubert Organization, it left the family''s control for a period in the mid-20th century, when it was used for radio and television broadcasts and even films, before returning to legitimate theatrical use. Its interior features the Adam-style plaster detailing characteristic of Krapp''s designs. Over the decades the Ambassador has hosted a variety of plays and musicals, and for much of the 21st century it was home to the long-running revival of the musical "Chicago." A mid-sized house in the heart of the Theater District, it remains an active Broadway venue.'
WHERE slug = 'ambassador-theatre';

UPDATE poi SET
  summary = 'The American Museum of Natural History (AMNH) is a natural history museum on the Upper West Side of Manhattan, set in Theodore Roosevelt Park across from Central Park. Its complex of 21 interconnected buildings houses 45 permanent exhibition halls, a planetarium, and a library, with collections of some 32 million specimens and artifacts. It averages about five million visits a year.',
  description = 'The American Museum of Natural History (AMNH) is a natural history museum on the Upper West Side of Manhattan. Located in Theodore Roosevelt Park, across the street from Central Park, the museum complex comprises 21 interconnected buildings housing 45 permanent exhibition halls, in addition to a planetarium and a library. Its collections contain about 32 million specimens of plants, animals, fungi, fossils, minerals, rocks, meteorites, human remains, and cultural artifacts, along with specialized collections of frozen tissue and genomic and astrophysical data, of which only a small fraction can be displayed at any time. The museum occupies more than 2.5 million square feet, has a full-time scientific staff of around 225, sponsors over 120 field expeditions each year, and averages about five million visits annually. A private nonprofit organization, it was conceived by the naturalist Albert S. Bickmore in 1861 and opened within Central Park''s Arsenal in 1871. Its first purpose-built structure in Theodore Roosevelt Park, designed by Calvert Vaux and J. Wrey Mould, opened in 1877, and numerous wings have since been added, including the Theodore Roosevelt entrance pavilion in 1936 and the Rose Center for Earth and Space in 2000.'
WHERE slug = 'american-museum-of-natural-history';

UPDATE poi SET
  summary = 'The Angelika Film Center is a well-known arthouse cinema at 18 West Houston Street in the Greenwich Village/NoHo area of Manhattan. Specializing in independent and foreign films, it is recognized for its café and its distinctive below-ground theaters.',
  description = 'The Angelika Film Center & Café is a landmark independent movie theater at 18 West Houston Street, at the corner of Mercer Street on the border of Greenwich Village, NoHo, and SoHo in Manhattan. Opened in 1989 in a historic Beaux-Arts building, it became one of New York''s premier venues for independent, foreign, and art-house cinema, helping define the specialty film scene of the era. The complex features multiple screening rooms located below street level and a ground-floor café serving coffee and light fare that doubles as a gathering place for filmgoers—an early example of pairing an arthouse cinema with a café atmosphere. Known for its eclectic programming of new independent releases, documentaries, and international films, the Angelika has long been a hub for cinephiles and a fixture of downtown Manhattan''s cultural life. Despite the rumble of the subway occasionally felt in its underground theaters, it remains one of the city''s best-loved specialty cinemas.'
WHERE slug = 'angelika-film-center-cafe-new-york';

UPDATE poi SET
  summary = 'The Apollo Theater is a historic 1,500-seat music hall at 253 West 125th Street in Harlem, long a landmark venue for Black American performers. Opened in 1913 and turned to Black audiences and artists in 1934, it is famous for its weekly Amateur Night. Its facade and interior are New York City landmarks, operated by the nonprofit Apollo Theater Foundation.',
  description = 'The Apollo Theater is a multi-use theater at 253 West 125th Street in the Harlem neighborhood of Upper Manhattan, one of the most storied venues for Black American performers and the longtime home of Amateur Night at the Apollo. Designed by George Keister in a neoclassical style, it seats roughly 1,500 across three levels, and its facade and interior are New York City landmarks listed on the National Register of Historic Places. It was built as a burlesque house in 1913, originally serving only white patrons; after Sidney Cohen acquired it in 1934 it became a venue for Black performers, and Frank Schiffman''s family operated it from 1935 to 1976. Former Manhattan borough president Percy Sutton bought it at auction in 1981, and it reopened in 1985 after a major refurbishment that added recording studios. In 1991 the state took ownership and assigned operation to the nonprofit Apollo Theater Foundation. Its weekly Amateur Night lets audiences judge novice performers, and many famous artists are inducted into the Apollo Legends Hall of Fame. Over the decades the theater has hosted countless music, dance, comedy, and theatrical acts, as well as film screenings, recordings, speeches, and tributes, exerting a profound influence on African-American culture.'
WHERE slug = 'apollo-theater';

UPDATE poi SET
  summary = 'Arte Museum New York is an immersive media-art exhibition at Chelsea Piers on Manhattan''s Hudson River waterfront, created by the South Korean digital design company d''strict. It fills a series of rooms with large-scale digital projections, soundscapes, and scents, turning natural and urban imagery into enveloping "media art" environments.',
  description = 'Arte Museum New York is an immersive media-art exhibition located at Chelsea Piers along Manhattan''s Hudson River waterfront. A New York edition of the popular Arte Museum concept created by the South Korean digital design company d''strict, it presents a sequence of roughly 16 room-scale "media artworks" that combine floor-to-ceiling projections with evocative soundscapes by composer Young-gyu Jang and custom fragrances. Visitors move through immersive environments—among them nature-themed scenes such as flowers and a shoreline, some previously shown in Korea, alongside works inspired by New York City itself. The journey culminates in a room that transforms an animated New York scene, complete with a Brooklyn Bridge rendered in light, into a gallery of Impressionist and Post-Impressionist masterpieces projected at monumental scale. A tea café, where drinks are paired with projected imagery, completes the roughly 90-minute experience. Arte Museum is among the wave of immersive, technology-driven art attractions that have opened in the city.'
WHERE slug = 'arte-museum-new-york';

UPDATE poi SET
  summary = 'ARTECHOUSE NYC is an immersive digital art space beneath Chelsea Market in Manhattan, set in a converted century-old boiler room. It presents rotating, room-scale projected exhibitions where art, technology, and sound design merge, typically changing several times a year.',
  description = 'ARTECHOUSE NYC is an immersive digital art venue in the historic Chelsea Market building on Manhattan''s West Side, occupying a roughly 6,000-square-foot space in a century-old former boiler room beneath the market. Part of the ARTECHOUSE network of digital art spaces, it is devoted to exhibitions where art and technology converge, presenting large-scale works by digital artists from around the world. Its main gallery wraps visitors in floor-to-ceiling projections—an environment of moving imagery synchronized with immersive sound design—so that the artwork surrounds and responds to the audience rather than hanging on a wall. Exhibitions rotate regularly, typically several times per year, ranging from data-driven abstract works to nature- and science-themed installations, and often include interactive elements. The venue has become a fixture of Chelsea''s arts scene and part of a broader wave of immersive, experience-based art destinations in New York.'
WHERE slug = 'artechouse-nyc';

UPDATE poi SET
  summary = 'The Astor Place Theatre is an Off-Broadway theater at 434 Lafayette Street near Astor Place in Manhattan, housed in the landmark Colonnade Row buildings. It is best known as the longtime home of the resident show "Blue Man Group."',
  description = 'The Astor Place Theatre is an Off-Broadway venue at 434 Lafayette Street, near Astor Place on the border of NoHo and Greenwich Village in Manhattan. It occupies part of Colonnade Row (also known as LaGrange Terrace), a landmarked row of Greek Revival marble-columned houses built in the 1830s. The intimate theater, seating a few hundred, is best known as the New York home of "Blue Man Group," the wordless percussion-and-comedy performance show that has run there since 1991, making it one of the longest-running shows in the city. The venue''s small scale and downtown location have made it a fixture of the Off-Broadway scene. While closely identified with its long-running resident production, the Astor Place Theatre and its historic Colonnade Row setting are notable both as a performance space and as a piece of 19th-century New York architecture.'
WHERE slug = 'astor-place-theatre';

UPDATE poi SET
  summary = 'The August Wilson Theatre is a Broadway theater at 245 West 52nd Street in the Theater District of Midtown Manhattan. Opened in 1925 and designed for the Theatre Guild, it seats about 1,225 and is operated by ATG Entertainment. In 2005 it became the first Broadway theater named for an African American, honoring Pulitzer Prize-winning playwright August Wilson.',
  description = 'The August Wilson Theatre, formerly the Guild, ANTA, and Virginia Theatre, is a Broadway theater at 245 West 52nd Street in the Theater District of Midtown Manhattan. Opened in 1925 and designed by C. Howard Crane and Kenneth Franzheim for the Theatre Guild, it seats about 1,225 across two levels and is operated by ATG Entertainment; its facade is a New York City designated landmark. That facade is designed as a variation of a 15th-century Tuscan villa, with a stucco surface, quoined openings, and a loggia, and originally housed Theatre Guild facilities such as classrooms, studios, a club room, a library, and a bookstore, with the auditorium set one story above ground over a lounge. The Guild Theatre opened on April 13, 1925; its early productions ran only briefly, and from 1938 the Guild leased it to other producers. Radio station WOR used the auditorium as a studio from 1943, and the American National Theater and Academy (ANTA) bought it in 1950, reopening it as the ANTA Theatre in 1954 after a renovation. Jujamcyn Theaters purchased it in 1981, renamed it the Virginia for co-owner Virginia McKnight Binger, and renamed it for August Wilson in 2005. Productions with long runs there have included City of Angels, Smokey Joe''s Cafe, and Jersey Boys. Jujamcyn merged with ATG in 2023.'
WHERE slug = 'august-wilson-theatre';

UPDATE poi SET
  summary = 'The Banksy Museum is an exhibition of life-size reproductions of works by the anonymous street artist Banksy, located at 277 Canal Street on the edge of Chinatown in Lower Manhattan. Opened in 2024, it displays more than 160 recreated murals, billed as the largest collection of Banksy imagery in the world.',
  description = 'The Banksy Museum is a privately run exhibition devoted to the work of the anonymous British street artist Banksy, located at 277 Canal Street, near the Manhattan Bridge on the edge of Chinatown in Lower Manhattan. It opened in 2024, spanning roughly 15,000 square feet across two floors of the Oltarsh Building. Because most of Banksy''s original street works have been damaged, painted over, or removed from their walls, the museum instead presents more than 160 life-size reproductions of his murals, recreated by a team of anonymous street artists, alongside information about the pieces and their original contexts. Billed as the world''s largest collection of Banksy imagery, it is not affiliated with or authorized by the artist himself, who is not involved in the venture. The exhibition offers a walk-through survey of Banksy''s satirical, politically charged imagery—stenciled rats, balloon-holding children, and biting social commentary—gathering in one place works that are otherwise scattered across cities around the world.'
WHERE slug = 'banksy-museum-new-york';

UPDATE poi SET
  summary = 'The Beacon Theatre is a historic concert venue at 2124 Broadway on the Upper West Side of Manhattan, near West 74th Street. Opened in 1929 as a movie palace, the ornately decorated theater is now a landmark venue for concerts and live performances, seating around 2,800.',
  description = 'The Beacon Theatre is a landmark performance venue at 2124 Broadway, near 74th Street on the Upper West Side of Manhattan. Opened in 1929 and designed by architect Walter W. Ahlschlager, it was built as a lavish movie palace, with an opulent interior blending Greek, Roman, and Renaissance-inspired ornamentation, gilded details, and large murals. Seating roughly 2,800 across an orchestra and two balconies, it transitioned over the decades from films to live entertainment and is now used primarily for concerts, comedy, and other performances. Its interior is a designated New York City landmark, and a major restoration in the 2000s returned much of its original splendor. The Beacon is especially associated with residencies and multi-night concert runs by major musicians—the Allman Brothers Band famously played long annual stands there—and its intimate scale and rich acoustics have made it one of the city''s favorite mid-size music venues.'
WHERE slug = 'beacon-theatre';

UPDATE poi SET
  summary = 'The Belasco Theatre is a Broadway theater at 111 West 44th Street in the Theater District of Midtown Manhattan. Built in 1907 as the Stuyvesant Theatre and designed by George Keister for impresario David Belasco, it seats 1,016 across three levels and has been operated by the Shubert Organization since 1948. Known for its Tiffany lighting and Everett Shinn murals, both its facade and interior are New York City landmarks.',
  description = 'The Belasco Theatre is a Broadway theater at 111 West 44th Street, between Sixth and Seventh Avenues, in the Theater District of Midtown Manhattan. Originally the Stuyvesant Theatre, it was built in 1907 and designed by architect George Keister for impresario David Belasco, seats 1,016 across three levels, and has been operated by the Shubert Organization since 1948; both its facade and interior are New York City landmarks. The 44th Street facade is red brick in Flemish bond with terracotta trim, its upper stories asymmetrical and topped by a pediment. Belasco kept his offices in the western wing, and a ten-room duplex penthouse in the eastern wing held his collection of memorabilia. The richly detailed interior features Tiffany lighting and ceiling panels, elaborate woodwork, and expansive murals by the American artist Everett Shinn, over an orchestra and two overhanging balconies with boxes. Developed by Meyer R. Bimberg and run by Belasco as the Stuyvesant, the theater opened on October 16, 1907, was expanded in 1909, and was renamed for Belasco in 1910. After his death in 1931 it was leased to various producers; the Shuberts bought it in 1948, leased it to NBC for three years, then returned it to legitimate use in 1953. It has continued to present Broadway plays and musicals and has been renovated several times.'
WHERE slug = 'belasco-theatre';

UPDATE poi SET
  summary = 'Bella Abzug Park is a landscaped public park in the Hudson Yards neighborhood on Manhattan''s West Side, part of the Hudson Park and Boulevard green corridor. Named for the pioneering congresswoman Bella Abzug, it offers lawns, trees, fountains, and seating amid the area''s high-rise development.',
  description = 'Bella Abzug Park is a public park in the Hudson Yards neighborhood on the far West Side of Manhattan, forming part of the Hudson Park and Boulevard—a landscaped green corridor created to serve the district''s dense new development. Running in sections along a boulevard roughly between 33rd and 39th Streets near Tenth Avenue, the park is named for Bella Abzug (1920–1998), the outspoken New York congresswoman, lawyer, and leader of the women''s and civil-rights movements. Its blocks offer manicured lawns, tree plantings, seating, and water features, providing open green space among the office and residential towers of Hudson Yards and the surrounding area. Built atop the rail yards and infrastructure that shaped the neighborhood''s redevelopment, the park serves as a pedestrian spine and neighborhood gathering place, connecting the growing Hudson Yards district to nearby transit and to other West Side open spaces.'
WHERE slug = 'bella-abzug-park';

UPDATE poi SET
  summary = 'Bloomingdale''s is a landmark upscale department store occupying a full block on the Upper East Side of Manhattan, at Lexington Avenue and 59th Street. The flagship of the Bloomingdale''s chain, it has been at this location since the 1880s and is known for its fashion, its "Little Brown Bag," and its window displays.',
  description = 'Bloomingdale''s flagship store occupies the block bounded by Lexington and Third Avenues and 59th and 60th Streets on the Upper East Side of Manhattan. Founded by brothers Joseph and Lyman Bloomingdale, the store established itself at this Lexington Avenue location in 1886 and expanded over the decades to fill the entire block, its facade combining several architectural styles, including Art Deco. Long positioned as a fashionable, upscale department store, "Bloomie''s" built a reputation for designer clothing, cosmetics, and home goods, and for trend-setting merchandising and theatrical window and in-store displays. Its distinctive brown shopping bags—the "Little Brown Bag" and its variants—became a recognizable emblem of the brand. A fixture of New York shopping and a popular stop for visitors, the Lexington Avenue flagship remains the chain''s signature store, drawing crowds during holidays and sales, and it anchors the retail district near the southeastern corner of Central Park.'
WHERE slug = 'bloomingdale-s';

UPDATE poi SET
  summary = 'Bow Bridge is a graceful cast-iron footbridge in Central Park, spanning the Lake between Cherry Hill and the Ramble in Manhattan. Built in the 1860s, its elegant bow-shaped form makes it one of the park''s most photographed and romantic landmarks.',
  description = 'Bow Bridge is a cast-iron pedestrian bridge crossing the Lake in Central Park, connecting the area around Cherry Hill on the west with the wooded Ramble to the north. Designed by Calvert Vaux and Jacob Wrey Mould and completed in 1862, it is one of the oldest cast-iron bridges in the United States and among the earliest structures built in the park. Its name comes from its shape, which resembles the bow of an archer or a violin—a long, low, gently arcing span decorated with ornamental ironwork and urns. Stretching about 60 feet across the water, the bridge offers sweeping views of the Lake, the surrounding foliage, and the buildings lining Central Park West and the Upper West Side. Long a favorite spot for strolling, wedding photographs, and film scenes, Bow Bridge is one of the most romantic and frequently photographed features of Central Park, and it was restored in the 1970s to preserve its original design.'
WHERE slug = 'bow-bridge';

UPDATE poi SET
  summary = 'The Broadhurst Theatre is a Broadway theater at 235 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1917, it was designed by Herbert J. Krapp for the Shubert brothers and named for producer George Broadhurst. Seating 1,218 and operated by the Shubert Organization, it has hosted long-running shows from Cabaret and Grease to Les Misérables and Mamma Mia!.',
  description = 'The Broadhurst Theatre is a Broadway theater at 235 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1917 and designed by Herbert J. Krapp for the Shubert brothers, it is named for the British-American producer George Broadhurst, who leased it before its opening. It seats 1,218 across two levels, is operated by the Shubert Organization, and both its facade and auditorium are New York City landmarks. The simple neoclassical facade, similar to the concurrently built Schoenfeld Theatre, is of buff-colored brick and terracotta, divided into a western stage house and an eastern entrance with a curved corner facing Broadway. The auditorium has an orchestra level, a large balcony, and a flat ceiling, decorated in classical Greek and Adam styles with Doric columns and Greek friezes, and box seats flanking the proscenium. The Shuberts developed the Broadhurst and Plymouth (now Schoenfeld) theaters after the success of the nearby Booth and Shubert theaters; the Broadhurst opened on September 27, 1917, with Misalliance, and the Shuberts took full control in 1929. It has hosted musicals, revues, comedies, and dramas, with long runs including Fiorello!, Cabaret, Grease, Kiss of the Spider Woman, Les Misérables, and Mamma Mia!.'
WHERE slug = 'broadhurst-theatre';

UPDATE poi SET
  summary = 'The Broadway Theatre is a Broadway theater at 1681 Broadway near 53rd Street in the Theater District of Midtown Manhattan—one of the few Broadway houses actually located on Broadway. Opened in 1924 as a movie theater, it seats about 1,763 and is operated by the Shubert Organization. It has hosted long-running musicals including Evita, Les Misérables, and Miss Saigon.',
  description = 'The Broadway Theatre is a Broadway theater at 1681 Broadway, near 53rd Street, in the Theater District of Midtown Manhattan—one of the few Broadway theaters physically located on Broadway. Opened in 1924 and designed by Eugene De Rosa for Benjamin S. Moss, who first ran it as a movie theater, it seats roughly 1,763 across two levels and is operated by the Shubert Organization. Its facade was originally Italian Renaissance in brick and terracotta; the modern facade is polished granite, part of the office building at 1675 Broadway completed in 1990, which is cantilevered above the auditorium. The auditorium has an orchestra level, one balcony, and box seats, redecorated in a reddish scheme during a 1986 renovation by Oliver Smith. B. S. Moss''s Colony Theatre opened on Christmas Day 1924, leased to Universal Pictures, before Moss converted it for legitimate shows and reopened it as the Broadway Theatre in 1930. After several operators and a mix of plays, movies, and vaudeville, Lee Shubert and Clifford Fischer took over in 1939 and the Shubert family bought it in 1940. Since then it has mostly been a legitimate theater, and it was extensively rebuilt in the late 1980s. Over the years it has hosted many long-running musicals transferred from other houses, including Evita, Les Misérables, and Miss Saigon.'
WHERE slug = 'broadway-theatre';

UPDATE poi SET
  summary = 'Brookfield Place is an upscale office, retail, and dining complex on the Hudson River waterfront in Battery Park City, Lower Manhattan. Formerly the World Financial Center, it features luxury shops, restaurants, the glass-domed Winter Garden atrium, and a marina.',
  description = 'Brookfield Place is a large mixed-use complex of office towers, shops, and restaurants on the Hudson River waterfront in Battery Park City, just west of the World Trade Center in Lower Manhattan. Originally built in the 1980s as the World Financial Center and designed by architect César Pelli, it was renamed Brookfield Place after a major renovation in the 2010s that repositioned it as an upscale shopping and dining destination. Its centerpiece is the Winter Garden, a soaring glass-vaulted atrium filled with palm trees that hosts events and performances and opens onto a marina on the Hudson. The complex houses luxury retailers, a French-themed marketplace and food hall, waterfront restaurants, and the offices of major financial and media firms. Connected by pedestrian bridges and passageways to the World Trade Center and its transit hub, Brookfield Place combines commerce, dining, and public space with expansive river views, and it is a prominent destination on the revitalized Lower Manhattan waterfront.'
WHERE slug = 'brookfield-place';

UPDATE poi SET
  summary = 'The Brooklyn Bridge is a hybrid cable-stayed and suspension bridge spanning the East River between Manhattan and Brooklyn. Opened in 1883, it was the first fixed crossing of the East River and, at the time, the longest suspension bridge in the world, with a main span of nearly 1,600 feet. Designed by John A. Roebling and completed by his son Washington and daughter-in-law Emily Warren Roebling, it is a National Historic Landmark and an icon of New York City.',
  description = 'The Brooklyn Bridge is a hybrid cable-stayed suspension bridge spanning the East River between the boroughs of Manhattan and Brooklyn. Opened on May 24, 1883, it was the first fixed crossing of the East River and the longest suspension bridge in the world at the time, with a main span of 1,595.5 feet and a deck 127 feet above high water. Originally called the New York and Brooklyn Bridge, it was officially renamed in 1915. It was designed by John A. Roebling; after his death, his son Washington Roebling served as chief engineer, assisted by his wife, the engineer Emily Warren Roebling. Construction started in 1870 under the New York Bridge Company, controlled by the Tammany Hall political machine, and controversies and the novelty of the design stretched the project over thirteen years. The bridge carried horse-drawn vehicles and elevated railway lines until 1950 and has been renovated several times as it aged. It is the southernmost of the vehicular bridges linking Manhattan and Long Island, and today carries passenger vehicles, pedestrians, and cyclists. A major tourist attraction and enduring symbol of New York City, the Brooklyn Bridge is designated a National Historic Landmark, a New York City landmark, and a National Historic Civil Engineering Landmark.'
WHERE slug = 'brooklyn-bridge';

UPDATE poi SET
  summary = 'Bryant Park is a 9.6-acre privately managed public park in Midtown Manhattan, between Fifth and Sixth Avenues and 40th and 42nd Streets. Its eastern half is occupied by the Main Branch of the New York Public Library, while its western half is a lawn ringed by shaded walkways and amenities, set over the library''s underground stacks. The park hosts events year-round, including a seasonal Winter Village with an ice rink and shops.',
  description = 'Bryant Park is a 9.6-acre privately managed public park in Midtown Manhattan, between Fifth Avenue and Sixth Avenue and 40th and 42nd Streets. Its eastern half is occupied by the Main Branch of the New York Public Library, while its western half—a lawn with shaded walkways, a carousel, and other amenities—sits atop an underground structure housing the library''s stacks. The first park here opened in 1847 as Reservoir Square, beside the Croton Distributing Reservoir, and hosted the New York Crystal Palace, which burned down in 1858. It was renamed in 1884 for the abolitionist and journalist William Cullen Bryant. After the reservoir was demolished, the library''s main branch rose on the site, opening in 1911, and the park was rebuilt in 1933–1934. Following a period of decline, Bryant Park was restored between 1988 and 1992, when the library''s stacks were built beneath it. Though owned by the city''s parks department, it is managed by the private nonprofit Bryant Park Corporation, founded in 1980, and is widely cited as a model of a successful public–private partnership. The park is both listed on the National Register of Historic Places and designated a New York City landmark.'
WHERE slug = 'bryant-park';

UPDATE poi SET
  summary = 'The Winter Village at Bryant Park is a seasonal winter attraction in Bryant Park in Midtown Manhattan, featuring a free-admission ice-skating rink and a holiday market. Running from late fall through winter, it is one of the city''s most popular seasonal destinations.',
  description = 'The Winter Village at Bryant Park is a seasonal winter attraction that transforms Bryant Park, in Midtown Manhattan behind the New York Public Library, into a holiday destination each year from roughly late October through early March. Its centerpiece is a large outdoor ice-skating rink—notable for offering free admission, with visitors paying only to rent skates—set on the park''s central lawn beneath the surrounding skyscrapers and holiday lights. Encircling the rink and filling the park''s pathways is a holiday market of glass-walled kiosks, where dozens of vendors sell crafts, gifts, apparel, and seasonal food and drink, alongside heated dining areas and food stalls. The Winter Village, produced by the Bryant Park Corporation that manages the park, has become one of New York''s signature seasonal experiences, drawing large crowds of shoppers, skaters, and tourists during the holiday season. When the village closes in late winter, the rink and kiosks are removed and the park''s lawn returns for the warmer months.'
WHERE slug = 'bryant-park-winter-village';

UPDATE poi SET
  summary = 'Carnegie Hall is a historic concert hall on Seventh Avenue at 57th Street in Midtown Manhattan, one of the most prestigious venues for classical and popular music in the world. Built by philanthropist Andrew Carnegie and opened in 1891, it is celebrated for its acoustics and its storied roster of performers.',
  description = 'Carnegie Hall is a landmark concert hall at 881 Seventh Avenue, near 57th Street in Midtown Manhattan. Financed by the industrialist and philanthropist Andrew Carnegie and designed by architect William Burnet Tuthill, it opened in 1891 with an inaugural festival featuring Pyotr Ilyich Tchaikovsky. Renowned for its warm acoustics, the hall comprises three performance spaces—the grand Stern Auditorium/Perelman Stage, the mid-sized Zankel Hall, and the intimate Weill Recital Hall—together hosting a vast range of classical, jazz, pop, and world music. Over its history it has presented an extraordinary array of artists, from the great orchestras and soloists of classical music to performers such as Benny Goodman and the Beatles, and "playing Carnegie Hall" has become a byword for artistic achievement. Threatened with demolition in the 1950s after the New York Philharmonic planned its move to Lincoln Center, the hall was saved through a public campaign led by violinist Isaac Stern and bought by the city. A National Historic Landmark, it remains one of the world''s most esteemed stages.'
WHERE slug = 'carnegie-hall';

UPDATE poi SET
  summary = 'Castle Clinton is a circular sandstone fort at the southern tip of Manhattan, in the Battery, built in the early 19th century to defend New York Harbor. Now a national monument administered by the National Park Service, it has served over its history as a fort, entertainment hall, immigration depot, and aquarium.',
  description = 'Castle Clinton National Monument is a circular sandstone fortification in the Battery at the southern tip of Manhattan. Built between 1808 and 1811 as the West Battery (later renamed for New York mayor and governor DeWitt Clinton), it was one of several forts erected to defend New York Harbor ahead of the War of 1812, originally standing on an artificial island just offshore before landfill connected it to Manhattan. It never saw combat, and over the following two centuries it was repurposed many times: as Castle Garden, a popular entertainment and concert hall in the mid-19th century; as the nation''s first official immigrant processing station from 1855 to 1890, through which millions of newcomers passed before Ellis Island opened; and later as the New York City Aquarium until 1941. Threatened with demolition, it was preserved and designated a national monument, and it is administered today by the National Park Service. The fort now houses exhibits on its layered history and serves as the ticket office for ferries to the Statue of Liberty and Ellis Island.'
WHERE slug = 'castle-clinton-national-monument';

UPDATE poi SET
  summary = 'The Cathedral of St. John the Divine is the cathedral of the Episcopal Diocese of New York, in the Morningside Heights neighborhood of Upper Manhattan. Begun in 1892 and still unfinished, it is one of the largest church buildings in the world, blending Romanesque and Gothic Revival styles.',
  description = 'The Cathedral of St. John the Divine is the mother church of the Episcopal Diocese of New York, on Amsterdam Avenue at 112th Street in Morningside Heights, near Columbia University. Construction began in 1892 to a Romanesque design that was later reworked in the Gothic Revival style, and because work has proceeded intermittently for well over a century—slowed by two world wars, funding gaps, and a major fire in 2001—the building remains unfinished, earning it the affectionate nickname "St. John the Unfinished." Even incomplete, it is among the largest cathedrals and church buildings in the world by floor area, with an immense nave, soaring vaults, and a great rose window. Beyond worship, the cathedral is known for its embrace of the arts, sciences, and interfaith and civic life, hosting concerts, exhibitions, and events such as the annual Blessing of the Animals. Its grounds include gardens and sculpture. A prominent Upper Manhattan landmark, it draws worshippers and visitors alike to its vast, atmospheric interior.'
WHERE slug = 'cathedral-of-st-john-the-divine';

UPDATE poi SET
  summary = 'Central Park is an 843-acre landscaped park between the Upper West Side and Upper East Side of Manhattan, the first landscaped public park in the United States. Designed by Frederick Law Olmsted and Calvert Vaux and completed by 1876, it is the most-visited urban park in the country, with roughly 42 million visitors a year.',
  description = 'Central Park is an urban park between the Upper West Side and Upper East Side of Manhattan, the first landscaped public park in the United States. Covering 843 acres, it is the sixth-largest park in the city and the most-visited urban park in the country, with an estimated 42 million visitors a year. It is owned by the city but managed since 1980 by the non-profit Central Park Conservancy under a public–private partnership. A large Manhattan park was first proposed in the 1840s, and in 1858 landscape architects Frederick Law Olmsted and Calvert Vaux won the design competition with their "Greensward Plan." Construction required seizing existing settlements, including the majority-Black community of Seneca Village, through eminent domain. The first areas opened in late 1858 and the park was completed in 1876. After a period of decline, parks commissioner Robert Moses cleaned it up in the 1930s, and the Conservancy has refurbished it since the 1980s. The park''s main attractions include the Ramble and Lake, the Jacqueline Kennedy Onassis Reservoir, Sheep Meadow, Wollman Rink, the Central Park Carousel and Zoo, Bethesda Terrace, and the Delacorte Theater, home of free Shakespeare in the Park. Its diverse ecosystem supports several hundred species of plants and animals, and activities range from cycling and carriage rides to concerts and sports. One of the most-filmed locations in the world, Central Park was designated a National Historic Landmark district in 1963.'
WHERE slug = 'central-park';

UPDATE poi SET
  summary = 'The Central Park Boathouse, formally the Loeb Boathouse, sits on the eastern shore of the Lake in Central Park. A longtime destination for lakeside dining and rowboat and gondola rentals, it is one of the park''s iconic recreational landmarks.',
  description = 'The Loeb Boathouse, commonly called the Central Park Boathouse, is a lakeside pavilion on the eastern shore of the Lake in Central Park, near 74th Street. The current structure was built in the mid-1950s, funded by a gift from investment banker Carl M. Loeb, replacing an earlier Victorian boathouse. For decades it served as a well-known destination combining a waterfront restaurant and bar with a boathouse offering rowboat rentals and an authentic Venetian gondola for rides on the Lake. Its terrace and dining room, overlooking the water and the wooded Ramble beyond, made it a popular spot for meals, weddings, and film and television scenes. Bicycle rentals and a seasonal outdoor café have also operated from the site. The boathouse and its boat-rental operation are enduring symbols of leisurely recreation in Central Park, and the tradition of rowing on the Lake from this spot dates back well over a century.'
WHERE slug = 'central-park-boathouse';

UPDATE poi SET
  summary = 'Chelsea Market is a popular food hall and shopping arcade in the Chelsea neighborhood of Manhattan, occupying a full block in a former Nabisco factory. Home to dozens of food vendors, restaurants, and shops, it is one of the city''s best-known culinary destinations.',
  description = 'Chelsea Market is a food hall, shopping arcade, and office building occupying a full block between Ninth and Tenth Avenues and 15th and 16th Streets in the Chelsea neighborhood of Manhattan. It is housed in a complex of former factory buildings once operated by the National Biscuit Company (Nabisco)—the birthplace of the Oreo cookie—which were redeveloped in the 1990s. The ground-floor concourse is a bustling indoor market lined with dozens of food vendors, restaurants, bakeries, and specialty shops, its industrial architecture of exposed brick, pipes, and salvaged materials giving it a distinctive character. Above the market, the upper floors house office tenants, including major media and technology companies. Located at the base of the High Line and near the galleries of West Chelsea, Chelsea Market draws large crowds of locals and tourists seeking everything from tacos and seafood to baked goods and international cuisine, and it has become one of New York''s premier food destinations.'
WHERE slug = 'chelsea-market';

UPDATE poi SET
  summary = 'Chelsea Park is a neighborhood park in Chelsea, Manhattan, dating to 1910, offering sports fields, basketball and handball courts, a playground, and seating. It is home to the "Doughboy Statue," a World War I memorial erected in 1921.',
  description = 'Chelsea Park is a park in the Chelsea neighborhood of Manhattan, dating back to 1910. The park has sports fields, basketball and handball courts, a children''s playground, and space for sitting; its surface is mostly tarmac or artificial turf, with pits for plane trees and some plots of annual flowers. It contains a statue of a World War I soldier, the "Doughboy Statue," erected in 1921. The process of approving, funding, and clearing the tenements that occupied the site was protracted, and the park has since been upgraded several times by the Works Progress Administration and the New York City Department of Parks and Recreation.'
WHERE slug = 'chelsea-park';

UPDATE poi SET
  summary = 'The Children''s Museum of Manhattan (CMOM) is a museum on the Upper West Side of Manhattan dedicated to interactive, educational play for young children and families. It offers hands-on exhibits spanning art, science, culture, and early learning.',
  description = 'The Children''s Museum of Manhattan (CMOM) is a family-oriented museum on the Upper West Side of Manhattan, at 212 West 83rd Street near Broadway. Founded in 1973 and dedicated to learning through play, it serves young children and their families with interactive, hands-on exhibits that blend art, science, literacy, health, and world cultures. Its multi-floor galleries feature immersive environments where children can climb, build, experiment, create art, and role-play, along with early-childhood spaces designed for infants and toddlers and exhibits tied to books and educational themes. The museum offers daily programs, workshops, and performances, and it emphasizes accessibility and family engagement. A popular destination for New York families and visitors with young children, CMOM has announced plans to move to a larger new home, but at its long-standing Upper West Side location it has introduced generations of children to museum-going through creative, participatory exhibits.'
WHERE slug = 'children-s-museum-of-manhattan';

UPDATE poi SET
  summary = 'Chinatown is a densely populated neighborhood in Lower Manhattan and one of the largest Chinese communities in the Western Hemisphere. Centered on Mott and Canal Streets, it is a bustling enclave of markets, restaurants, and shops that has long been a center of Chinese-American life.',
  description = 'Manhattan''s Chinatown is a large, densely populated neighborhood in Lower Manhattan, bounded roughly by the Lower East Side, Little Italy, and the Civic Center, and centered on streets such as Mott, Mulberry, Canal, and the Bowery. Established in the late 19th century as Chinese immigrants settled around Mott Street, it grew—despite decades of exclusionary immigration laws—into one of the oldest and largest Chinese ethnic enclaves in the Western Hemisphere. The neighborhood is a hub of Chinese-American commerce and culture, crowded with restaurants, bakeries, tea shops, herbal-medicine stores, and open-air markets selling produce, fish, and specialty goods. It is home to numerous family and community associations, temples, and the Museum of Chinese in America. Major celebrations such as the Lunar New Year, with its parades and lion dances, draw large crowds each winter. A vibrant, working immigrant neighborhood as well as a popular destination for visitors, Chinatown remains a central gathering place for Chinese culture in New York City.'
WHERE slug = 'chinatown-manhattan';

UPDATE poi SET
  summary = 'The Chrysler Building is a 1,046-foot Art Deco skyscraper at 42nd Street and Lexington Avenue in East Midtown Manhattan. Completed in 1930 for automobile magnate Walter Chrysler, it was briefly the world''s tallest building and remains the tallest brick building with a steel framework. It is widely regarded as a masterpiece of Art Deco design.',
  description = 'The Chrysler Building is a 1,046-foot Art Deco skyscraper in the East Midtown neighborhood of Manhattan, at the intersection of 42nd Street and Lexington Avenue. It is the tallest brick building in the world with a steel framework, and on its completion in 1930 it was both the world''s first supertall skyscraper and, for 11 months, the world''s tallest building. Originally a project of developer William H. Reynolds, it was commissioned by Walter Chrysler, head of the Chrysler Corporation, and its construction featured a famous race with 40 Wall Street and the Empire State Building to be the world''s tallest. Chrysler funded the tower personally as a real-estate investment for his children; it was never the corporation''s headquarters, which remained in Detroit. An annex was completed in 1952, and the Chrysler family sold the building the following year, after which it had numerous owners. Reviews at its opening were mixed, but the building came to be regarded as a paragon of Art Deco, ranking ninth on the American Institute of Architects'' 2007 list of America''s favorite architecture. Its facade and interior became New York City designated landmarks in 1978, and it was named a National Historic Landmark in 1976.'
WHERE slug = 'chrysler-building';

UPDATE poi SET
  summary = 'Circle in the Square Theatre is a Broadway theater at 235 West 50th Street in Midtown Manhattan, notable as one of the only Broadway houses with a thrust (arena-style) stage. Opened at this location in 1972, it is affiliated with the Circle in the Square Theatre School, a professional acting conservatory.',
  description = 'Circle in the Square Theatre is a Broadway house located below street level at 1633 Broadway, with its entrance on West 50th Street in Midtown Manhattan. It carries the name of the influential company founded in Greenwich Village in 1951, which pioneered arena-style staging and helped launch the Off-Broadway movement before opening this Broadway home in 1972. Seating roughly 800, it is distinctive as one of the very few Broadway theaters with a thrust or arena stage, in which the audience surrounds the playing area on multiple sides rather than facing a conventional proscenium—an arrangement suited to intimate and inventive productions. The venue is affiliated with the Circle in the Square Theatre School, a professional acting and musical-theater conservatory. Over the years the theater has hosted acclaimed revivals and new works well suited to its unusual configuration, and it remains one of Broadway''s most architecturally unusual and intimate stages.'
WHERE slug = 'circle-in-the-square-theatre-school';

UPDATE poi SET
  summary = 'Circle Line Sightseeing Cruises is a long-running boat-tour operator based at Pier 83 on the Hudson River in Midtown Manhattan''s Hell''s Kitchen. It offers sightseeing cruises around and along Manhattan, including trips past the Statue of Liberty and full circumnavigations of the island.',
  description = 'Circle Line Sightseeing Cruises is one of New York''s best-known boat-tour companies, operating from Pier 83 at West 42nd Street on the Hudson River in the Hell''s Kitchen area of Midtown Manhattan. In business since the 1940s, Circle Line is famous for its cruises around Manhattan, including a full circumnavigation of the island that passes major landmarks along the Hudson and East Rivers and the harbor. Its fleet of sightseeing vessels offers a range of narrated trips—among them shorter harbor cruises that pass close to the Statue of Liberty and Ellis Island, landmark tours, and seasonal excursions—with commentary on the city''s history and sights. The open decks provide sweeping views of the skyline, bridges, and waterfront. A fixture of New York tourism for decades, Circle Line gives visitors a water-level perspective on Manhattan and its surrounding rivers and harbor.'
WHERE slug = 'circle-line-sightseeing-cruises-midtown';

UPDATE poi SET
  summary = 'City Hall Park is a public park in the Civic Center of Lower Manhattan, surrounding New York City Hall. A historic common dating to the colonial era, it features a landmark fountain, monuments, and tree-lined paths near the foot of the Brooklyn Bridge.',
  description = 'City Hall Park is a landscaped public park in the Civic Center area of Lower Manhattan, bounded roughly by Broadway, Park Row, and Chambers Street, with New York City Hall at its center. The site has been public common land since the colonial era, when it served as a town common, and it witnessed key moments in the city''s history—including a reading of the Declaration of Independence to Washington''s troops in 1776. Over the centuries it held a range of civic buildings and monuments. Today the park features a restored 19th-century cast-iron fountain, statuary, and tree-shaded walkways, forming a green setting for the seat of city government and a gathering place near the Brooklyn Bridge and the Manhattan Municipal Building. A designated landmark, City Hall Park is both a working civic space and a historic green oasis at the heart of Lower Manhattan.'
WHERE slug = 'city-hall-park';

UPDATE poi SET
  summary = 'Color Factory is an interactive, color-themed art experience in the Hudson Square/SoHo area of Lower Manhattan. Opened in 2018, it leads visitors through a series of immersive, playful installations celebrating color—complete with photo moments, treats, and a ball pit.',
  description = 'Color Factory is an immersive, interactive art experience in the Hudson Square area near SoHo in Lower Manhattan. It began as a temporary pop-up in San Francisco, conceived by Jordan Ferney of the blog "Oh Happy Day!," before opening a New York edition in 2018 that became a permanent attraction. Occupying some 20,000 square feet, the experience guides visitors through about 14 rooms and installations built around the theme of color, created in collaboration with more than 20 artists, designers, and makers. Highlights include vividly hued environments, participatory activities, hidden surprises, edible treats along the way, and a large ball pit—all designed to be experienced and photographed. The installations draw inspiration in part from the colors of New York City itself. Family-friendly and heavily geared toward social-media-worthy moments, Color Factory is one of several "experiential museums" that emerged in Manhattan in the late 2010s, blending playful design, interactivity, and photography into a walk-through attraction.'
WHERE slug = 'color-factory-nyc';

UPDATE poi SET
  summary = 'Columbia University is a private Ivy League research university in New York City, established in 1754 as King''s College by royal charter on the grounds of Trinity Church. The oldest institution of higher education in New York, it moved to its current Morningside Heights campus in 1896.',
  description = 'Columbia University in the City of New York is a private Ivy League research university, established in 1754 as King''s College by royal charter under George II on the grounds of Trinity Church in Manhattan. It is the oldest institution of higher education in New York and the fifth-oldest in the United States. Renamed Columbia College in 1784 after the American Revolution, it was placed in 1787 under a private board of trustees led by former students Alexander Hamilton and John Jay, and it moved to its current Morningside Heights campus in 1896. Columbia is organized into 17 schools and includes affiliated institutions such as Barnard College and Teachers College. Its research enterprise spans the Lamont–Doherty Earth Observatory, the Goddard Institute for Space Studies, and other laboratories; it was the first U.S. school to grant the MD degree, and it administers the Pulitzer Prize. Columbia scholars have contributed to major breakthroughs, including the laser and maser, nuclear magnetic resonance, the first nuclear pile, early evidence for plate tectonics, and much of the initial research for the Manhattan Project. Its alumni, faculty, and staff have included founders of the United States, several U.S. presidents, Supreme Court justices, and more than 100 Nobel laureates.'
WHERE slug = 'columbia-university';

UPDATE poi SET
  summary = 'The Conservatory Garden is a six-acre formal garden in the northeastern part of Central Park—the park''s only formal garden. Divided into Italian, French, and English styles, it is a designated quiet zone prized for its fountains, seasonal plantings, and tranquil atmosphere.',
  description = 'The Conservatory Garden is a six-acre formal garden along Fifth Avenue near 105th Street, in the northeastern section of Central Park. Named for a glass conservatory that once stood on the site and was demolished in the mid-20th century, the garden opened in its present form in 1937 and is the only formal garden within the park. It is composed of three distinct sections in different national styles: a central Italian garden with a great lawn, a fountain, and a wisteria pergola; a northern French garden centered on the bronze "Three Dancing Maidens" fountain and elaborate seasonal flower beds; and a southern English garden built around the Burnett Fountain, honoring "The Secret Garden" author Frances Hodgson Burnett. Entered through the ornate Vanderbilt Gate, the garden is designated a quiet zone where recreation and noise are discouraged. Restored by the Central Park Conservancy, it is a favorite for weddings and photography and offers changing displays of tulips, chrysanthemums, and other flowers through the seasons.'
WHERE slug = 'conservatory-garden-central-park';

UPDATE poi SET
  summary = 'Cooper Hewitt, Smithsonian Design Museum is the only museum in the United States devoted solely to historic and contemporary design, on Museum Mile on Manhattan''s Upper East Side. It is housed in the former Andrew Carnegie mansion and is part of the Smithsonian Institution.',
  description = 'Cooper Hewitt, Smithsonian Design Museum is a design museum on Fifth Avenue at 91st Street, along Museum Mile on the Upper East Side of Manhattan. Part of the Smithsonian Institution, it is the only museum in the country dedicated exclusively to historic and contemporary design. The museum traces its origins to 1897, when it was founded by the granddaughters of industrialist Peter Cooper as part of Cooper Union, and it later joined the Smithsonian. Since 1976 it has occupied the former mansion of steel magnate Andrew Carnegie, a Georgian-style landmark completed in 1902 that offers a grand domestic setting for its galleries. Its vast collection spans thousands of years and disciplines—product and industrial design, graphic design, textiles, wallcoverings, drawings, and decorative arts—and it mounts changing exhibitions exploring design''s role in everyday life, often featuring interactive technology that lets visitors design their own creations. Cooper Hewitt combines a historic mansion, a garden, and a forward-looking mission to celebrate design past and present.'
WHERE slug = 'cooper-hewitt-smithsonian-design-museum';

UPDATE poi SET
  summary = 'The Deutsche Bank Center is a mixed-use skyscraper complex at Columbus Circle on the southwest corner of Central Park in Manhattan. Formerly the Time Warner Center, its twin towers house offices, luxury residences, a hotel, upscale shops, restaurants, and Jazz at Lincoln Center.',
  description = 'The Deutsche Bank Center is a large mixed-use complex at Columbus Circle, on the southwest corner of Central Park in Manhattan, where the Upper West Side meets Midtown. Completed in 2003 and designed by architect David Childs of Skidmore, Owings & Merrill, its twin glass towers rise above a multi-story base and were originally known as the Time Warner Center before being renamed for anchor tenant Deutsche Bank. The complex combines offices, luxury condominium residences, the Mandarin Oriental hotel, and an upscale shopping mall with high-end retailers and restaurants arranged around a soaring atrium overlooking Columbus Circle and the park. It is also home to Jazz at Lincoln Center, whose performance halls—including the Rose Theater—occupy part of the building. With its prominent position on Columbus Circle and its blend of commerce, residence, culture, and hospitality, the Deutsche Bank Center is a major landmark at the gateway between Midtown, the Upper West Side, and Central Park.'
WHERE slug = 'deutsche-bank-center';

UPDATE poi SET
  summary = 'Eataly NYC Flatiron is the original New York location of the Italian food-hall and marketplace chain Eataly, near Madison Square Park in the Flatiron District. It combines Italian groceries, food counters, and sit-down restaurants under one roof.',
  description = 'Eataly NYC Flatiron is a large Italian marketplace and food hall at 200 Fifth Avenue, across from Madison Square Park in the Flatiron District of Manhattan. Opened in 2010 as the first U.S. outpost of the Italian Eataly chain—co-founded by entrepreneur Oscar Farinetti with partners including the chefs Mario Batali and Lidia Bastianich—it spans roughly 50,000 square feet and combines a grocery market, specialty food counters, and multiple sit-down restaurants and eateries. Visitors can shop for imported and fresh Italian products—pasta, cheese, cured meats, olive oil, produce, and wine—while dining at counters and restaurants devoted to pizza and pasta, seafood, meat, and other regional Italian specialties, with a rooftop restaurant and beer garden among its features. Blending retail, dining, and culinary education, Eataly Flatiron popularized the large-scale Italian food-hall concept in the United States and remains a bustling destination for food lovers near Madison Square Park.'
WHERE slug = 'eataly-nyc-flatiron';

UPDATE poi SET
  summary = 'Edge is an outdoor sky deck on the 100th floor of 30 Hudson Yards on Manhattan''s West Side, one of the highest observation decks in the Western Hemisphere. Opened in 2020, its triangular platform juts about 80 feet out from the building, more than 1,100 feet above the street, with angled glass walls and a glass floor.',
  description = 'Edge is a sky-high observation deck at 30 Hudson Yards on the West Side of Manhattan, part of the Hudson Yards development. Perched on the building''s 100th floor, roughly 1,131 feet above the ground, it opened on March 11, 2020, as one of the highest outdoor observation decks in the Western Hemisphere. Its most striking feature is a triangular platform that cantilevers about 80 feet out from the side of the tower, seeming to float over the city; angled glass walls lean outward, and a section of glass floor lets visitors look straight down to the streets below. The deck offers open-air, 360-degree views of the Manhattan skyline, the Hudson River, and the surrounding region. For thrill-seekers, the attraction also offers "City Climb," a guided experience in which harnessed participants ascend the exterior of the building above the deck. Edge quickly became one of the marquee attractions of the Hudson Yards neighborhood.'
WHERE slug = 'edge';

UPDATE poi SET
  summary = 'El Museo del Barrio, often called simply El Museo, is a museum at 1230 Fifth Avenue near the northern end of Museum Mile in Upper Manhattan. Founded in 1969, it specializes in Latin American and Caribbean art, with an emphasis on Puerto Rico and New York''s Puerto Rican community. It is the oldest museum in the country dedicated to Latino art.',
  description = 'El Museo del Barrio, often known simply as El Museo, is a museum at 1230 Fifth Avenue in Upper Manhattan. It is located near the northern end of Fifth Avenue''s Museum Mile, immediately north of the Museum of the City of New York. Founded in 1969, El Museo specializes in Latin American and Caribbean art, with an emphasis on works from Puerto Rico and the Puerto Rican community in New York City. It is the oldest museum in the country dedicated to Latino art.'
WHERE slug = 'el-museo-del-barrio';

UPDATE poi SET
  summary = 'The Empire State Building is a 102-story Art Deco skyscraper in Midtown Manhattan, designed by Shreve, Lamb & Harmon and completed in 1931. Standing 1,454 feet to the tip of its antenna, it was the tallest building in the world for nearly 40 years. Its 86th- and 102nd-floor observatories and its status as a global cultural icon make it one of New York''s most popular attractions.',
  description = 'The Empire State Building is a 102-story Art Deco skyscraper in the Midtown South neighborhood of Manhattan, on Fifth Avenue between West 33rd and 34th Streets. Designed by Shreve, Lamb & Harmon and constructed in just over a year, it opened on May 1, 1931. It has a roof height of 1,250 feet and stands 1,454 feet tall including its antenna, and it takes its name from "Empire State," the nickname of New York. The building was the tallest in the world until 1970, when the World Trade Center''s North Tower was topped out; after the September 11 attacks it was again the city''s tallest until One World Trade Center surpassed it in 2012. Built during the Great Depression, the tower struggled to fill its offices and did not turn a profit until the early 1950s. Its architecture, height, and observation decks have made it a premier attraction, drawing around four million visitors a year to its 86th- and 102nd-floor observatories, with an indoor observatory on the 80th floor added in 2019. An international cultural icon, it has appeared in more than 250 films and television series since King Kong in 1933, and its size is often used as a benchmark for describing other structures. The American Society of Civil Engineers has named it one of the Seven Wonders of the Modern World, and in 2007 it topped the American Institute of Architects'' list of America''s favorite architecture.'
WHERE slug = 'empire-state-building';

UPDATE poi SET
  summary = 'The Eugene O''Neill Theatre is a Broadway theater at 230 West 49th Street in the Theater District of Midtown Manhattan. Opened in 1925 and named for the playwright Eugene O''Neill, it seats about 1,100 and is owned by Jujamcyn, now part of ATG Entertainment.',
  description = 'The Eugene O''Neill Theatre is a Broadway house at 230 West 49th Street in the Theater District of Midtown Manhattan. Opened in 1925 as the Forrest Theatre and designed by architect Herbert J. Krapp, it was later renamed for the four-time Pulitzer Prize–winning American playwright Eugene O''Neill. Seating roughly 1,100 across two levels, it is owned by Jujamcyn Theaters, which merged in 2023 with ATG Entertainment. Over its history the theater has hosted a wide range of plays and musicals, and since 2011 it has been the longtime home of the hit satirical musical "The Book of Mormon." Its neo-Renaissance styling is characteristic of Krapp''s Broadway designs. A mid-sized house in the heart of the Theater District, the Eugene O''Neill remains an active Broadway venue.'
WHERE slug = 'eugene-o-neill-theatre';

UPDATE poi SET
  summary = 'FAO Schwarz is a famous luxury toy store, with its flagship at Rockefeller Plaza in Midtown Manhattan. One of the oldest toy retailers in the United States, it is known for its lavish displays, giant plush animals, and the walk-on floor piano.',
  description = 'FAO Schwarz is a historic, high-end toy retailer whose flagship store is at Rockefeller Plaza in Midtown Manhattan. Founded in 1862 by German immigrant Frederick August Otto Schwarz, it is one of the oldest toy stores in the United States and a longtime New York institution, famous for its theatrical displays, life-size and giant plush animals, and exclusive toys. For decades its landmark store on Fifth Avenue near the Plaza Hotel was a beloved destination, immortalized by the "Big Piano"—a giant floor keyboard that shoppers play by dancing on the keys, made famous by the film "Big." After that store closed in 2015, FAO Schwarz reopened a new flagship at Rockefeller Plaza in 2018, reviving its signature attractions, including the walk-on piano and costumed "toy soldier" greeters. Blending retail with spectacle, FAO Schwarz remains a magical destination for children and a nostalgic stop for visitors in the heart of Midtown.'
WHERE slug = 'fao-schwarz';

UPDATE poi SET
  summary = 'Father Duffy Square is the northern triangle of Times Square in Midtown Manhattan, between 46th and 47th Streets. It is home to the famous red TKTS discount-ticket booth and the statue of Father Francis P. Duffy for which it is named.',
  description = 'Father Duffy Square is a public plaza forming the northern portion of Times Square, in the triangle between Broadway, Seventh Avenue, and 46th and 47th Streets in Midtown Manhattan. It is named for Father Francis P. Duffy, a celebrated World War I army chaplain and pastor of a nearby church, whose bronze statue stands at the site alongside a statue of the composer and performer George M. Cohan. The square is best known as the home of the TKTS booth, the bright-red, tiered-glass structure where visitors buy same-day discounted tickets to Broadway and Off-Broadway shows; the booth''s illuminated red steps have become a popular place to sit and take in the lights of Times Square. As the pedestrian heart of the Theater District, Father Duffy Square is one of the most heavily trafficked and photographed spots in the city, at the center of the "Crossroads of the World."'
WHERE slug = 'father-duffy-square';

UPDATE poi SET
  summary = 'Federal Hall National Memorial stands at 26 Wall Street in Lower Manhattan, on the site of the first U.S. capitol under the Constitution. The original building was where the First Congress met and George Washington was inaugurated as president in 1789, before its demolition in 1812. The current Greek Revival structure, built in 1842 as a custom house, is run by the National Park Service as a memorial to those events.',
  description = 'Federal Hall was the first capitol building of the United States established under the Constitution, standing on Wall Street facing Broad Street in Lower Manhattan. As the meeting place of the First United States Congress and the site of George Washington''s first presidential inauguration in 1789, it was central to the founding of the federal government. The original structure, built from 1699 to 1703 as New York''s second city hall, hosted the 1765 Stamp Act Congress and served the Congress of the Confederation from 1785 to 1789 before being demolished in 1812. The current building, designed by Ithiel Town and Alexander Jackson Davis, was completed in 1842 as the U.S. Custom House and later served as a Subtreasury from 1862 to 1925; it opened as a public memorial in 1940. Built of Tuckahoe marble, it features a colonnade of Doric columns and a domed rotunda, with a large statue of Washington by John Quincy Adams Ward standing before it. The National Park Service operates the building as a national memorial. Its facade and part of its interior are New York City designated landmarks, and it is a contributing property to the Wall Street Historic District.'
WHERE slug = 'federal-hall-national-memorial';

UPDATE poi SET
  summary = 'The Flatiron Building is a 22-story, 307-foot steel-framed triangular building at 175 Fifth Avenue in Manhattan''s Flatiron District. Designed by Daniel Burnham and Frederick P. Dinkelberg and opened in 1902, it takes its name from its wedge shape, which recalls a cast-iron clothes iron. Its striking form on a triangular block at Fifth Avenue, Broadway, and 22nd Street has made it one of the city''s most iconic buildings.',
  description = 'The Flatiron Building, originally the Fuller Building, is a 22-story, 307-foot steel-framed triangular building at 175 Fifth Avenue in the Flatiron District of Manhattan. Designed by Daniel Burnham and Frederick P. Dinkelberg, it opened in 1902 on a triangular block formed by Fifth Avenue, Broadway, and East 22nd Street, with East 23rd Street grazing its northern peak. The name derives from its shape, which recalls a cast-iron clothes iron. Developed as the headquarters of the Fuller Company construction firm, it rose quickly and was sometimes called "Burnham''s Folly" by locals skeptical of its structural integrity; a "cowcatcher" retail space and penthouse were added soon after opening. Ownership passed through several syndicates over the 20th century, with Helmsley-Spear and later the Newmark Group managing the building. After a 2023 auction fell through when the winning bidder failed to pay, three of the four ownership groups took control, and in late 2023 the owners announced a conversion to residential condominiums. The facade is divided into three horizontal sections like a classical column, with a limestone base and glazed terracotta above, over a steel frame engineered to withstand far more than the area''s maximum wind force. Long celebrated as one of the world''s most iconic skyscrapers, the Flatiron is a New York City and National landmark.'
WHERE slug = 'flatiron-building';

UPDATE poi SET
  summary = 'Fort Tryon Park is a 67-acre public park on a ridge in the Washington Heights and Inwood neighborhoods of Upper Manhattan, overlooking the Hudson River. Created by John D. Rockefeller Jr., who engaged the Olmsted Brothers to design it, the park was given to the city in 1931 and completed in 1935. It is home to the Met Cloisters and the celebrated Heather Garden.',
  description = 'Fort Tryon Park is a 67-acre public park in the Washington Heights and Inwood neighborhoods of Upper Manhattan, set on a ridge close to the Hudson River. It extends roughly from 192nd Street south to Riverside Drive north, with its main entrance at Margaret Corbin Circle. The site was known to the Lenape as Chquaesgeck, and during the Revolutionary War the Battle of Fort Washington was fought here on November 16, 1776. By the turn of the 20th century it held large country estates. Beginning in 1917, philanthropist John D. Rockefeller Jr. bought up the Tryon Hall estate and neighboring properties to create the park, engaging the Olmsted Brothers firm to design it. He gave the land to the city in 1931, and the park was completed in 1935. Rockefeller also bought sculptor George Grey Barnard''s medieval-art collection and gave it to the Metropolitan Museum of Art, which built the Cloisters in the park from 1935 to 1939 to house it. Built on Manhattan schist bearing glacial striations, the park features extensive plantings, including the Heather Garden, restored in the 1980s, along with walking paths, meadows, and views of the Hudson and Harlem Rivers. Fort Tryon Park was added to the National Register of Historic Places in 1978 and designated a New York City scenic landmark in 1983.'
WHERE slug = 'fort-tryon-park';

UPDATE poi SET
  summary = 'Fort Washington Park is a waterfront park along the Hudson River in the Washington Heights neighborhood of Upper Manhattan. It stretches beneath the George Washington Bridge and is home to the Little Red Lighthouse, a beloved small lighthouse at the river''s edge.',
  description = 'Fort Washington Park is a long, narrow waterfront park along the Hudson River in the Washington Heights neighborhood of Upper Manhattan, running for roughly two miles beneath the cliffs of the west side and passing under the George Washington Bridge. The park is named for Fort Washington, a Revolutionary War fortification that once stood on the heights above, where American forces suffered a major defeat in 1776. Today the park offers riverside paths that form part of the Manhattan Waterfront Greenway, along with playing fields, tennis courts, and open space with sweeping views across the Hudson to the New Jersey Palisades. Its most famous feature is the Little Red Lighthouse, a small early-20th-century lighthouse standing at the river''s edge directly under the great bridge—immortalized in the classic children''s book "The Little Red Lighthouse and the Great Gray Bridge." The park is a scenic and historic stretch of Upper Manhattan''s waterfront.'
WHERE slug = 'fort-washington-park';

UPDATE poi SET
  summary = 'Fraunces Tavern is a historic tavern and museum at 54 Pearl Street in Lower Manhattan, in a reconstructed 18th-century building. Famous as the site where George Washington bade farewell to his officers in 1783, it houses a museum of Revolutionary and early American history above a working restaurant.',
  description = 'Fraunces Tavern is a landmark building at 54 Pearl Street, at the corner of Broad Street, in the Financial District of Lower Manhattan. The site''s brick structure dates to 1719 as a mansion, and in 1762 Samuel Fraunces opened it as a tavern that became a gathering place in the years surrounding the American Revolution. Its most celebrated moment came on December 4, 1783, when George Washington gathered his Continental Army officers in the Long Room to bid them an emotional farewell after the British evacuation of New York. The building later served briefly as offices for federal government departments in the 1780s. Restored in the early 20th century by the Sons of the Revolution, the complex today combines a working tavern and restaurant on the ground floor with the Fraunces Tavern Museum above, which preserves period rooms—including the Long Room—and displays paintings, artifacts, and documents relating to the Revolution and early American history. It is among the oldest surviving structures in Manhattan and a designated landmark.'
WHERE slug = 'fraunces-tavern-museum';

UPDATE poi SET
  summary = 'Gapstow Bridge is a small stone bridge at the northern end of the Pond in the southeastern corner of Central Park. Built in 1896, its simple low arch framing the Midtown skyline is one of the most photographed views in the park.',
  description = 'Gapstow Bridge is a low, gently arching stone bridge that crosses a narrow inlet at the northern end of the Pond, near the southeastern corner of Central Park at Fifth Avenue and 59th Street. The current bridge, built in 1896 and designed by Howard & Caudwell, replaced an earlier, more ornate wooden-and-stone span from the 1870s. Constructed of rough Manhattan schist, it stretches about 76 feet with a single elliptical arch and blends quietly into the naturalistic landscape. Gapstow Bridge is celebrated above all for the view it frames: looking north across the Pond, visitors see the bridge in the foreground with the skyscrapers of Central Park South and Midtown rising beyond the trees—a composition that has appeared in countless photographs, paintings, and films. Its picturesque simplicity and prime location near the park''s Grand Army Plaza entrance make it one of Central Park''s best-loved and most-recognized landmarks.'
WHERE slug = 'gapstow-bridge';

UPDATE poi SET
  summary = 'The Gerald Schoenfeld Theatre is a Broadway theater at 236 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1917 as the Plymouth Theatre and designed by Herbert J. Krapp for the Shubert brothers, it seats 1,079 and is operated by the Shubert Organization. It was renamed in 2005 for Gerald Schoenfeld, the longtime Shubert Organization president.',
  description = 'The Gerald Schoenfeld Theatre, known as the Plymouth Theatre before 2004, is a Broadway theater at 236 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1917 and designed by Herbert J. Krapp for the Shubert brothers, it seats 1,079 across two levels, is operated by the Shubert Organization, and both its facade and auditorium are New York City landmarks. The simple neoclassical facade, similar to that of the concurrently built Broadhurst Theatre, is of buff-colored brick and terracotta, divided into a western stage house and an eastern entrance with a curved corner facing Broadway. The auditorium has an orchestra level, a large balcony, a small technical gallery, a mostly flat ceiling, and a sounding board, decorated in the Adam style with plasterwork, and box seats flanking the elliptical proscenium arch. The Shuberts developed the Broadhurst and Plymouth theaters after the success of the nearby Booth and Shubert theaters. The Plymouth was leased to Arthur Hopkins and opened on October 10, 1917, with the comedy A Successful Calamity; the Shuberts retained ownership and took over after Hopkins''s death in 1950. It has hosted musicals, revues, comedies, and dramas throughout its history, and was renamed for Gerald Schoenfeld in 2005.'
WHERE slug = 'gerald-schoenfeld-theatre';

UPDATE poi SET
  summary = 'The Gershwin Theatre is a Broadway theater at 222 West 51st Street, within the Paramount Plaza office building in Midtown Manhattan. Opened in 1972 and operated by the Nederlander Organization, it is named for songwriting brothers George and Ira Gershwin. With about 1,933 seats, it is Broadway''s largest theater and has housed the musical Wicked since 2003.',
  description = 'The Gershwin Theatre, originally the Uris Theatre, is a Broadway theater at 222 West 51st Street, on the second floor of the Paramount Plaza office building in Midtown Manhattan. Opened in 1972 and operated by the Nederlander Organization, it is named for brothers George and Ira Gershwin and is, with roughly 1,933 seats across two levels, Broadway''s largest theater. Designed by Ralph Alswang, it was one of the first theaters built under the Special Theater District amendment of 1967, with the Uris Buildings Corporation constructing it inside its office tower in exchange for additional floors of office space. Escalators lead from the ground floor to the second-story lobby and rotundas, which house the American Theater Hall of Fame and its inscriptions of more than 500 notable theatrical figures. The Uris opened on November 28, 1972, with the musical Via Galactica; after several flops it was rented for concerts and dance in the 1970s, though The King and I and Sweeney Todd had long runs late in the decade. It was renamed the Gershwin in 1983 and has since hosted six Tony Awards ceremonies, concerts, and musicals such as Show Boat. The theater has staged the long-running musical Wicked since 2003.'
WHERE slug = 'gershwin-theatre';

UPDATE poi SET
  summary = 'Gramercy Park is a small, gated green space at the center of the Gramercy neighborhood in Manhattan, laid out in the early 1830s. It is one of only two private parks in New York City, accessible only to residents of the surrounding buildings who hold a key.',
  description = 'Gramercy Park is a two-acre private garden square at the heart of the Gramercy neighborhood, bounded by East 20th and 21st Streets where Lexington Avenue meets Irving Place. It was created in the early 1830s by developer Samuel B. Ruggles, who drained a marsh and deeded the land as a shared park to raise the value of the surrounding lots. Enclosed by a cast-iron fence and framed by elegant 19th-century townhouses and clubs, it remains one of only two private parks in New York City; only residents of the fronting buildings and a handful of institutions hold keys to the locked gates. Passersby can admire the manicured grounds and its statue of actor Edwin Booth from the sidewalk. The park and its surrounding blocks form a designated historic district.'
WHERE slug = 'gramercy-park';

UPDATE poi SET
  summary = 'Grand Army Plaza is a public square at the southeast corner of Central Park in Manhattan, near Fifth Avenue and Central Park South. Split by 59th Street into two halves, it features the gilded equestrian statue of General William Tecumseh Sherman by Augustus Saint-Gaudens to the north and the Pulitzer Fountain to the south. Its current design dates to a 1916 reconstruction by Carrère and Hastings.',
  description = 'Grand Army Plaza, formerly Fifth Avenue Plaza and Central Park Plaza, is a public square at the southeast corner of Central Park in Manhattan, near the intersection of Fifth Avenue and Central Park South. It consists of two rectangular plots on the west side of Fifth Avenue between 58th and 60th Streets, bisected by 59th Street, and is a designated New York City scenic landmark. The northern half, carved from the corner of Central Park, centers on the gilded equestrian statue of William Tecumseh Sherman by Augustus Saint-Gaudens, while the southern half features the Pulitzer Fountain, topped by Karl Bitter''s bronze statue of the Roman goddess Pomona. Once a residential area dotted with hotels, the plaza is still flanked by the Plaza Hotel and the Sherry-Netherland. Its northern half was planned in 1858 as one of four entrance plazas at Central Park''s corners and expanded in 1868. Karl Bitter proposed a unified design in 1898, and the Sherman statue was dedicated in 1903. After publisher Joseph Pulitzer died in 1911, the whole plaza was redesigned to plans by Carrère and Hastings, with the memorial fountain installed in 1916, and it was rededicated in 1924 in honor of the Grand Army of the Republic. The plaza and its fountain have been restored several times since.'
WHERE slug = 'grand-army-plaza';

UPDATE poi SET
  summary = 'Grand Central Terminal is a landmark commuter rail terminal at 42nd Street and Park Avenue in Midtown Manhattan. Opened in 1913, it is the southern terminus of Metro-North Railroad''s Harlem, Hudson, and New Haven Lines and, since 2023, serves the Long Island Rail Road via the underground Grand Central Madison. Celebrated for its Beaux-Arts architecture, it is one of the world''s most-visited attractions.',
  description = 'Grand Central Terminal is a commuter rail terminal at 42nd Street and Park Avenue in Midtown Manhattan. Opened in 1913 and built by the New York Central Railroad on the site of two earlier stations, it is the southern terminus of Metro-North Railroad''s Harlem, Hudson, and New Haven Lines. Since 2023 it has also served the Long Island Rail Road through Grand Central Madison, a 16-acre addition beneath the existing tracks, and it connects to the subway at Grand Central–42nd Street. It is the third-busiest train station in North America. The terminal''s Beaux-Arts station house has earned it National Historic Landmark status; its design incorporates numerous works of art, and its Main Concourse—often used as a meeting place and frequently featured in films—is one of the city''s iconic interiors. Grand Central is one of the world''s ten most-visited tourist attractions, with more than 21 million visitors in 2018 apart from train and subway passengers. It contains shops and food vendors, upscale restaurants and bars, a food hall, and a grocery market, along with a library, event hall, and railroad offices. Covering 48 acres with 44 platforms—more than any other station in the world—it serves 30 tracks on its upper level and 26 below. Intercity service ran until 1991, when Amtrak consolidated its New York operations at nearby Penn Station.'
WHERE slug = 'grand-central-terminal';

UPDATE poi SET
  summary = 'Grant''s Tomb, officially the General Grant National Memorial, is the mausoleum of Ulysses S. Grant, the Union Civil War general and 18th U.S. president, and his wife, Julia. Located in Riverside Park in Morningside Heights, it is the largest mausoleum in North America and is administered by the National Park Service.',
  description = 'Grant''s Tomb, officially the General Grant National Memorial, is a granite-and-marble mausoleum in Riverside Park at Riverside Drive and 122nd Street, in the Morningside Heights neighborhood of Upper Manhattan. It holds the remains of Ulysses S. Grant—commanding general of the Union Army during the Civil War and the 18th president of the United States—and his wife, Julia Dent Grant. Designed by architect John Duncan and funded largely through public donations, the monument was dedicated in 1897 on what would have been Grant''s 75th birthday, drawing an enormous crowd. Its domed, classical form was inspired by ancient tombs such as the Mausoleum at Halicarnassus, and at roughly 150 feet tall it is the largest mausoleum in North America. Inside, an open crypt displays the couple''s twin sarcophagi, surrounded by busts and murals commemorating Grant''s military career. Administered by the National Park Service and free to visit, the memorial stands as a monument to Grant''s role in preserving the Union.'
WHERE slug = 'grant-s-tomb';

UPDATE poi SET
  summary = 'Greenacre Park is a privately owned "vest-pocket" park on East 51st Street in the Turtle Bay neighborhood of Midtown Manhattan. Tucked mid-block, it offers a small urban oasis centered on a dramatic waterfall.',
  description = 'Greenacre Park is a small privately owned but publicly accessible "vest-pocket" park on East 51st Street between Second and Third Avenues, in the Turtle Bay neighborhood of Midtown Manhattan. Opened in 1971 and funded by the Greenacre Foundation, established by a granddaughter of John D. Rockefeller, it was designed as a tranquil retreat from the surrounding city on a compact mid-block lot. Its centerpiece is a 25-foot cascading waterfall that tumbles down a granite wall, its sound helping to mask city noise, surrounded by terraced seating, honey locust trees, planters, and a trellised area. Together with the better-known Paley Park a few blocks away, Greenacre is celebrated as a model of the pocket-park concept—demonstrating how a tiny sliver of urban land can be transformed into a lush, restorative green space. Open seasonally, it offers office workers, residents, and visitors a quiet place to sit, eat lunch, and escape the bustle of Midtown, and it is often cited in discussions of successful small-scale urban design.'
WHERE slug = 'greenacre-park';

UPDATE poi SET
  summary = 'Hamilton Grange National Memorial preserves the Grange, the only home ever owned by Alexander Hamilton, a Founding Father and the first U.S. Treasury Secretary. Now situated in St. Nicholas Park in Harlem, the Federal-style house is administered by the National Park Service.',
  description = 'Hamilton Grange National Memorial preserves "the Grange," the Federal-style country house that was the only home Alexander Hamilton ever owned. Hamilton—a Founding Father, principal author of the Federalist Papers, and the first Secretary of the Treasury—completed the house in 1802 on his estate in what was then rural upper Manhattan, but he lived there only about two years before his death in the 1804 duel with Aaron Burr. Designed by architect John McComb Jr., the house has been moved twice from its original site; in 2008 it was relocated to nearby St. Nicholas Park in Harlem and restored to reflect its early-19th-century appearance. Administered by the National Park Service, it is open to the public with period rooms and exhibits on Hamilton''s life, family, and career. Interest in the site surged following the success of the musical "Hamilton," and the memorial offers a tangible connection to one of the nation''s most consequential founders.'
WHERE slug = 'hamilton-grange-national-memorial';

UPDATE poi SET
  summary = 'The High Line Observation Deck refers to the elevated viewing points along the High Line, the popular elevated park on Manhattan''s West Side. Its best-known overlook, the 10th Avenue Square, is a sunken amphitheater with a large window framing the avenue and the city below.',
  description = 'The High Line Observation Deck refers to the elevated vantage points that make the High Line—an elevated linear park built on a former rail viaduct on Manhattan''s West Side—a destination for city views. Running some 30 feet above street level from the Meatpacking District through Chelsea to Hudson Yards, the park offers continuous open-air perspectives on the surrounding streets, the Hudson River, and the city''s architecture. Its most distinctive viewing feature is the 10th Avenue Square, a wooden, stadium-style amphitheater where visitors descend a few steps to sit before a large picture window that frames Tenth Avenue and the traffic flowing beneath the park—turning an ordinary city street into a framed urban tableau. Other overlooks and seating areas along the route provide views of landmarks such as the Statue of Liberty in the distance, the Hudson Yards towers, and the ever-changing West Side skyline. Integrated into the park''s landscaping of native plantings and walkways, these observation points draw crowds of walkers and photographers taking in the city from above.'
WHERE slug = 'high-line-observation-deck';

UPDATE poi SET
  summary = 'Highbridge Park is a public park on the western bank of the Harlem River in Washington Heights, Upper Manhattan, stretching between 155th and Dyckman Streets. It is home to the historic High Bridge—the city''s oldest standing bridge—and the High Bridge Water Tower.',
  description = 'Highbridge Park is a large, rugged public park running along the western bank of the Harlem River in the Washington Heights neighborhood of Upper Manhattan, stretching roughly from 155th Street north to Dyckman Street. Set on steep, rocky terrain, the park is operated by the New York City Department of Parks and Recreation, with its northern portion maintained in partnership with the nonprofit New York Restoration Project. Its most notable feature is the High Bridge, the oldest standing bridge in New York City, originally built in the 1840s as part of the Croton Aqueduct to carry fresh water into Manhattan; after decades of closure it was restored and reopened as a pedestrian walkway to the Bronx in 2015. Nearby stand the landmark High Bridge Water Tower and the Highbridge Play Center, a historic Works Progress Administration–era pool and recreation complex. The park also offers woodland trails, sports facilities, playgrounds, and one of the city''s mountain-biking trail networks, along with views across the Harlem River. Blending 19th-century water-supply history with natural landscape and recreation, Highbridge Park is a significant green space in Upper Manhattan.'
WHERE slug = 'highbridge-park';

UPDATE poi SET
  summary = 'Hudson River Park is a waterfront park stretching about four miles along the west side of Manhattan, from the Battery to 59th Street. Built on former shipping piers, it is one of the city''s largest open-space projects, offering promenades, piers, lawns, gardens, and recreation along the Hudson River.',
  description = 'Hudson River Park is a linear waterfront park running roughly four miles along the Hudson River on the west side of Manhattan, from Battery Park in the south to 59th Street in the north, covering about 550 acres of land and water. Developed beginning in the late 1990s on the site of decayed shipping piers and a former elevated highway, it is among the largest open-space initiatives in New York since the creation of Central Park. The park transformed a series of historic piers into public spaces offering lawns, gardens, esplanades, playgrounds, sports fields, boat launches, and a bikeway and greenway that form part of the Manhattan Waterfront Greenway. Individual piers host varied uses, from mini-golf and beach volleyball to nature exploration and event lawns, and the newer Little Island park is part of the system. Managed by the Hudson River Park Trust, it draws millions of visitors for recreation and offers sweeping views across the river to New Jersey.'
WHERE slug = 'hudson-river-park';

UPDATE poi SET
  summary = 'The Hudson River Park Trust is the public-benefit organization that builds, operates, and maintains Hudson River Park, the four-mile waterfront park along Manhattan''s West Side. Created jointly by New York State and City, it oversees the park''s piers, esplanades, gardens, and recreational facilities.',
  description = 'The Hudson River Park Trust is the joint New York State–City public-benefit corporation charged with the design, construction, operation, and maintenance of Hudson River Park, the roughly four-mile stretch of waterfront parkland along the Hudson River on Manhattan''s West Side. Established by the Hudson River Park Act of 1998, the Trust has led the multi-decade transformation of former shipping piers and derelict waterfront into a continuous public park running from the Battery to 59th Street, with lawns, gardens, sports facilities, boathouses, and a popular greenway. The Trust is notable for its largely self-sustaining financial model, generating much of its operating revenue from commercial activities within the park—such as pier leases—rather than relying primarily on tax dollars. It also oversees the Hudson River Park Estuarine Sanctuary, protecting the aquatic habitat in the waters along the park. Through the Trust''s stewardship, the park has become one of the most heavily used open spaces in the city.'
WHERE slug = 'hudson-river-park-trust';

UPDATE poi SET
  summary = 'The Theater at Madison Square Garden, known through naming rights as the Infosys Theater, is a mid-size performance venue within the Madison Square Garden complex in Midtown Manhattan. Seating around 5,600, it hosts concerts, family shows, awards ceremonies, and other events on a smaller scale than the main arena.',
  description = 'The Theater at Madison Square Garden—carrying the name Infosys Theater under a naming-rights agreement—is a performance space within the Madison Square Garden complex above Pennsylvania Station in Midtown Manhattan. Distinct from the much larger main arena, the theater seats roughly 5,600 and is configured for concerts, comedy, family entertainment, awards shows, and corporate and public events suited to a mid-size auditorium. Opened along with the current Madison Square Garden in 1968 and renovated over the years, it has hosted a wide range of programming, from music residencies and touring productions to televised events and seasonal shows. Its location within the MSG complex places it at a major transit hub adjacent to Penn Station, making it easily accessible. As the more intimate of the venues under the Madison Square Garden name, the theater complements the arena by accommodating events that do not require the arena''s full capacity.'
WHERE slug = 'infosys-theater-at-madison-square-garden';

UPDATE poi SET
  summary = 'The International Center of Photography (ICP) is a leading museum and school dedicated to photography and visual culture, located at 79 Essex Street in the Essex Crossing development on Manhattan''s Lower East Side. Since relocating there in 2020, it has united galleries, classrooms, and darkrooms under one roof.',
  description = 'The International Center of Photography (ICP) is a museum and school devoted to photography and visual culture, located at 79 Essex Street (with an entrance at 84 Ludlow Street) in the Essex Crossing development on the Lower East Side of Manhattan. Founded in 1974 by Cornell Capa—brother of the war photographer Robert Capa—to preserve and champion "concerned photography," ICP occupied several homes in the city before consolidating its museum and educational programs into an integrated 40,000-square-foot center, designed by the firm Gensler, that opened at Essex Crossing in 2020. The institution mounts changing exhibitions drawn from its extensive collection and from contemporary photographers, spanning documentary work, photojournalism, fashion, and experimental image-making, and it engages current social and political themes. Alongside its galleries, ICP operates a renowned photography school with classes, workshops, and degree programs, plus media labs, darkrooms, studios, a research library, a shop, and a café. It is widely regarded as one of the world''s foremost institutions dedicated to the photographic image.'
WHERE slug = 'international-center-of-photography';

UPDATE poi SET
  summary = 'The Intrepid Museum is a military, aerospace, and history museum at Pier 86 on the Hudson River in Manhattan''s Hell''s Kitchen. It is built aboard the USS Intrepid, a World War II–era aircraft carrier and National Historic Landmark, and its collection includes the space shuttle Enterprise, a Concorde, and the submarine USS Growler. It opened in 1982 and is run by the nonprofit Intrepid Museum Foundation.',
  description = 'The Intrepid Museum, originally the Intrepid Sea, Air & Space Museum, is a military, aerospace, and history museum at Pier 86 along the Hudson River in the Hell''s Kitchen neighborhood of Manhattan. Its exhibits, aircraft, and Space Shuttle Pavilion are housed aboard the USS Intrepid, a World War II–era aircraft carrier and National Historic Landmark, and its collection also includes the cruise-missile submarine USS Growler and a Concorde. Proposed in the late 1970s to preserve Intrepid, the museum opened on August 3, 1982; it struggled financially at first, filing for bankruptcy protection in 1985 and acquiring additional vessels to draw visitors. After a $115 million renovation from 2006 to 2008 it reopened, and a pavilion for the Space Shuttle Enterprise followed in 2012. The museum spans three of the carrier''s decks—flight, hangar, and gallery—with most of its collection made up of military aircraft, alongside a Lockheed A-12 reconnaissance plane and the shuttle. Its decks hold exhibit halls, a theater, and flight simulators, and the museum hosts community and national events such as Fleet Week as well as educational programs. It is operated by the nonprofit Intrepid Museum Foundation, established in 1979.'
WHERE slug = 'intrepid-museum';

UPDATE poi SET
  summary = 'Inwood Hill Park is a 196-acre public park at the northern tip of Manhattan, in the Inwood neighborhood. Set on a high schist ridge above the Hudson River, it contains the largest remaining old-growth forest on the island. Unlike most Manhattan parks, it is mostly natural, wooded, non-landscaped terrain.',
  description = 'Inwood Hill Park is a 196-acre public park in the Inwood neighborhood of Manhattan, operated by the New York City Department of Parks and Recreation. On a high schist ridge that rises about 200 feet above the Hudson River, from Dyckman Street to the northern tip of the island, its densely folded, glacially scoured topography contains the largest remaining old-growth forest on the island of Manhattan. The area is also known as the Shorakapkok Preserve—shorakapkok meaning "the sitting place" in the Munsee language of the Wecquaesgeek tribe, who inhabited the area for nearly 700 years. Unlike other Manhattan parks, Inwood Hill Park is largely composed of natural areas, consisting of mostly wooded, non-landscaped hills.'
WHERE slug = 'inwood-hill-park';

UPDATE poi SET
  summary = 'John V. Lindsay East River Park is a waterfront park along the East River on the Lower East Side of Manhattan, running for over a mile. Named for former mayor John Lindsay, it offers sports fields, an amphitheater, and a riverside esplanade with views toward Brooklyn.',
  description = 'John V. Lindsay East River Park is a long waterfront park stretching along the East River on the Lower East Side of Manhattan, from around Montgomery Street north toward East 12th Street. Named in 2001 for John V. Lindsay, mayor of New York from 1966 to 1973, the park has long given the densely populated Lower East Side rare access to open riverfront space, offering athletic fields, tennis and basketball courts, running and cycling paths, a track, and the East River Park Amphitheater, along with an esplanade and views across the river to Brooklyn and Queens. In recent years the park has been the subject of a major coastal-resiliency project—part of the city''s effort to protect the low-lying Lower East Side from flooding and storm surge after the damage of Hurricane Sandy—which has involved reconstructing and elevating much of the parkland. It remains a key recreational resource and waterfront green space for the neighborhood.'
WHERE slug = 'john-v-lindsay-east-river-park';

UPDATE poi SET
  summary = 'Koreatown is a compact, lively neighborhood in Midtown Manhattan centered on West 32nd Street near Herald Square. Packed with Korean restaurants, bars, karaoke rooms, and shops—many open around the clock—it is the cultural and culinary heart of Korean New York.',
  description = 'Koreatown is a small but intensely active neighborhood in Midtown Manhattan, concentrated along West 32nd Street between Fifth Avenue and Broadway, near Herald Square and the Empire State Building, with businesses spilling onto adjacent streets and upper floors; the block is often nicknamed "Korea Way." Developing from the 1980s onward as Korean-owned businesses clustered in the area, it became the commercial and cultural center of the Korean community in Manhattan. Unusually dense and vertical, the district stacks restaurants, Korean barbecue houses, bakeries, cafés, bars, karaoke ("noraebang") rooms, spas, and shops across multiple floors of its buildings, and much of it operates late into the night or around the clock. Koreatown draws a diverse crowd for authentic Korean food and nightlife, serving both as a gathering place for Korean New Yorkers and as a popular destination for visitors. Its concentrated, 24-hour energy in the heart of Midtown gives it a character distinct from the city''s larger residential ethnic enclaves.'
WHERE slug = 'koreatown-manhattan';

UPDATE poi SET
  summary = 'The Lena Horne Theatre is a Broadway theater at 256 West 47th Street in the Theater District of Midtown Manhattan. Designed by Herbert J. Krapp in a Spanish Revival style for Irwin Chanin and opened in 1926, it seats 1,069 and is operated by the Nederlander Organization. Formerly the Brooks Atkinson Theatre, it was renamed in 2022 for the singer, actress, and civil-rights activist Lena Horne.',
  description = 'The Lena Horne Theatre, previously the Mansfield and then the Brooks Atkinson Theatre, is a Broadway theater at 256 West 47th Street in the Theater District of Midtown Manhattan. Designed by Herbert J. Krapp in a Spanish Revival style for Irwin Chanin, it seats 1,069 across two levels and is operated by the Nederlander Organization; both its facade and auditorium are New York City landmarks. The facade combines a four-story stage house in buff brick with a three-story auditorium in yellow-beige brick and terracotta, with Palladian and sash windows above a marquee, topped by a tiled roof. The auditorium features ornamental plasterwork, a sloped orchestra, a large balcony with box seats and murals, and a coved ceiling. Opening as the Mansfield Theatre on February 15, 1926, it struggled to find hits until Michael Myerberg bought it in 1945; from 1950 it was leased to CBS for television as Studio 59. Returned to legitimate use in 1960, it was renamed for former New York Times critic Brooks Atkinson. The Nederlander Organization gained partial ownership in 1967 and full ownership in 1974. After a 2000 renovation it hosted 21st-century shows such as Waitress and Six, and on November 1, 2022, it was renamed for Lena Horne.'
WHERE slug = 'lena-horne-theatre';

UPDATE poi SET
  summary = 'Lincoln Center for the Performing Arts is a 16-acre complex of concert halls and theaters on the Upper West Side of Manhattan, the largest performing-arts center of its kind in the United States. Developed in the 1960s, it is home to resident companies including the Metropolitan Opera, the New York Philharmonic, and New York City Ballet.',
  description = 'Lincoln Center for the Performing Arts is a sprawling cultural complex on the Upper West Side of Manhattan, centered on a plaza and fountain between 62nd and 66th Streets near Columbus Avenue. Conceived as part of a mid-century urban-renewal effort and developed in the late 1950s and 1960s—with major support from John D. Rockefeller III—it gathered many of the city''s leading performing-arts institutions onto a single campus. Its principal venues include the Metropolitan Opera House, David Geffen Hall (home of the New York Philharmonic), and the David H. Koch Theater (home of New York City Ballet), along with halls and theaters for chamber music, theater, and film, the Juilliard School, and a branch of the New York Public Library devoted to the performing arts. The travertine-clad buildings frame outdoor plazas that host free events in warmer months. With about 30 indoor and outdoor performance spaces, Lincoln Center is the largest complex of its kind in the country and a cornerstone of New York''s cultural life.'
WHERE slug = 'lincoln-center';

UPDATE poi SET
  summary = 'Little Island is an artificial island and public park on Pier 55 in Hudson River Park, off Manhattan''s West Side near the Meatpacking District. Designed by Heatherwick Studio and largely funded by Barry Diller and Diane von Fürstenberg, it sits atop 132 planter-like concrete "tulips" rising from the river. Opened in 2021, its 2.4 acres include lawns, walking paths, and a 687-seat amphitheater.',
  description = 'Little Island, at Pier 55, is an artificial island and public park within Hudson River Park, off the western shore of Manhattan near the Meatpacking District and Chelsea. Designed by Heatherwick Studio, it is connected to the rest of Hudson River Park by footbridges at 13th and 14th Streets and offers two concession stands, a small stage, and a 687-seat amphitheater. The 2.4-acre park is supported by 132 pot-shaped concrete structures called "tulips," which rise 15 to 62 feet above the water on 280 pilings driven into the riverbed; its lawns, paths, and plantings were arranged by landscape architect Signe Nielsen. Plans for the park arose in 2014, funded largely by Barry Diller and Diane von Fürstenberg with some public support. Construction was delayed by lawsuits from the City Club of New York and briefly scrapped in 2017 over legal challenges and cost overruns, before being revived that October with state funding. Construction began in 2018, the project was renamed Little Island in 2019, and the park opened on May 21, 2021.'
WHERE slug = 'little-island';

UPDATE poi SET
  summary = 'Little Italy is a historic neighborhood in Lower Manhattan, centered on Mulberry Street, that was once the heart of New York''s Italian-American community. Though much diminished, it remains known for its Italian restaurants, cafés, and the annual Feast of San Gennaro.',
  description = 'Little Italy is a neighborhood in Lower Manhattan, traditionally centered on Mulberry Street between roughly Canal and Kenmare Streets, bordering Chinatown to the south and Nolita to the north. In the late 19th and early 20th centuries it was a densely populated enclave of Italian immigrants, one of the largest such communities in the United States, filled with tenements, social clubs, churches, and shops. Over the following decades, as later generations moved to the outer boroughs and suburbs and the adjacent Chinatown expanded, the Italian population dwindled and the neighborhood shrank to a few blocks. Today Little Italy survives largely as a compact, tourist-oriented strip of Italian restaurants, cafés, bakeries, and specialty food shops. Its best-known event is the Feast of San Gennaro, an eleven-day street festival held each September in honor of the patron saint of Naples, which fills Mulberry Street with food vendors, processions, and crowds. The neighborhood remains a symbol of the Italian-American heritage of New York City.'
WHERE slug = 'little-italy';

UPDATE poi SET
  summary = 'The Lunt-Fontanne Theatre is a Broadway theater at 205 West 46th Street in the Theater District of Midtown Manhattan. Opened in 1910 as the Globe Theatre and renamed in 1958 for the acting couple Alfred Lunt and Lynn Fontanne, it seats about 1,500 and is operated by the Nederlander Organization.',
  description = 'The Lunt-Fontanne Theatre is a Broadway house at 205 West 46th Street in the Theater District of Midtown Manhattan. It opened in 1910 as the Globe Theatre, designed by the firm Carrère and Hastings for producer Charles Dillingham, and originally featured a roof that could open to the sky. After serving for a time as a movie theater, it was extensively renovated and reopened in 1958 as the Lunt-Fontanne, named for the celebrated husband-and-wife stage actors Alfred Lunt and Lynn Fontanne. Seating roughly 1,500 and operated by the Nederlander Organization, it is a large house well suited to musicals, and over the decades it has hosted major productions, star vehicles, and long runs of family musicals. Its Beaux-Arts origins and later remodeling give it a distinctive place among Broadway theaters, and the Lunt-Fontanne remains an active venue for large-scale shows.'
WHERE slug = 'lunt-fontanne-theatre';

UPDATE poi SET
  summary = 'The Lyceum Theatre is a Broadway theater at 149 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1903, it is the oldest continuously operating legitimate theater in New York City and one of the oldest surviving Broadway venues. Designed by Herts & Tallant in the Beaux-Arts style for impresario Daniel Frohman, it seats 922 and is operated by the Shubert Organization.',
  description = 'The Lyceum Theatre is a Broadway theater at 149 West 45th Street in the Theater District of Midtown Manhattan. Opened in 1903, it is one of the oldest surviving Broadway venues and the oldest continuously operating legitimate theater in New York City. Designed by Herts & Tallant in the Beaux-Arts style for impresario Daniel Frohman, it seats 922 across three levels and is operated by the Shubert Organization; its facade was designated a city landmark in 1974 and its lobby and auditorium in 1987. The theater retains most of its original Beaux-Arts design, with a 45th Street facade featuring an undulating glass-and-metal marquee and a colonnade with three arched windows, a groin-vaulted lobby with murals, and an ornately decorated proscenium and boxes. An apartment above the lobby, originally used by Frohman, became the headquarters of the Shubert Archives in 1986. The current Lyceum replaced Frohman''s earlier theater on Fourth Avenue and opened on November 2, 1903, with the play The Proud Prince. Frohman later partnered with David Belasco until 1930, then lost the theater to foreclosure during the Great Depression; a syndicate of George S. Kaufman, Max Gordon, and Moss Hart bought it in 1940, and the Shubert Organization has operated it since 1950. It was later leased to the Association of Producing Artists and, in the 1990s, the National Actors Theatre.'
WHERE slug = 'lyceum-theatre';

UPDATE poi SET
  summary = 'The Lyric Theatre is a large Broadway theater at 213 West 42nd Street in the Theater District of Midtown Manhattan. Opened in its current form in 1998 and rebuilt behind historic facades, it is Broadway''s largest theater by capacity, seating around 1,900, and is operated by ATG Entertainment.',
  description = 'The Lyric Theatre is a Broadway house at 213 West 42nd Street, between Seventh and Eighth Avenues in the Theater District of Midtown Manhattan. It was created as part of the 1990s redevelopment of 42nd Street, combining the sites and preserved architectural elements of two historic early-20th-century theaters—the Lyric and the Apollo—into a single large modern house that opened in 1998, originally as the Ford Center for the Performing Arts. After subsequent renamings it took the Lyric name, and with roughly 1,900 seats it is the largest Broadway theater by capacity. Suited to big-budget spectacles, it has hosted large-scale musicals such as "Ragtime" and "42nd Street," and later "Harry Potter and the Cursed Child," which was staged there following a major theater renovation. Operated by ATG Entertainment, the Lyric anchors the revitalized 42nd Street theater corridor near Times Square.'
WHERE slug = 'lyric-theatre';

UPDATE poi SET
  summary = 'Macy''s Herald Square is the flagship department store of the Macy''s chain, occupying a full block at Herald Square in Midtown Manhattan. Opened at the site in 1902 and long billed as one of the world''s largest stores, it is famous for its wooden escalators and the annual Thanksgiving Day Parade.',
  description = 'Macy''s Herald Square is the flagship location of the Macy''s department store chain, filling the block bounded by Broadway, Seventh Avenue, and 34th and 35th Streets at Herald Square in Midtown Manhattan. The store opened at this site in 1902 and, through later expansions, grew into one of the largest department stores in the world by floor area, spread across roughly ten selling floors. Its Beaux-Arts facade is a designated landmark, and among its most beloved features are the original early-20th-century wooden escalators still in use in parts of the store. Macy''s is closely tied to two New York traditions: the Macy''s Thanksgiving Day Parade, staged since 1924 with its giant character balloons that end at the store, and the annual Fourth of July fireworks it sponsors. The flagship draws shoppers and tourists year-round, particularly during its elaborate holiday window displays and its annual spring flower show, and it remains a symbol of New York retail.'
WHERE slug = 'macy-s-herald-square';

UPDATE poi SET
  summary = 'Madison Square Garden, known as the Garden or MSG, is a multi-purpose indoor arena in Midtown Manhattan, sitting above Pennsylvania Station between Seventh and Eighth Avenues. Opened in 1968, it is the fourth venue to bear the name and the oldest major sports arena in the New York area. It is home to the NBA''s New York Knicks and the NHL''s New York Rangers.',
  description = 'Madison Square Garden, colloquially the Garden or MSG, is a multi-purpose indoor arena in Midtown Manhattan, located between Seventh and Eighth Avenues from 31st to 33rd Streets, above Pennsylvania Station. It is the fourth venue to bear the name; the first two, opened in 1879 and 1890, stood at Madison Square, and the third (1925) was farther uptown at Eighth Avenue and 50th Street. The current arena opened on February 11, 1968, on the site of the former Pennsylvania Station, and is the oldest major sporting facility in the New York metropolitan area—the oldest arena in the NBA and second-oldest in the NHL. It is home to the New York Knicks of the NBA and the New York Rangers of the NHL, and was home to the WNBA''s New York Liberty from 1997 to 2017. Beyond basketball and hockey, it hosts boxing, mixed martial arts, professional wrestling, concerts, circuses, and ice shows, and ranks among the busiest music arenas in the world. Its two major renovations, in 1991 and 2013, brought its total construction cost to roughly $1.1 billion. The Garden is part of the Pennsylvania Plaza office and retail complex.'
WHERE slug = 'madison-square-garden';

UPDATE poi SET
  summary = 'The Majestic Theatre is a Broadway theater at 245 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1927, it was designed by Herbert J. Krapp in a Spanish style for developer Irwin S. Chanin and seats about 1,681. Operated by the Shubert Organization, it famously housed The Phantom of the Opera for 35 years.',
  description = 'The Majestic Theatre is a Broadway theater at 245 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1927 and designed by Herbert J. Krapp in a Spanish style for real-estate developer Irwin S. Chanin, it seats 1,681 across two levels and is operated by the Shubert Organization; both its facade and interior are New York City landmarks. The facade, of golden brick, terracotta, and stone, is divided into an entrance section with a terracotta pediment and a stage house topped by archways. The auditorium features Adam-style detailing, steep stadium-style orchestra seating, a large decorated balcony, a broad plaster dome, and box seats at balcony level. The Majestic, the Bernard B. Jacobs, and the John Golden theaters, along with the Lincoln Hotel, were developed together by Chanin and Krapp as a theater-and-hotel complex, and the Shuberts have operated the Majestic since 1930. Always intended for large musicals, it premiered Carousel, South Pacific, The Music Man, Camelot, A Little Night Music, and The Wiz. From 1988 to 2023 it housed The Phantom of the Opera, which was the longest-running production in Broadway history when it closed.'
WHERE slug = 'majestic-theatre';

UPDATE poi SET
  summary = 'The Marquis Theatre is a Broadway theater at 210 West 46th Street, inside the New York Marriott Marquis hotel in Times Square. Opened in 1986, it seats about 1,600 and is operated by the Nederlander Organization—one of the few large Broadway houses built in the modern era.',
  description = 'The Marquis Theatre is a Broadway house at 210 West 46th Street, built into the base of the New York Marriott Marquis hotel in the heart of Times Square. It opened in 1986 as part of the hotel''s construction, a project that controversially required the demolition of several historic Broadway theaters on the site. One of the few large Broadway houses built in the modern era, the Marquis seats roughly 1,600 and is operated by the Nederlander Organization. Its contemporary design contrasts with the ornate early-20th-century houses that surround it, and its location within a major hotel, steps from the TKTS booth, places it at the very center of the Theater District. Over the years it has hosted numerous musicals and revivals, and it remains an active, sizable Broadway venue in the busiest part of Times Square.'
WHERE slug = 'marquis-theatre';

UPDATE poi SET
  summary = 'Mercer Labs is a museum of art and technology at 21 Dey Street in Lower Manhattan, presenting immersive, multi-sensory installations across a series of experiential rooms. Co-created by artist Roy Nachum and Michael Cayre, it opened in 2024 in part of the former Century 21 building.',
  description = 'Mercer Labs is a Museum of Art and Technology at 21 Dey Street in Lower Manhattan, near the World Trade Center. Co-created by the artist Roy Nachum and entrepreneur Michael Cayre, it opened in early 2024 in a portion of the former Century 21 department store building, spanning some 36,000 square feet. The museum leads visitors through about 15 experiential spaces that blend visual art, projection, sound, and interactivity to explore the intersection of art, technology, and perception. Installations range from enveloping projection environments and mirrored rooms to responsive works that react to visitors'' movements, combining the sensibilities of a contemporary art gallery with those of an immersive attraction. Much of the work reflects the aesthetic of co-founder Roy Nachum, known for his multisensory painting and design. Mercer Labs is among the newest additions to New York''s growing roster of immersive, experience-driven art venues.'
WHERE slug = 'mercer-labs';

UPDATE poi SET
  summary = 'The MetLife Building is a 59-story, 808-foot skyscraper at 200 Park Avenue, rising just north of Grand Central Terminal in Midtown Manhattan. Designed in the International style by Richard Roth, Walter Gropius, and Pietro Belluschi and completed in 1962, it was advertised as the world''s largest commercial office building at its opening. Originally the Pan Am Building, it remains one of the tallest office towers in the United States.',
  description = 'The MetLife Building, also 200 Park Avenue and formerly the Pan Am Building, is a skyscraper at Park Avenue and 45th Street, just north of Grand Central Terminal in Midtown Manhattan. Designed in the International style by Richard Roth, Walter Gropius, and Pietro Belluschi and completed in 1962, it stands 808 feet tall with 59 stories and, at its opening, was advertised as the world''s largest commercial office building by floor area, with 2.4 million square feet of usable space. It remains among the 100 tallest buildings in the United States. Its elongated octagonal form sits atop two levels of railroad tracks leading into Grand Central, and its facade was one of the first precast-concrete exterior walls in a New York City building. The lobby connects by a pedestrian passage to Grand Central''s Main Concourse and holds artwork, with a parking garage at the base and a rooftop heliport that operated briefly in the 1960s and 1977. First proposed in 1954 to raise money for the struggling railroads that ran Grand Central, the tower—initially called Grand Central City—was built behind the terminal rather than in its place; work began in 1959 and it opened in 1963 as the headquarters of Pan American World Airways. MetLife bought the building in 1981, used it as its headquarters, and sold it in 2005. Its design has been widely criticized, largely for its dominating position beside Grand Central.'
WHERE slug = 'metlife-building';

UPDATE poi SET
  summary = 'The Morris-Jumel Mansion is an 18th-century historic house museum in the Washington Heights neighborhood of Upper Manhattan. Built in 1765, it is the oldest surviving house in Manhattan and briefly served as George Washington''s headquarters during the Revolutionary War. City-owned since 1903 and run as a museum, it is a National Historic Landmark.',
  description = 'The Morris–Jumel Mansion is an 18th-century historic house museum in the Washington Heights neighborhood of Upper Manhattan. Built in 1765 by British military officer Roger Morris, it is the oldest surviving house in Manhattan and was later home to the family of socialite Eliza Jumel in the 19th century. During the Revolutionary War, Continental Army General George Washington used the mansion as his temporary headquarters for about a month in late 1776, after which British and Hessian officers occupied it until 1783. Following the British evacuation, the house passed through many owners, serving variously as a residence and a tavern, until the Jumels bought it in 1810. The city acquired the mansion in 1903, and it reopened as a museum in 1907. Designed with Federal, Georgian, and Palladian elements, the house has a raised basement and three above-ground stories, a wooden facade with a double-height portico facing south, and an octagonal rear annex. Its interior includes a basement kitchen; a parlor, library, and dining room on the first floor; and bedrooms above, joined by wide central hallways. The museum''s collection includes furniture, decorations, and personal items of its former occupants, and it hosts performances and events. Its facade and interior are New York City designated landmarks, and the building is a National Historic Landmark and a contributing property to the Jumel Terrace and Dominican Historic Districts.'
WHERE slug = 'morris-jumel-mansion';

UPDATE poi SET
  summary = 'The Museum of Arts and Design (MAD) is a museum at 2 Columbus Circle in Midtown Manhattan dedicated to contemporary and historic craft, art, and design. It collects and exhibits objects that document innovation in materials and making, from glass and ceramics to jewelry and beyond.',
  description = 'The Museum of Arts and Design (MAD) is a museum at 2 Columbus Circle, on the southern edge of Central Park in Midtown Manhattan, dedicated to contemporary and historic craft, art, and design. Founded in 1956—originally as the Museum of Contemporary Crafts—it champions the creative process by which materials such as clay, glass, wood, metal, and fiber are transformed into works of art and design. Its collection and changing exhibitions explore craft traditions and cutting-edge making across disciplines including jewelry, ceramics, furniture, fashion, and studio glass. Since 2008 the museum has occupied a distinctive redesigned building at Columbus Circle, whose terracotta-and-glass facade replaced the controversial original "lollipop" building on the site. Inside, galleries are complemented by open artist studios where visitors can watch resident artists at work, along with education programs, a shop, and a restaurant with views over Columbus Circle. By focusing on materials and process, MAD occupies a distinctive niche among New York''s museums, celebrating the artistry of handmade and designed objects and their role in everyday life.'
WHERE slug = 'museum-of-arts-and-design';

UPDATE poi SET
  summary = 'The Museum of Broadway is the first permanent museum dedicated to the history of Broadway theatre, located at 145 West 45th Street in the Theater District near Times Square. Opened in 2022, its immersive, walk-through exhibits trace Broadway''s evolution through costumes, artifacts, and interactive installations.',
  description = 'The Museum of Broadway is the first permanent museum devoted to the history and experience of Broadway theatre, located at 145 West 45th Street in the heart of the Theater District near Times Square. Opened in November 2022 and spanning about 26,000 square feet across multiple floors, it was founded by Julie Boardman and Diane Nicoletti in collaboration with Playbill and other theatrical organizations. The museum presents an immersive, walk-through journey through Broadway''s past, present, and future, with nearly 500 artifacts, costumes, and props drawn from hundreds of productions. Its major sections include a Map Room exploring the geography and history of the Broadway district, a comprehensive timeline charting the art form''s evolution, and "The Making of a Broadway Show," a behind-the-scenes look at how a production comes together. Interactive, heavily designed installations—many created by leading theatrical designers—make it as much an experience as a traditional museum, celebrating the artistry, history, and cultural impact of Broadway.'
WHERE slug = 'museum-of-broadway';

UPDATE poi SET
  summary = 'The Museum of Ice Cream is an interactive, experience-based attraction at 558 Broadway in SoHo, built around playful, photo-friendly installations themed on ice cream. Its permanent New York flagship opened in 2019 and includes a multi-story slide and a signature sprinkle pool.',
  description = 'The Museum of Ice Cream is an immersive "experience museum" at 558 Broadway in SoHo, designed around the idea that ice cream sparks joy and connection. Rather than displaying objects behind glass, it fills roughly 25,000 square feet across three floors with about 13 interactive art installations meant to be explored, played in, and photographed. Signature features include a three-story indoor slide, a pink Museum of Ice Cream subway car, and a large "sprinkle pool" that guests can wade into, with ice cream tastings and other treats included in admission. The concept began as a temporary pop-up in 2016 before its permanent SoHo home opened in 2019, and it has since welcomed millions of visitors. The venue periodically refreshes its installations, most recently unveiling a reimagined experience in early 2026.'
WHERE slug = 'museum-of-ice-cream';

UPDATE poi SET
  summary = 'The Museum of Illusions is an interactive attraction at 77 Eighth Avenue, on the edge of Chelsea and the Meatpacking District in Manhattan, filled with optical illusions, mind-bending rooms, and hands-on exhibits. Part of a global chain, the New York location opened in 2018 with more than 50 illusions.',
  description = 'The Museum of Illusions is an interactive museum at 77 Eighth Avenue, near West 14th Street on the edge of Chelsea and the Meatpacking District in Manhattan. Opened in 2018 as part of an international chain of illusion museums, it fills a historic former bank building with more than 50 hands-on exhibits, installations, and holograms built around optical and perceptual illusions. Popular features include an Infinity Room lined with mirrors that appears to extend endlessly, an Ames Room in which people seem to grow or shrink as they cross it, and a rotated "reverse" room that makes visitors look as though they are defying gravity. The exhibits are designed to be photographed, and the museum bills itself as an entertaining, family-friendly stop that also illustrates how the brain and eyes can be fooled. It is one of several playful, experience-oriented attractions to open in Manhattan in recent years.'
WHERE slug = 'museum-of-illusions-new-york';

UPDATE poi SET
  summary = 'The Museum of Modern Art (MoMA) is an art museum at 11 West 53rd Street in Midtown Manhattan, widely regarded as one of the most influential museums of modern and contemporary art in the world. Founded in 1929, its collection spans painting, sculpture, photography, film, design, and architecture.',
  description = 'The Museum of Modern Art, known as MoMA, is one of the largest and most influential modern art museums in the world, located at 11 West 53rd Street in Midtown Manhattan. Founded in 1929 by Abby Aldrich Rockefeller and two associates, it was among the first museums devoted to collecting and exhibiting modern art, and it played a central role in establishing modern art as a field of serious study. Its collection of roughly 200,000 works spans painting, sculpture, drawing, photography, film, design, and architecture, with iconic holdings such as Vincent van Gogh''s "The Starry Night," Pablo Picasso''s "Les Demoiselles d''Avignon," and Andy Warhol''s "Campbell''s Soup Cans." The museum''s galleries, sculpture garden, film archive, and design collection draw millions of visitors annually. A major expansion completed in 2019 significantly enlarged its exhibition space, reaffirming its status as a cornerstone of New York''s cultural life.'
WHERE slug = 'museum-of-modern-art';

UPDATE poi SET
  summary = 'The Museum of Sex, or MoSex, is a museum at 233 Fifth Avenue in Manhattan dedicated to the history, evolution, and cultural significance of human sexuality. Its exhibits span topics from LGBTQ history and erotica to pornography and sex work, and admission is limited to visitors 18 and older. Founded by Daniel Gluck, it opened in 2002.',
  description = 'The Museum of Sex, also known as MoSex, is a museum dedicated to preserving and presenting the history, evolution, and cultural significance of human sexuality. It focuses on a range of sexual preferences and subcultures, including lesbian and gay history and erotica, BDSM, pornography, and sex work, and because of the explicit content of its educational exhibits, visitors must be at least 18 years old. Despite initial controversy from religious groups and an early rejection for non-profit status by the New York State Board of Regents, the museum has operated without significant opposition since opening and has hosted interfaith events exploring sexuality and religion. Located at 233 Fifth Avenue at the corner of East 27th Street in Manhattan, the museum opened on October 5, 2002, founded by Daniel Gluck. In 2024, it expanded with a second location in Miami, Florida.'
WHERE slug = 'museum-of-sex';

UPDATE poi SET
  summary = 'The National Museum of Mathematics, known as MoMath, is the only museum in North America dedicated to mathematics, located near Madison Square Park in Manhattan''s NoMad neighborhood. It offers more than 30 interactive, hands-on exhibits that make mathematical ideas playful and accessible for visitors of all ages.',
  description = 'The National Museum of Mathematics, known as MoMath, is the only museum in North America devoted to mathematics, located in the NoMad/Flatiron area of Manhattan near Madison Square Park. It opened in 2012 at 11 East 26th Street and has since relocated to a larger home nearby. Spread across two floors, the museum features more than 30 colorful, interactive exhibits designed to reveal the beauty and playfulness of math to visitors of all ages. Hands-on installations let guests ride a tricycle with square wheels across a specially shaped surface, explore geometry and symmetry through light and motion, manipulate digital and physical puzzles, and find mathematical patterns in art and nature. Beyond its galleries, MoMath runs a busy calendar of public lectures, family programs, and events aimed at sparking curiosity about mathematics and countering the notion that the subject is dull or intimidating. Founded to celebrate math as engaging and creative, it has become a popular educational attraction for children, families, and math enthusiasts.'
WHERE slug = 'national-museum-of-mathematics';

UPDATE poi SET
  summary = 'The Nederlander Theatre is a Broadway theater at 208 West 41st Street, the southernmost house in the Theater District of Midtown Manhattan. Opened in 1921, it seats about 1,235 and is operated by the Nederlander Organization, which named it in 1980 for impresario David Tobias Nederlander. It is best known for the long run of the musical Rent.',
  description = 'The Nederlander Theatre, formerly the National, Billy Rose, and Trafalgar Theatre, is a Broadway theater at 208 West 41st Street—the southernmost house in the Theater District of Midtown Manhattan. Opened in 1921 and designed by William Neil Smith for theatrical operator Walter C. Jordan, it seats about 1,235 across two levels and is operated by the Nederlander Organization, which named it in 1980 for impresario David Tobias Nederlander, father of producer James M. Nederlander. Its facade is relatively plain brick, and its auditorium, originally in an early Renaissance style with little plaster decoration, has been modified several times. Built as a carpenter''s shop in 1920 and converted into the National Theatre the next year, the venue was managed by the Shuberts on Jordan''s behalf when it opened in 1921; the Shubert brothers bought it in 1927 and ran it for three decades. In 1956, under an antitrust settlement, they sold it to Harry Fromkes, and in 1958 producer Billy Rose acquired and renamed it after himself. The Nederlander Organization and the Cooney-Marsh Organization bought it in 1978, and it took its current name in 1980. With few other theaters nearby, it hosted little until the musical Rent opened, which became its longest-running production. Other shows there have included Cyrano de Bergerac and performances by Lena Horne.'
WHERE slug = 'nederlander-theatre';

UPDATE poi SET
  summary = 'The Neil Simon Theatre is a Broadway theater at 250 West 52nd Street in the Theater District of Midtown Manhattan. Opened in 1927 as the Alvin Theatre and renamed in 1983 for the playwright Neil Simon, it seats about 1,450 and is operated by the Nederlander Organization.',
  description = 'The Neil Simon Theatre is a Broadway house at 250 West 52nd Street in the Theater District of Midtown Manhattan. Opened in 1927 as the Alvin Theatre—its name formed from the first names of its builders, Alex Aarons and Vinton Freedley—it was designed by architect Herbert J. Krapp and seats roughly 1,450 across two levels. In 1983 it was renamed in honor of the prolific American playwright Neil Simon. Operated by the Nederlander Organization, the theater has a distinguished history, having premiered classic musicals and plays over the decades—including early works by George and Ira Gershwin—and later hosting a range of long-running musicals. Its facade and interior reflect the neo-Georgian and Adam-style detailing characteristic of Krapp''s Broadway theaters. The Neil Simon remains one of the larger Broadway houses and a regular home for major musical productions.'
WHERE slug = 'neil-simon-theatre';

UPDATE poi SET
  summary = 'The Neue Galerie New York is a museum of early 20th-century German and Austrian art and design on the Upper East Side of Manhattan. Established in 2001, it occupies the William Starr Miller House at 86th Street and Fifth Avenue, among the most recent additions to Museum Mile. In 2026 it announced that it would merge with the Metropolitan Museum of Art in 2028.',
  description = 'The Neue Galerie New York is a museum of early twentieth-century German and Austrian art and design on the Upper East Side of Manhattan. It is located in the William Starr Miller House at 86th Street and Fifth Avenue. Established in 2001, it is one of the most recent additions to New York City''s Museum Mile. In 2026, the museum and the Metropolitan Museum of Art announced that the two institutions would merge in 2028.'
WHERE slug = 'neue-galerie-new-york';

UPDATE poi SET
  summary = 'The New Museum of Contemporary Art is a museum at 235 Bowery on the Lower East Side of Manhattan, dedicated to contemporary art and emerging artists. Founded in 1977 by Marcia Tucker, it occupies a distinctive stacked-box building designed by the Japanese firm SANAA.',
  description = 'The New Museum of Contemporary Art is a museum at 235 Bowery on the Lower East Side of Manhattan. It was founded in 1977 by Marcia Tucker, a former curator at the Whitney Museum of American Art, as a space devoted to contemporary art and living artists. From the outset it set itself apart by showing new, experimental, and often under-recognized work rather than assembling a large permanent collection. After occupying several homes in its early decades, the museum opened its purpose-built Bowery home in 2007. Designed by the Pritzker Prize–winning Japanese firm SANAA, the building is composed of off-center stacked boxes wrapped in a shimmering aluminum mesh — a striking form that helped spur the cultural revival of the Bowery. The museum presents rotating exhibitions of contemporary art from around the world, along with performances, public programs, and education initiatives, and in 2014 it launched NEW INC, a cultural incubator supporting practitioners working at the intersection of art, design, and technology.'
WHERE slug = 'new-museum';

UPDATE poi SET
  summary = 'New World Stages is an Off-Broadway performing-arts complex at 340 West 50th Street in the Hell''s Kitchen area of Midtown Manhattan. Housed in a former multiplex cinema below street level, it contains five stages hosting long-running commercial Off-Broadway shows.',
  description = 'New World Stages is an Off-Broadway theater complex at 340 West 50th Street, near Eighth and Ninth Avenues in the Hell''s Kitchen area of Midtown Manhattan. Located below street level in a space that originally opened as a multiplex movie theater, it was converted into a performing-arts venue in the mid-2000s. The complex contains five separate stages of varying sizes, allowing multiple productions to run simultaneously, and it has become a leading home for commercial Off-Broadway shows—both open-ended long-runners and transfers of former Broadway productions extending their New York life. Over the years its stages have hosted hit plays, musicals, and comedies, including long-running productions that found sustained success at the Off-Broadway scale. With its cluster of flexible modern theaters, New World Stages offers a contemporary alternative to the historic Broadway houses a few blocks east and is a significant venue in the New York commercial theater landscape.'
WHERE slug = 'new-world-stages';

UPDATE poi SET
  summary = 'New York City Center is a performing-arts theater at 131 West 55th Street in Midtown Manhattan, known for dance, musical theater, and its "Encores!" concert series. Opened in 1923 in a Moorish Revival building, it was the city''s first municipally owned performing-arts center.',
  description = 'New York City Center is a performing-arts venue at 131 West 55th Street in Midtown Manhattan. Built in 1923 as a Shriners'' meeting hall—the Mecca Temple—in an elaborate Moorish Revival style, the building was acquired by the City of New York and reopened in 1943 as City Center of Music and Drama, becoming the city''s first municipally owned performing-arts center. Championed by Mayor Fiorello La Guardia, it was dedicated to making theater, opera, ballet, and concerts accessible to a broad public at affordable prices, and it served as an early home for institutions that later moved to Lincoln Center, including the New York City Ballet and New York City Opera. Today City Center is especially known for dance—hosting leading companies and the annual Fall for Dance festival—and for "Encores!," its acclaimed series of staged concert revivals of classic American musicals. Its landmark tiled dome and richly decorated auditorium were restored in a 2011 renovation.'
WHERE slug = 'new-york-city-center';

UPDATE poi SET
  summary = 'New York City Hall is the seat of New York City government, at the center of City Hall Park in Lower Manhattan''s Civic Center. Constructed from 1803 to 1812, it is the oldest city hall in the United States still housing its original governmental functions. It contains the office of the Mayor and the chambers of the City Council.',
  description = 'New York City Hall is the seat of New York City government, located at the center of City Hall Park in the Civic Center area of Lower Manhattan, between Broadway, Park Row, and Chambers Street. Constructed from 1803 to 1812, it is the oldest city hall in the United States that still houses its original governmental functions. The building holds the office of the Mayor of New York City and the chambers of the New York City Council. While the Mayor''s Office is in the building, the staff of thirteen municipal agencies under mayoral control are located in the nearby Manhattan Municipal Building—one of the largest government buildings in the world—with many others housed in buildings in the immediate vicinity. New York City Hall is a National Historic Landmark and is listed on the National Register of Historic Places, and the New York City Landmarks Preservation Commission designated its exterior and interior as official city landmarks in 1966 and 1976, respectively.'
WHERE slug = 'new-york-city-hall';

UPDATE poi SET
  summary = 'The New York Historical (formerly the New-York Historical Society) is an American history museum and library on the Upper West Side of Manhattan, facing Central Park. Founded in 1804 as New York''s first museum, it presents exhibitions and research exploring the history of New York and the nation.',
  description = 'The New York Historical—long known as the New-York Historical Society—is a history museum and research library on Central Park West between 76th and 77th Streets on the Upper West Side of Manhattan. Founded in 1804, it is the oldest museum in New York City, established to collect and preserve materials documenting the history of the city, state, and nation. Since 1908 it has occupied a granite building designed by the firm York & Sawyer in a Roman Eclectic style, a designated New York City landmark that has been expanded and renovated over the years, including a recent wing addition. Its holdings are vast and varied, encompassing American paintings and sculpture—notably a major collection of Hudson River School landscapes and the watercolors of John James Audubon—decorative arts, historical artifacts, and one of the country''s most important research libraries of manuscripts, prints, photographs, and documents. The institution mounts exhibitions on American history and culture, operates the DiMenna Children''s History Museum, and runs public programs, lectures, and educational initiatives. Combining museum and library under one roof, the New York Historical offers an in-depth look at the story of New York and the United States.'
WHERE slug = 'new-york-historical-society';

UPDATE poi SET
  summary = 'The Stephen A. Schwarzman Building is the landmark main branch of the New York Public Library, a Beaux-Arts palace on Fifth Avenue at 42nd Street in Midtown Manhattan. Opened in 1911 and famous for its marble lion statues and grand Rose Main Reading Room, it is one of the world''s great research libraries.',
  description = 'The Stephen A. Schwarzman Building is the flagship of the New York Public Library, a monumental Beaux-Arts structure on Fifth Avenue between 40th and 42nd Streets in Midtown Manhattan, adjoining Bryant Park. Designed by the firm Carrère and Hastings and built of white Vermont marble, it opened in 1911 as one of the largest marble buildings in the United States and serves as the library''s principal research center, holding vast collections of books, manuscripts, maps, and archives. Guarding its Fifth Avenue steps are the celebrated pair of marble lions, nicknamed "Patience" and "Fortitude," which have become symbols of the library and the city. Inside, the building is known for its magnificent public spaces, above all the Rose Main Reading Room—a nearly block-long, ornately decorated hall beneath elaborate ceiling murals—as well as the McGraw Rotunda. A National Historic Landmark and New York City landmark, the building was renamed in 2008 for benefactor Stephen A. Schwarzman and remains both a working research library and a major cultural attraction.'
WHERE slug = 'new-york-public-library-stephen-a-schwarzman-building';

UPDATE poi SET
  summary = 'The Oculus is the striking transit hub and shopping center at the World Trade Center in Lower Manhattan, serving as the main station house of the World Trade Center Transportation Hub. Designed by Santiago Calatrava and opened in 2016, its soaring white ribbed structure resembles a bird in flight.',
  description = 'The Oculus is the central station house of the World Trade Center Transportation Hub, a major transit and retail complex in Lower Manhattan''s Financial District. Designed by the Spanish architect Santiago Calatrava and opened in 2016, it connects the PATH commuter line to New Jersey with several New York City Subway lines and the surrounding World Trade Center buildings. The structure is defined by its dramatic exterior of white steel ribs that sweep upward and outward, evoking a bird being released from a child''s hands. Inside, a vast, light-filled marble hall—the Oculus proper—rises beneath a skylight that runs the length of the roof and opens each year on September 11. Below and around the main hall, the Westfield World Trade Center shopping concourse houses shops and restaurants. Widely praised for its ambition and criticized for its enormous cost and delays, the Oculus has become a striking architectural landmark of the rebuilt World Trade Center and a busy hub for commuters and visitors alike.'
WHERE slug = 'oculus';

UPDATE poi SET
  summary = 'One Times Square is a 25-story, 363-foot skyscraper on Times Square in Midtown Manhattan, built in 1903–1904 as the headquarters of The New York Times. The neighborhood was renamed Times Square for the tower, which became famous as the site of the annual New Year''s Eve ball drop. Now largely stripped of its original detail and wrapped in billboards, it is one of the most valuable advertising locations in the world.',
  description = 'One Times Square, also known as the Times Tower, is a 25-story, 363-foot skyscraper on Times Square in Midtown Manhattan, bounded by Seventh Avenue, 42nd Street, Broadway, and 43rd Street. Designed by Cyrus L. W. Eidlitz in the neo-Gothic style, it was built in 1903–1904 as the headquarters of The New York Times, and the surrounding Longacre Square was renamed Times Square during its construction. Its original architecture has since been entirely obscured or removed, and its defining features are now the advertising billboards added to its facade in the 1990s, which make it one of the most valuable advertising sites in the world. The Times moved in around January 1905 but, quickly outgrowing the tower, relocated its offices eight years later to nearby 229 West 43rd Street. The building nonetheless remained a focal point through its annual New Year''s Eve ball drop and a street-level lighted news ticker introduced in 1928. The Times sold it in 1961, and it passed through several owners, serving mainly as an office building and, later, a billboard host after Lehman Brothers acquired it in 1995. Jamestown L.P. has owned it since 1997 and, beginning in 2022, undertook a $500 million renovation that added an observation deck, museum space, and a glass exterior, completed by 2026.'
WHERE slug = 'one-times-square';

UPDATE poi SET
  summary = 'One World Observatory is the observation attraction near the top of One World Trade Center in Lower Manhattan, occupying the 100th through 102nd floors of the Western Hemisphere''s tallest building. Opened in 2015, it offers panoramic views of Manhattan, New York Harbor, and beyond.',
  description = 'One World Observatory is the observation attraction at the top of One World Trade Center, the tallest building in the Western Hemisphere, in Lower Manhattan''s Financial District. Spanning the 100th, 101st, and 102nd floors—more than 1,250 feet above the ground—it opened on May 29, 2015. Visitors ascend in "SkyPod" elevators whose interior screens animate the growth of the New York skyline over centuries during the roughly one-minute ride, arriving through a short introductory presentation before the main viewing floor is revealed. Floor-to-ceiling windows then provide 360-degree views taking in the harbor, the Statue of Liberty, the Brooklyn and Manhattan Bridges, and the length of Manhattan Island. The observatory also features interactive displays, dining options, and an elevated glass disc called the "Sky Portal" that shows a live street-level view beneath visitors'' feet. As part of the rebuilt World Trade Center, it draws large numbers of visitors and complements the neighboring National September 11 Memorial & Museum.'
WHERE slug = 'one-world-observatory';

UPDATE poi SET
  summary = 'One World Trade Center, also known as One WTC or the Freedom Tower, is the main building of the rebuilt World Trade Center complex in Lower Manhattan. Designed by David Childs of Skidmore, Owings & Merrill and completed in 2014, it is the tallest building in the Western Hemisphere at a symbolic 1,776 feet. It stands on the northwest corner of the World Trade Center site, replacing the destroyed original North Tower.',
  description = 'One World Trade Center, also known as One WTC and the Freedom Tower, is the main building of the rebuilt World Trade Center complex in Lower Manhattan. Designed by David Childs of Skidmore, Owings & Merrill, it is the tallest building in the United States and the Western Hemisphere and among the tallest in the world. It shares its name with the North Tower of the original World Trade Center, destroyed in the September 11, 2001 attacks, and stands on the northwest corner of the 16-acre site, bounded by West, Vesey, Fulton, and Washington Streets. Construction of the foundations began in April 2006. The tower surpassed the Empire State Building to become the city''s tallest structure in April 2012, was topped out that August, and reached its full height of 1,776 feet—a reference to the year the Declaration of Independence was signed—when its spire was completed in May 2013. The building opened on November 3, 2014, and the One World Observatory followed in May 2015. In 2009 the Port Authority confirmed the tower''s official name as One World Trade Center rather than the colloquial Freedom Tower. It has 94 stories, with its top floor numbered 104. The broader rebuilt complex also includes additional office towers along Greenwich Street, the National September 11 Memorial & Museum, and the World Trade Center Transportation Hub.'
WHERE slug = 'one-world-trade-center';

UPDATE poi SET
  summary = 'The Palace Theatre is a historic Broadway theater at 1564 Broadway in the Theater District of Midtown Manhattan. Opened in 1913, it was once the most prestigious vaudeville house in America, and after a dramatic 2020s project that raised the entire theater to build retail below, it remains a Broadway landmark.',
  description = 'The Palace Theatre is a Broadway house at 1564 Broadway, near 47th Street in the Theater District of Midtown Manhattan. Opened in 1913, it became the flagship of the Keith-Albee vaudeville circuit and the most prestigious vaudeville house in the United States, where "playing the Palace" was regarded as the pinnacle of a performer''s career. After vaudeville declined, the Palace was converted to a movie house and later returned to live theater, hosting concerts and Broadway musicals, and its interior is a designated New York City landmark. In an extraordinary engineering project completed in the 2020s, the entire theater was lifted about 30 feet within a new building to create retail and public space beneath it while preserving the historic auditorium, which was restored and reopened for Broadway productions. Seating roughly 1,700, the Palace remains one of Broadway''s storied stages.'
WHERE slug = 'palace-theatre';

UPDATE poi SET
  summary = 'The Park Avenue Armory, also known as the 7th Regiment Armory, is a historic Gothic Revival armory at 643 Park Avenue on the Upper East Side of Manhattan. Completed in 1880 for an elite militia regiment, it is renowned for lavish interiors by designers including Louis Comfort Tiffany and Stanford White and for its vast column-free drill hall. Since 2006 it has been home to the Park Avenue Armory arts organization, which stages large-scale performances and installations.',
  description = 'The Park Avenue Armory, also known as the 7th Regiment Armory, is a historic armory at 643 Park Avenue on the Upper East Side of Manhattan. Designed in the Gothic Revival style by Charles Clinton for the 7th New York Militia Regiment, it was completed in 1880, with two early-20th-century expansions. The building and its interior are New York City designated landmarks, and it is also a National Historic Landmark. Since 2006 it has been home to the Park Avenue Armory Conservancy, which leased the building for 99 years from the state and stages ambitious arts programming, while portions remain occupied by National Guard and veterans'' organizations, a cadet corps, and a neighborhood house. Occupying a full city block between 66th and 67th Streets, the armory comprises a five-story administration building of Philadelphia red brick and granite and a large drill hall to the east. Its interiors were designed in various styles by decorators including Louis Comfort Tiffany, Stanford White, and the Herter Brothers, encompassing halls and stairways and a series of regimental and company rooms. The drill hall, measuring 200 by 300 feet, was one of the city''s largest column-free indoor spaces when built. The Board of Aldermen approved the armory in 1875 but declined to fund it, so the regiment financed construction through donations and a bond issue; work began in 1877 and the armory opened on September 30, 1880. It was substantially expanded from 1909 to 1913.'
WHERE slug = 'park-avenue-armory';

UPDATE poi SET
  summary = 'Pier 17 is a modern waterfront entertainment and dining complex at the South Street Seaport in Lower Manhattan, on the East River. Rebuilt in the late 2010s, it features restaurants, shops, and a rooftop concert venue with views of the Brooklyn Bridge.',
  description = 'Pier 17 is a waterfront entertainment, dining, and retail complex at the South Street Seaport in the historic seaport district of Lower Manhattan, extending into the East River near the Brooklyn Bridge. The current glass-and-steel building, which opened in 2018, replaced an earlier festival marketplace on the pier as part of a major redevelopment of the Seaport. It houses restaurants, shops, and event spaces, and its signature feature is a rooftop that serves as an open-air concert and event venue in warmer months and hosts other programming through the year, all with sweeping views of the river, the Brooklyn Bridge, and the Lower Manhattan skyline. Surrounded by the cobblestone streets and 19th-century buildings of the South Street Seaport Historic District and the adjacent South Street Seaport Museum, Pier 17 anchors the revitalized waterfront as a destination for dining, shopping, and live entertainment on the East River.'
WHERE slug = 'pier-17';

UPDATE poi SET
  summary = 'Pier 35 is a waterfront public space on the East River in the Two Bridges/Lower East Side area of Manhattan, near the Manhattan Bridge. Part of the East River Waterfront Esplanade, it offers an "eco-park" with a sloped lawn, seating, plantings, and river views.',
  description = 'Pier 35 is a public waterfront space on the East River in the Two Bridges neighborhood of Lower Manhattan, near the foot of the Manhattan Bridge along the East River Waterfront Esplanade. Redeveloped as part of the city''s effort to reclaim the Lower Manhattan waterfront for public use, the former shipping pier was transformed into a landscaped "eco-park" that opened in the 2010s. It features a sloped lawn and seating areas, plantings, and a distinctive "mussel beach"—a tidal zone designed to attract shellfish and help improve the health of the river ecosystem—along with benches and railings for taking in views of the water and the bridges. Connecting to the broader esplanade and greenway that runs along the Lower Manhattan shoreline, Pier 35 gives residents of the densely built Two Bridges and Lower East Side neighborhoods access to open riverfront space, blending recreation with ecological restoration on the East River.'
WHERE slug = 'pier-35';

UPDATE poi SET
  summary = 'Pier 57 is a redeveloped pier on the Hudson River at the edge of Chelsea and the Meatpacking District in Manhattan, part of Hudson River Park. Reopened in the 2020s, it houses a public rooftop park, a food hall, offices, and event space.',
  description = 'Pier 57 is a large historic pier on the Hudson River at West 15th Street, on the border of Chelsea and the Meatpacking District, within Hudson River Park on Manhattan''s West Side. Originally built in the 1950s—notable for being constructed on floating concrete caissons—and long used as a bus depot, the pier was extensively redeveloped and reopened to the public in the 2020s as a mixed-use destination. Its centerpiece is a roughly two-acre public rooftop park offering lawns and sweeping views of the Hudson River, the skyline, and the nearby Little Island. Inside, the pier houses a food hall with a variety of vendors, public gathering and event spaces, educational programming, and offices, with Google occupying a large share of the building as office space. Blending public open space, dining, and workplace, Pier 57 is among the newer additions to the West Side waterfront and connects to the surrounding Hudson River Park and greenway.'
WHERE slug = 'pier-57';

UPDATE poi SET
  summary = 'Radio City Music Hall is a landmark Art Deco theater at 1260 Avenue of the Americas within Rockefeller Center in Midtown Manhattan. Opened in 1932 and nicknamed "The Showplace of the Nation," it is the home of the Rockettes. Designed by Edward Durell Stone and Donald Deskey, its 5,960-seat auditorium was the world''s largest when it opened.',
  description = 'Radio City Music Hall is an entertainment venue and theater at 1260 Avenue of the Americas, within Rockefeller Center in Midtown Manhattan. Nicknamed "The Showplace of the Nation," it is the headquarters of the Rockettes and was designed by Edward Durell Stone and Donald Deskey in the Art Deco style. Built on a plot originally intended for a Metropolitan Opera house, it opened on December 27, 1932, as part of Rockefeller Center. Its four-tiered, 5,960-seat auditorium was the world''s largest when it opened. The hall was largely successful until the 1970s, when declining attendance nearly forced it into bankruptcy; it was designated a New York City Landmark in 1978, saved, and extensively renovated in 1999. Though built for stage shows, within a year it was converted into a movie palace and hosted films in a film-and-stage-spectacle format into the 1970s, staging many premieres. Since then it has primarily presented concerts by leading pop and rock musicians and live productions such as the annual Radio City Christmas Spectacular, and it has hosted televised events including the Grammy Awards, Tony Awards, MTV Video Music Awards, and the NFL draft.'
WHERE slug = 'radio-city-music-hall';

UPDATE poi SET
  summary = 'Randall''s Island Park is a large park occupying Randall''s and Wards Islands in the East River, between Manhattan, the Bronx, and Queens. It offers extensive sports fields, waterfront paths, and open space, and is home to major athletic facilities and festival grounds.',
  description = 'Randall''s Island Park is an expansive public park covering most of Randall''s and Wards Islands, joined landmasses in the East River between Upper Manhattan (Harlem), the Bronx, and Queens, beneath the Robert F. Kennedy (Triborough) Bridge. Administratively part of Manhattan, the roughly 480-acre park is one of the city''s largest, and it has been transformed in recent decades from a site of institutional buildings into a major recreational destination. It offers dozens of sports fields for soccer, baseball, softball, and other sports, along with a tennis center, the Icahn Stadium track-and-field arena, waterfront pathways and salt marshes, freshwater wetlands, gardens, and picnic areas. The park is reachable by footbridge from Manhattan at 103rd Street, by car via the RFK Bridge, and seasonally by ferry, and it hosts large events, including music festivals, on its open fields. With sweeping views of the surrounding rivers and skylines, Randall''s Island Park serves athletes, families, and event-goers from across the region and is a key green space in the East River.'
WHERE slug = 'randall-s-island-park';

UPDATE poi SET
  summary = 'The Richard Rodgers Theatre is a Broadway theater at 226 West 46th Street in the Theater District of Midtown Manhattan. Opened in 1925 and named for the composer Richard Rodgers, it seats about 1,300, is operated by the Nederlander Organization, and has been the home of "Hamilton" since 2015.',
  description = 'The Richard Rodgers Theatre is a Broadway house at 226 West 46th Street in the Theater District of Midtown Manhattan. Opened in 1925 as Chanin''s 46th Street Theatre and designed by architect Herbert J. Krapp for developer Irwin Chanin, it introduced a "democratic" seating plan that reduced the traditional divide between orchestra and balcony patrons. Seating roughly 1,300 and operated by the Nederlander Organization, it was renamed in 1990 for the legendary composer Richard Rodgers. Over its history it has hosted a distinguished series of musicals and won numerous Tony Awards for productions staged there, and since 2015 it has been the Broadway home of Lin-Manuel Miranda''s blockbuster "Hamilton." Its well-proportioned auditorium and central Theater District location have long made it a sought-after house, and the Richard Rodgers remains one of Broadway''s marquee venues.'
WHERE slug = 'richard-rodgers-theatre';

UPDATE poi SET
  summary = 'RiseNY is an immersive Times Square attraction that combines a flying-theater ride with museum-style exhibits about New York City''s history and culture. Opened in 2022 at 160 West 45th Street, it was the first flying-theater attraction in the northeastern United States.',
  description = 'RiseNY is a three-part immersive attraction in the heart of Times Square, at 160 West 45th Street, that celebrates New York City''s role as a global cultural capital. Visitors begin in a re-creation of the city''s original City Hall subway station, where they watch a short documentary — narrated by actor Jeff Goldblum and produced by Ric Burns and James Sanders — tracing New York''s rise. They then move through seven themed galleries devoted to the city''s defining industries and art forms: Finance, the Skyline, Film, Fashion, Music, Radio and Television, and Broadway, with interactive displays and memorabilia. The experience culminates in a flying-theater ride that lifts guests about 30 feet in the air and sends them soaring over a film of the city''s landmarks, complete with wind and other 4D effects. Opened in 2022, RiseNY was the first attraction of its kind in the northeastern United States.'
WHERE slug = 'riseny';

UPDATE poi SET
  summary = 'Riverside Park is a scenic waterfront park along the Hudson River on the Upper West Side of Manhattan, stretching for several miles. Designed in part by Frederick Law Olmsted, it offers tree-lined promenades, gardens, monuments, and river views from roughly 72nd to 158th Streets.',
  description = 'Riverside Park is a long, narrow public park running along the Hudson River on the Upper West Side and into Morningside Heights and Harlem in Manhattan, extending roughly from 72nd Street to 158th Street. Laid out beginning in the 1870s, its original design involved Frederick Law Olmsted, the co-designer of Central Park, and later expansions in the 1930s under parks commissioner Robert Moses added waterfront land and covered the rail tracks along the shore. The park''s terraced landscape offers tree-lined promenades, lawns, gardens, playgrounds, sports courts, and a waterfront greenway popular with walkers and cyclists, all with sweeping views across the Hudson to New Jersey. Among its landmarks are Grant''s Tomb, the Soldiers'' and Sailors'' Monument, and the community-planted 91st Street Garden. A designated scenic landmark, Riverside Park is one of the Upper West Side''s defining green spaces and a beloved recreational corridor along the river.'
WHERE slug = 'riverside-park';

UPDATE poi SET
  summary = 'Riverside Park South is the southern extension of Riverside Park, running along the Hudson River waterfront on the Upper West Side of Manhattan below 72nd Street. Built on former rail yards, it offers piers, lawns, and a riverside promenade with open views of the river.',
  description = 'Riverside Park South is a waterfront park along the Hudson River on the Upper West Side of Manhattan, extending Riverside Park southward from around 72nd Street toward 59th Street. It was created in the late 1990s and 2000s on former New York Central Railroad yards as part of a large residential development on the site, designed to reconnect the neighborhood to the river. The park features a riverside esplanade and bikeway—part of the Manhattan Waterfront Greenway—along with lawns, gardens, sports facilities, and a restored pier extending into the water. Remnants of the site''s industrial past, including old rail transfer bridges and pier structures, have been preserved as features within the landscape. Offering open river views and a continuous waterfront path linking to the larger Riverside Park to the north and Hudson River Park to the south, Riverside Park South is a key link in Manhattan''s West Side greenway.'
WHERE slug = 'riverside-park-south';

UPDATE poi SET
  summary = 'Robert F. Wagner Jr. Park is a waterfront park at the southern tip of Battery Park City in Lower Manhattan, overlooking New York Harbor. Known for its gardens, lawns, and views of the Statue of Liberty, it adjoins the Museum of Jewish Heritage.',
  description = 'Robert F. Wagner Jr. Park is a small but celebrated waterfront park at the southern end of Battery Park City in Lower Manhattan, where the Hudson River meets New York Harbor. Named for Robert F. Wagner Jr., a three-term mayor of New York City, the park opened in 1996 and was praised for its sophisticated design, which combined lawns, perennial gardens, brick pavilions, and terraces with sweeping harbor views. From its waterfront promenade visitors can see the Statue of Liberty, Ellis Island, and Governors Island, making it a scenic complement to the nearby Battery. The park adjoins the Museum of Jewish Heritage and connects to the Battery Park City esplanade and the broader Hudson River waterfront. A refined piece of urban landscape design, Wagner Park has long been a favorite spot for taking in the harbor, and portions have been reconstructed as part of Lower Manhattan coastal-resilience efforts.'
WHERE slug = 'robert-f-wagner-jr-park';

UPDATE poi SET
  summary = 'Rockefeller Center is a complex of 19 Art Deco commercial buildings spanning three blocks in Midtown Manhattan, between Fifth and Sixth Avenues. Built by John D. Rockefeller Jr. in the 1930s, it is a National Historic Landmark known for its plaza, seasonal ice rink, and towering Christmas tree.',
  description = 'Rockefeller Center is a complex of 19 commercial buildings covering roughly 22 acres in Midtown Manhattan, between 48th and 51st Streets. Financed by John D. Rockefeller Jr. and built largely between 1931 and 1939 during the Great Depression, it was one of the largest private construction projects of its era and is celebrated as a masterpiece of Art Deco design. At its heart is the sunken Lower Plaza, which hosts an ice-skating rink in winter and is overlooked by the gilded statue of Prometheus and the city''s most famous Christmas tree. The centerpiece skyscraper, 30 Rockefeller Plaza, rises 850 feet and houses the Top of the Rock observation decks and the studios of NBC. The complex also includes Radio City Music Hall, the shop-lined Channel Gardens, and a wealth of public murals and sculpture. Designated a National Historic Landmark in 1987, Rockefeller Center remains a hub of offices, shops, restaurants, and one of New York''s most visited gathering places.'
WHERE slug = 'rockefeller-center';

UPDATE poi SET
  summary = 'Rockefeller Park is a waterfront park at the northern end of Battery Park City in Lower Manhattan, along the Hudson River. Known for its lawns, gardens, playgrounds, and public art, it is a popular family-friendly green space with views across the river.',
  description = 'Rockefeller Park is a public park at the northern end of Battery Park City, the planned neighborhood built on landfill along the Hudson River in Lower Manhattan. Opened in the 1990s as part of Battery Park City''s extensive network of parks and esplanades, it offers broad lawns, gardens, a playground, ball fields, and a riverside promenade, all designed to a high standard as part of the community''s acclaimed public realm. The park is known for its family-friendly amenities and for works of public art, including whimsical bronze sculptures, and it hosts community programs and events. From its greenery and waterfront paths, visitors take in views across the Hudson River to New Jersey and south toward the harbor. Connected to the broader Hudson River waterfront greenway, Rockefeller Park is a well-loved recreational space serving Battery Park City and Lower Manhattan.'
WHERE slug = 'rockefeller-park';

UPDATE poi SET
  summary = 'The Roosevelt Island Tramway is an aerial cable-car line connecting Manhattan to Roosevelt Island over the East River. Offering sweeping skyline views during its short ride, it is one of the few commuter aerial tramways in the United States.',
  description = 'The Roosevelt Island Tramway is an aerial cable-car system that carries passengers across the East River between Manhattan and Roosevelt Island, a narrow island in the river between Manhattan and Queens. Opened in 1976, it was originally intended as a temporary link until subway service reached the island, but it proved so popular that it became a permanent part of the transit system. Its two cabins run on cables suspended from towers, rising alongside the Queensboro (Ed Koch) Bridge and reaching heights that give riders panoramic views of the Midtown Manhattan skyline, the river, and the bridge during the roughly three-to-five-minute crossing. Operated as part of the city''s public transit network, the tram accepts the same fare payment as the subway and buses and serves both commuters and sightseers. Extensively modernized in 2010, the Roosevelt Island Tramway is a beloved and unusual piece of New York infrastructure, offering one of the most scenic short rides in the city.'
WHERE slug = 'roosevelt-island-tramway';

UPDATE poi SET
  summary = 'The Rubin Museum of Art was a museum in the Chelsea neighborhood of Manhattan dedicated to the art and cultures of the Himalayas, the Indian subcontinent, and surrounding regions, with a focus on Tibetan art. Opened in 2004, it closed its physical New York building in 2024 to become a "museum without walls."',
  description = 'The Rubin Museum of Art—also known as the Rubin Museum of Himalayan Art—was dedicated to the collection, display, and preservation of the art and cultures of the Himalayas, the Indian subcontinent, Central Asia, and surrounding regions of Eurasia, with a permanent collection focused particularly on Tibetan art. Founded by the collectors Donald and Shelley Rubin, it opened in 2004 at 150 West 17th Street in the Chelsea neighborhood of Manhattan, in a former department store building whose dramatic spiral staircase became a signature feature. For two decades it was New York''s principal home for Himalayan art, presenting paintings, sculptures, textiles, and ritual objects alongside immersive spaces—such as a re-created Tibetan Buddhist shrine room—and a program of exhibitions, meditation sessions, music, and public events exploring themes of mindfulness and cross-cultural connection. In early 2024 the museum announced that it would close its Chelsea building later that year and reinvent itself as a decentralized, global "museum without walls," lending its collection to partner institutions, mounting traveling exhibitions, and expanding its digital and scholarly programs rather than operating a single physical home.'
WHERE slug = 'rubin-museum-of-art';

UPDATE poi SET
  summary = 'The Shubert Theatre is a Broadway theatre at 225 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1913 and operated by the Shubert Organization, it is one of Broadway''s most storied venues, having hosted the record-setting run of "A Chorus Line."',
  description = 'The Shubert Theatre is a Broadway house at 225 West 44th Street in Midtown''s Theater District, the flagship of the Shubert Organization. It opened in 1913 and was named in memory of Sam S. Shubert, the brother whose early death shaped the founding of the family''s theatrical empire. Designed by architect Henry Beaumont Herts in a refined neo-Renaissance style, the theatre seats roughly 1,400 and shares its block with the private Shubert Alley, long a gathering place for actors and theatergoers. Over more than a century it has premiered and hosted landmark productions, most famously "A Chorus Line," which ran there from 1975 to 1990 and became one of Broadway''s longest-running shows. The building''s interior and facade are designated New York City landmarks, and the Shubert remains one of Broadway''s premier stages for major musicals.'
WHERE slug = 'shubert-theatre';

UPDATE poi SET
  summary = 'The Solomon R. Guggenheim Museum is an art museum at 1071 Fifth Avenue on Manhattan''s Upper East Side, dedicated to modern and contemporary art. It is housed in a landmark spiral building designed by Frank Lloyd Wright, one of the most recognizable works of 20th-century architecture.',
  description = 'The Solomon R. Guggenheim Museum sits on Fifth Avenue along Museum Mile on the Upper East Side, facing Central Park. It grew from the collection of mining magnate Solomon R. Guggenheim, whose foundation opened its first museum in 1939, and it is devoted to modern and contemporary art. The building itself is as celebrated as its holdings: designed by Frank Lloyd Wright and completed in 1959, it takes the form of a widening white spiral, with a continuous ramp winding up around a soaring central atrium so that visitors view art while descending a single gently sloping path. The permanent collection includes major works of Impressionism, Post-Impressionism, and early modernism, with significant holdings of Kandinsky, Picasso, and others. Now a designated New York City landmark and part of a UNESCO World Heritage listing of Wright''s work, the Guggenheim anchors an international network of Guggenheim museums.'
WHERE slug = 'solomon-r-guggenheim-museum';

UPDATE poi SET
  summary = 'SPYSCAPE is an interactive spy museum and experience in Midtown Manhattan, at 928 Eighth Avenue. Visitors explore the history of espionage through real artifacts and hands-on challenges designed with the help of former intelligence officers.',
  description = 'SPYSCAPE is an interactive museum devoted to the world of espionage, located at 928 Eighth Avenue between 54th and 55th Streets in Midtown Manhattan. It pairs genuine artifacts and stories — of double agents, code breakers, and hackers — with immersive, mission-style activities that let visitors test their own aptitude for spycraft. The museum is organized into themed gallery zones such as Encryption, which highlights the analysts who cracked wartime codes. Its centerpiece, developed in collaboration with a former British intelligence (MI6) officer, has guests crack codes, spot hidden surveillance, and take a lie-detection challenge before receiving a personalized "spy profile." A separate SPYGAMES component offers a series of physical and mental challenges inspired by intelligence and special-operations training. A typical visit lasts around 90 minutes to two hours, making it a popular hands-on attraction for families and groups.'
WHERE slug = 'spyscape-spygames';

UPDATE poi SET
  summary = 'The St. James Theatre is a Broadway theater at 246 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1927, it seats about 1,700 and is one of Broadway''s premier houses for large musicals, having premiered classics such as "Oklahoma!" and "The King and I."',
  description = 'The St. James Theatre is a Broadway house at 246 West 44th Street in the Theater District of Midtown Manhattan. Opened in 1927 as Erlanger''s Theatre—built for producer Abraham Erlanger and designed by the firm Warren & Wetmore—it was renamed the St. James in 1932. Seating roughly 1,700, it is one of Broadway''s larger theaters and a favored home for major musicals. Its stage has seen a remarkable roster of premieres and landmark runs, including Rodgers and Hammerstein''s "Oklahoma!" in 1943 and "The King and I" in 1951, along with later hits such as "Hello, Dolly!" and "The Producers." Long operated by Jujamcyn Theaters, it became part of ATG Entertainment when the two merged in 2023. With its size, history, and prime 44th Street location, the St. James remains one of the most prestigious stages on Broadway.'
WHERE slug = 'st-james-theatre';

UPDATE poi SET
  summary = 'St. Nicholas Park is a hilly public park in Harlem, on the west side of Manhattan, running along St. Nicholas Avenue between about 128th and 141st Streets. Set on rocky terrain, it is home to Hamilton Grange and borders the City College campus.',
  description = 'St. Nicholas Park is a public park in the Harlem and Hamilton Heights areas on the west side of Manhattan, extending along St. Nicholas Avenue roughly between 128th and 141st Streets. Set on a steep, rocky ridge of Manhattan schist, the park was designed in the early 20th century to take advantage of its dramatic topography, with winding paths, stairways, lawns, and mature trees climbing the slope. During the American Revolution the high ground here figured in the Battle of Harlem Heights. The park is home to Hamilton Grange National Memorial—the relocated country house of Alexander Hamilton—which sits on a rise within its northern section, and it borders the Gothic campus of the City College of New York. With playgrounds, a dog run, and open space serving the surrounding neighborhoods, St. Nicholas Park is an important green space in Upper Manhattan and a link between local history and everyday recreation.'
WHERE slug = 'st-nicholas-park';

UPDATE poi SET
  summary = 'St. Patrick''s Cathedral is a Gothic Revival Roman Catholic cathedral on Fifth Avenue in Midtown Manhattan, opposite Rockefeller Center. Completed in the 1870s, it is the seat of the Archbishop of New York and the largest Gothic Revival Catholic cathedral in the United States, known for its twin 330-foot spires.',
  description = 'St. Patrick''s Cathedral is a Gothic Revival Roman Catholic cathedral occupying a full block on Fifth Avenue between 50th and 51st Streets in Midtown Manhattan, directly across from Rockefeller Center. Designed by architect James Renwick Jr., it was begun in 1858, interrupted by the Civil War, and opened in 1879, with its landmark twin spires—rising about 330 feet—completed in 1888. The seat of the Archbishop of New York, it is the largest Gothic Revival Catholic cathedral in the United States, seating some 3,000 people. Its exterior is clad in white marble, and the interior features a soaring nave, stained-glass windows crafted in Europe and America, a Lady Chapel added in the early 20th century, and a great pipe organ. A major restoration completed in 2015 cleaned the marble and repaired the structure. A designated New York City landmark and National Historic Landmark, the cathedral is both an active place of worship and one of the most visited churches in the country, drawing millions of visitors a year.'
WHERE slug = 'st-patrick-s-cathedral';

UPDATE poi SET
  summary = 'St. Paul''s Chapel is a historic Episcopal chapel at Broadway and Fulton Street in Lower Manhattan, part of Trinity Church parish. Completed in 1766, it is the oldest surviving church building in Manhattan and famously served as a relief center after the September 11 attacks.',
  description = 'St. Paul''s Chapel is a Georgian-style Episcopal chapel at Broadway and Fulton Street in the Financial District of Lower Manhattan, a chapel of ease of Trinity Church parish. Completed in 1766, it is the oldest surviving church building in Manhattan and one of the city''s few remaining structures from the colonial era. George Washington worshipped here on the day of his 1789 inauguration as president, and his pew is preserved in the chapel. Built of local stone with a later steeple, the chapel and its surrounding churchyard survived the Great Fire of 1776 and, in the 20th century, stood directly across from the World Trade Center. After the September 11, 2001 attacks, though only steps from the collapse, the chapel emerged undamaged and became a round-the-clock relief center where volunteers ministered to recovery workers for months; it later housed a memorial exhibit to that period. A New York City and National Historic Landmark, St. Paul''s Chapel remains an active place of worship and a site of deep historical significance.'
WHERE slug = 'st-paul-s-chapel';

UPDATE poi SET
  summary = 'Saint Thomas Church is an Episcopal parish church on Fifth Avenue at 53rd Street in Midtown Manhattan, known for its French High Gothic architecture and celebrated music program. The present church, completed in 1913, is noted for its elaborately carved stone reredos and its choir of men and boys.',
  description = 'Saint Thomas Church is an Episcopal parish on Fifth Avenue at 53rd Street in Midtown Manhattan, a short walk from Rockefeller Center and the Museum of Modern Art. The present building, the fourth for the parish, was designed by the architects Ralph Adams Cram and Bertram Goodhue in the French High Gothic style and completed in 1913. It is admired for the richness of its stonework, above all the towering carved reredos behind the high altar, populated with dozens of sculpted figures, as well as its stained glass and distinctive asymmetrical single tower. The church is especially renowned for its music: its choir of men and boys, associated with the affiliated Saint Thomas Choir School—one of the few church-affiliated boarding choir schools in the country—maintains a rigorous choral tradition in the English cathedral style. An active Anglo-Catholic congregation, Saint Thomas hosts regular choral services and concerts and stands as a notable work of Gothic Revival architecture on Fifth Avenue.'
WHERE slug = 'st-thomas-church';

UPDATE poi SET
  summary = 'The Whitehall Terminal is the Manhattan hub of the Staten Island Ferry, at the southern tip of Manhattan near the Battery. It is the departure point for the free ferry to Staten Island, famous for its free views of the Statue of Liberty and New York Harbor.',
  description = 'The Staten Island Ferry Whitehall Terminal is the Manhattan terminal of the Staten Island Ferry, at Whitehall Street near the southern tip of Manhattan, beside the Battery. From here the city-operated ferry carries passengers across New York Harbor to the St. George Terminal on Staten Island, a roughly 25-minute trip that is free of charge. The current terminal building, opened in 2005 after a fire destroyed its predecessor, features a large glass waiting hall with panoramic harbor views. The ferry itself is one of New York''s best-known experiences: because it passes close to the Statue of Liberty, Ellis Island, and Governors Island and offers sweeping views of the Lower Manhattan skyline, it is popular with visitors as a free sightseeing trip as well as an essential commuter link carrying tens of thousands of riders a day. The Whitehall Terminal connects directly to the subway and to nearby bus and rail links, making it a major transit gateway between Manhattan and Staten Island.'
WHERE slug = 'staten-island-ferry-whitehall-terminal';

UPDATE poi SET
  summary = 'Statue City Cruises is the official ferry operator carrying visitors from Battery Park in Lower Manhattan to the Statue of Liberty and Ellis Island. Its boats provide the authorized access to Liberty and Ellis Islands in New York Harbor.',
  description = 'Statue City Cruises is the official concessioner operating the ferries that carry visitors from the Battery in Lower Manhattan to Liberty Island—home of the Statue of Liberty—and Ellis Island, the historic immigration station, in New York Harbor. Departing from a dock near Castle Clinton in Battery Park (with additional service from Liberty State Park in New Jersey), it provides the only authorized transportation to the two national monuments. The ferry ride itself offers close-up views of the Statue of Liberty and sweeping panoramas of the Lower Manhattan skyline and the harbor. Tickets include access to the islands, where visitors can explore the grounds and museums, and options range from general admission to pedestal and crown access at the statue. Part of a national operator of sightseeing and ferry services, Statue City Cruises handles the large volume of tourists visiting two of America''s most iconic landmarks, making Battery Park a busy gateway to the harbor''s monuments.'
WHERE slug = 'statue-city-cruises-battery-park';

UPDATE poi SET
  summary = 'The Stephen Sondheim Theatre is a Broadway theater at 124 West 43rd Street in the Theater District of Midtown Manhattan. The modern 1,055-seat house opened in 2009 at the base of the Bank of America Tower, behind the preserved landmark facade of the original 1918 Henry Miller''s Theatre. Owned by the Durst Organization and managed by the Roundabout Theatre Company, it was renamed for composer Stephen Sondheim in 2010.',
  description = 'The Stephen Sondheim Theatre, formerly Henry Miller''s Theatre, is a Broadway theater at 124 West 43rd Street in the Theater District of Midtown Manhattan. Owned by the Durst Organization and managed by the Roundabout Theatre Company, the modern 1,055-seat theater opened in 2009 at the base of the Bank of America Tower and is mostly underground, designed by COOKFOX with Adamson Associates as architect of record. It retains the landmarked neoclassical facade of the original Henry Miller''s Theatre, a 950-seat house built in 1918 by the actor-producer Henry Miller and designed by Harry Creighton Ingalls. After Miller''s death in 1926, his son Gilbert ran it; the family sold it in 1966 to the Nederlander Organization and then to Seymour Durst in 1968. The original theater''s final musical closed in 1969, after which it served as a pornographic cinema in the 1970s, the Xenon discotheque from 1978 to 1984, and various nightclubs into the 1990s. It reopened as a Broadway house in 1998 for a Roundabout revival of Cabaret staged as the "Kit Kat Klub," and later hosted Urinetown from 2001 to 2004. The old auditorium was then demolished and the modern theater opened in 2009, taking Sondheim''s name on his 80th birthday in 2010.'
WHERE slug = 'stephen-sondheim-theatre';

UPDATE poi SET
  summary = 'The Stonewall Inn is a gay bar at 53 Christopher Street in the Greenwich Village neighborhood of Lower Manhattan. It was the site of the 1969 Stonewall riots, which catalyzed the gay liberation movement and the modern fight for LGBTQ rights in the United States.',
  description = 'The Stonewall Inn is a gay bar and tavern at 53 Christopher Street in the Greenwich Village neighborhood of Lower Manhattan. It was the site of the 1969 Stonewall riots, which led to the gay liberation movement and the modern fight for LGBTQ rights in the United States. When the riots occurred, Stonewall was one of the relatively few gay bars in New York City, occupying two structures that had been built as horse stables in the 1840s. The original establishment opened in 1930 as a speakeasy and moved to Christopher Street in 1934, operating as a restaurant until 1966. In early 1967, figures associated with the Genovese crime family reopened it as a gay bar, and it became a popular hangout, especially for young people and those on the fringes of the community. Unable to obtain a liquor license, Stonewall ran as a private club, and police raided it frequently despite bribes from its owners; the riots of June 28 to July 3, 1969, followed one such raid. The bar closed soon after and the buildings passed through many tenants. A new bar opened at number 53 in 1990 and eventually took the Stonewall name, reopening under new owners in 2007, while the adjacent building at 51 Christopher Street became a visitor center for the Stonewall National Monument in the 2020s. Long a symbol of the LGBTQ community, the Stonewall Inn in 2016 became the first LGBTQ site designated a U.S. National Historic Landmark.'
WHERE slug = 'stonewall-inn';

UPDATE poi SET
  summary = 'Summit One Vanderbilt is an immersive observation experience occupying the top floors of One Vanderbilt, a supertall skyscraper beside Grand Central Terminal in Midtown Manhattan. Opened in 2021, it combines panoramic views more than 1,000 feet up with mirrored art installations, glass ledges, and light effects.',
  description = 'Summit One Vanderbilt is an observation attraction at the top of One Vanderbilt, one of New York''s newest supertall skyscrapers, adjacent to Grand Central Terminal in Midtown Manhattan. Opened in October 2021, it occupies the tower''s top four floors and reimagines the traditional observation deck as a multi-sensory art-and-technology experience. Its mirrored galleries multiply the skyline and visitors'' own reflections into a disorienting, immersive environment, and installations include a room filled with reflective silver balloons and works by contemporary artists. Outdoor and glass-floored areas—among them two transparent "Levitation" ledges suspended roughly 1,000 feet above Madison Avenue—offer dramatic views of Manhattan. An optional glass-walled exterior elevator, "Ascent," climbs several stories up the side of the building for an even higher vantage. The blend of panoramic views and immersive design has made Summit one of the city''s most popular recent attractions.'
WHERE slug = 'summit-one-vanderbilt';

UPDATE poi SET
  summary = 'The Basilica of St. Patrick''s Old Cathedral is a historic Roman Catholic church at Mott and Prince Streets in the Nolita/Little Italy area of Lower Manhattan. Completed in 1815, it was the original seat of the Archdiocese of New York before the current St. Patrick''s Cathedral opened uptown.',
  description = 'The Basilica of St. Patrick''s Old Cathedral is a historic Roman Catholic church at 263 Mulberry Street, at the corner of Mott and Prince Streets, on the border of Nolita and Little Italy in Lower Manhattan. Built between 1809 and 1815 and designed in the Gothic Revival style, it was the original St. Patrick''s Cathedral and served as the seat of the Roman Catholic Archdiocese of New York until the much larger cathedral of the same name opened on Fifth Avenue in 1879; after a fire, the old cathedral was rebuilt in the 1860s. As one of the oldest Catholic churches in the city, it played a central role in the life of generations of immigrant New Yorkers, and its brick-walled churchyard and surrounding walls figure in local history. The church was elevated to the status of a basilica by the Vatican in 2010. A designated New York City landmark, it remains an active parish, has appeared in films, and offers tours of the historic catacombs beneath the building.'
WHERE slug = 'the-basilica-of-st-patrick-s-old-cathedral';

UPDATE poi SET
  summary = 'The Battery, also known as Battery Park, is a 25-acre public park at the southern tip of Manhattan, overlooking New York Harbor. It is the departure point for ferries to the Statue of Liberty and Ellis Island and contains the historic Castle Clinton.',
  description = 'The Battery, historically Battery Park, is a public park of about 25 acres at the southern tip of Manhattan, facing New York Harbor where the Hudson and East Rivers meet. Its name derives from the artillery batteries that once stood along the shoreline to defend the young city. Today the park is a landscaped waterfront green space with promenades, gardens, monuments, and sweeping views of the harbor, the Statue of Liberty, Ellis Island, and Governors Island. It is the mainland embarkation point for ferries to the Statue of Liberty and Ellis Island, and it contains Castle Clinton, a circular sandstone fort from the early 19th century that now serves as the ferries'' ticket office and a national monument. The park also holds numerous memorials, along with the SeaGlass Carousel and monuments to immigrants and to those lost at sea. A redesigned perennial garden by landscape designer Piet Oudolf and other improvements have enhanced the grounds. As one of the oldest public open spaces in the city, the Battery is a gateway between Lower Manhattan and the harbor.'
WHERE slug = 'the-battery';

UPDATE poi SET
  summary = 'The Dakota is a landmark cooperative apartment building at 1 West 72nd Street on the Upper West Side of Manhattan, overlooking Central Park. Built between 1880 and 1884 in the German Renaissance style by Henry Janeway Hardenbergh, it is the oldest surviving luxury apartment building in New York City. A National Historic Landmark, it has been home to many artists and musicians, including John Lennon, who was murdered outside it in 1980.',
  description = 'The Dakota is a cooperative apartment building at 1 West 72nd Street on the Upper West Side of Manhattan, on the western side of Central Park West between 72nd and 73rd Streets. Constructed between 1880 and 1884 in the German Renaissance style and designed by Henry Janeway Hardenbergh for businessman Edward Cabot Clark, it was one of the first large developments on the Upper West Side and is the oldest remaining luxury apartment building in the city. A National Historic Landmark and a New York City designated landmark, it is also part of the Central Park West Historic District. The building is roughly square, built around a central H-shaped courtyard through which all apartments are reached; its brick facade features sandstone and terracotta trim, deep roofs with dormers, balconies, and balustrades, and each apartment originally had a unique layout of four to twenty rooms. Work began in 1880, and though Clark died before its completion in 1884, the Dakota was fully rented on opening. The Clark family managed it for eight decades until residents bought the building and converted it to a housing cooperative in 1961. It has long been home to artists, actors, and musicians, most famously John Lennon, who was killed outside the building on December 8, 1980.'
WHERE slug = 'the-dakota';

UPDATE poi SET
  summary = 'The Frick Collection is an art museum on Fifth Avenue at 70th Street on Manhattan''s Upper East Side, housed in the former Gilded Age mansion of industrialist Henry Clay Frick. It is renowned for its intimate display of Old Master paintings, sculpture, and decorative arts within a preserved domestic setting.',
  description = 'The Frick Collection is an art museum at 1 East 70th Street, on Fifth Avenue facing Central Park on Manhattan''s Upper East Side. It is housed in the former residence of the industrialist and art collector Henry Clay Frick, a Beaux-Arts mansion completed in 1914 and designed by Thomas Hastings of Carrère and Hastings. Following the deaths of Frick and his wife, the house and its collection were converted into a public museum, which opened in 1935. The collection is celebrated for its concentration of European Old Master paintings—including works by Bellini, Vermeer, Rembrandt, Velázquez, and Goya—displayed alongside sculpture, French furniture, porcelain, and enamels within the mansion''s preserved rooms rather than conventional galleries. The tranquil garden court and period interiors are central to its distinctive character. The museum also maintains the Frick Art Reference Library, a major resource for art-historical research. After a multi-year renovation and expansion, the Frick reopened in its enlarged home in 2025, adding gallery and program space while preserving the intimacy for which it is known.'
WHERE slug = 'the-frick-collection';

UPDATE poi SET
  summary = 'The FRIENDS Experience: The One in New York City is an immersive, interactive exhibition celebrating the hit television sitcom "Friends," located at 130 East 23rd Street in the Gramercy neighborhood of Manhattan. It features recreated sets, authentic costumes and props, and photo opportunities across two floors.',
  description = 'The FRIENDS Experience: The One in New York City is an immersive exhibition dedicated to the popular television sitcom "Friends," located at 130 East 23rd Street in the Gramercy neighborhood of Manhattan. Beginning as a pop-up before finding a permanent home—the New York location opened in 2021—it is billed as the biggest permanent celebration of the show. Across two floors, visitors walk through faithful recreations of the series'' iconic sets, including Monica''s apartment and living room, the Central Perk coffee house, and the Las Vegas wedding chapel, and can pose with props such as the orange sofa and the frame on the peephole door. The experience also displays authentic costumes and props used during filming, alongside trivia, interactive moments, and photo opportunities designed for fans. Part nostalgia trip and part interactive attraction, it is one of a number of TV- and film-themed immersive experiences that have opened in Manhattan, drawing fans of the enduringly popular show.'
WHERE slug = 'the-friends-experience-the-one-in-new-york-city';

UPDATE poi SET
  summary = 'The High Line is a 1.45-mile elevated linear park built on a former New York Central Railroad freight spur on Manhattan''s West Side. Running from the Meatpacking District through Chelsea to the Hudson Yards area, it was created by the nonprofit Friends of the High Line and designed by James Corner Field Operations, Diller Scofidio + Renfro, and planting designer Piet Oudolf. Opened in phases from 2009, it has become an icon of contemporary landscape architecture.',
  description = 'The High Line is a 1.45-mile-long elevated linear park, greenway, and rail trail created on a former New York Central Railroad spur on the West Side of Manhattan. Running from Gansevoort Street in the Meatpacking District, through Chelsea, to the West Side Yard near 34th Street, it was designed as a "living system" blending landscape architecture, urban design, and ecology by James Corner Field Operations, Diller Scofidio + Renfro, and planting designer Piet Oudolf; it was inspired by the Coulée verte, an elevated park in Paris. The viaduct it sits on was part of the West Side Line and was effectively abandoned by 1980 as rail traffic declined, with portions later demolished. In 1999 Joshua David and Robert Hammond founded the nonprofit Friends of the High Line to preserve the structure as public open space, and after the Bloomberg administration backed the plan in 2003, conversion began in 2006. The park opened in phases in 2009, 2011, and 2014, with the Spur added in 2019 and the Moynihan Connector, linking east to Moynihan Train Hall, in 2023. Since opening, the High Line has become an icon of American contemporary landscape architecture, drawing millions of visitors, spurring real-estate development nearby, and inspiring cities across the country to repurpose obsolete infrastructure as public space.'
WHERE slug = 'the-high-line';

UPDATE poi SET
  summary = 'The Jewish Museum is an art museum at 1109 Fifth Avenue, in the former Felix M. Warburg House along Museum Mile on Manhattan''s Upper East Side. Its collection of about 30,000 objects—religious artifacts, fine art, and media—makes it one of the largest museums of Jewish culture in the world. It stages exhibitions centered on Jewish heritage while appealing to broad audiences.',
  description = 'The Jewish Museum is an art museum at 1109 Fifth Avenue, housed in the Felix M. Warburg House along Museum Mile on the Upper East Side of Manhattan. Its collection of about 30,000 objects—including religious artifacts, fine art, and media—makes it one of the largest museums devoted to Jewish culture in the world, and it is known for exhibitions that center Jewish heritage and viewpoints while appealing to broad audiences. The museum originated in 1904 with Judge Mayer Sulzberger''s gift of ceremonial objects to the Jewish Theological Seminary. It was established in the Warburg family mansion, donated in 1944 by Frieda Warburg, and opened to the public in 1947; the châteauesque building, designed by C. P. H. Gilbert, was later expanded. A 1993 renovation by Kevin Roche added exhibition and education space while preserving the building''s character. Over its history the museum has made notable contributions to the study of modern and contemporary art, hosting early solo exhibitions of artists such as Helen Frankenthaler and Robert Rauschenberg, and the influential 1966 exhibition "Primary Structures," which helped launch Minimalist sculpture. It also launched the New York Jewish Film Festival in 1992.'
WHERE slug = 'the-jewish-museum';

UPDATE poi SET
  summary = 'The Mall is a grand, tree-lined promenade in Central Park, the only intentionally straight path in the park''s otherwise winding design. Its quarter-mile stretch beneath a canopy of American elms leads to Bethesda Terrace and is lined with statues along Literary Walk.',
  description = 'The Mall is a broad, formal promenade near the southern end of Central Park, running roughly from 66th to 72nd Streets. It is the only major straight, axial path in a park otherwise defined by curving, naturalistic routes, and it was designed by Frederick Law Olmsted and Calvert Vaux as a grand pedestrian esplanade drawing the eye toward Bethesda Terrace and the Lake beyond. The Mall is famous for its arching canopy of American elms—one of the largest remaining stands of the species in North America—whose branches meet overhead to form a cathedral-like tunnel of green. Its southern portion, known as Literary Walk, is lined with statues of writers including William Shakespeare, Robert Burns, and Sir Walter Scott. A gathering place since the park''s earliest days, the Mall has long hosted strollers, performers, and events, and its stately tree-lined allée is among the most recognizable and beloved landscapes in Central Park.'
WHERE slug = 'the-mall-central-park';

UPDATE poi SET
  summary = 'The Met Cloisters is a museum in Fort Tryon Park in Upper Manhattan, specializing in the medieval art and architecture of Romanesque and Gothic Europe. Governed by the Metropolitan Museum of Art, it displays its collection within architectural settings reconstructed from French monasteries and abbeys.',
  description = 'The Cloisters, also known as the Met Cloisters, is a museum in Fort Tryon Park, straddling the Washington Heights and Inwood neighborhoods of Upper Manhattan. It specializes in European medieval art and architecture, with a focus on the Romanesque and Gothic periods. Governed by the Metropolitan Museum of Art, it contains a large collection of medieval artworks shown in the architectural settings of French monasteries and abbeys. Its buildings center on four cloisters — the Cuxa, Saint-Guilhem, Bonnefont, and Trie-sur-Baïse — acquired by the American sculptor George Grey Barnard in France before 1913 and moved to New York. Barnard''s collection was purchased for the museum by financier John D. Rockefeller Jr., with other major objects coming from the collections of J. P. Morgan and Joseph Brummer. Designed by architect Charles Collens on a steep hilltop site, the building contains medieval gardens and a series of chapels and themed galleries — including the Romanesque, Fuentidueña, Unicorn, Spanish, and Gothic rooms — all intended to evoke medieval European monastic life. It holds about 5,000 works of European art and architecture, mostly dating from the 12th through 15th centuries, including stone and wood sculptures, tapestries, illuminated manuscripts, and panel paintings. Its best-known works are the c. 1422 Mérode Altarpiece and the c. 1495–1505 Unicorn Tapestries. Rockefeller purchased the site in 1930 and donated it to the Metropolitan in 1931; the Cloisters opened on May 10, 1938.'
WHERE slug = 'the-met-cloisters';

UPDATE poi SET
  summary = 'The Metropolitan Museum of Art, known as the Met, is an encyclopedic art museum on Fifth Avenue along Museum Mile on Manhattan''s Upper East Side. The largest art museum in the Americas, it holds a permanent collection of around 1.5 million works spanning ancient to contemporary art across 17 curatorial departments. It is the most-visited museum in the United States.',
  description = 'The Metropolitan Museum of Art, colloquially the Met, is an encyclopedic art museum in New York City and the largest art museum in the Americas. By floor area it is among the world''s largest museums, and with more than 5.7 million visitors in fiscal 2025 it was the most-visited museum in the United States. Founded in 1870 by a group of philanthropists, artists, and businessmen who sought to create a national institution to educate the public, it opened its main building at 1000 Fifth Avenue, on the eastern edge of Central Park, in 1880. Its permanent collection of about 1.5 million works is divided into 17 curatorial departments and ranges from the ancient Near East and Egypt through classical antiquity to the present. Holdings include paintings and sculpture by European Old Masters; extensive American, modern, and contemporary art; and major collections of African, Asian, Oceanian, Byzantine, and Islamic art, along with musical instruments, costumes, arms and armor, and decorative arts. Several period interiors, from 1st-century Rome to modern American design, are installed within its galleries. The museum operates a second location, The Cloisters in Fort Tryon Park, devoted to medieval European art, and is set to absorb the nearby Neue Galerie as a third site in 2028.'
WHERE slug = 'the-metropolitan-museum-of-art';

UPDATE poi SET
  summary = 'The Morgan Library & Museum is a museum and research library at 225 Madison Avenue in the Murray Hill neighborhood of Manhattan. Completed in 1906 as the private library of banker J. P. Morgan, it opened to the public in 1924. Its collection of more than 350,000 objects includes illuminated and literary manuscripts, rare books, drawings, and music.',
  description = 'The Morgan Library & Museum, formerly the Pierpont Morgan Library, is a museum and research library at 225 Madison Avenue in Manhattan''s Murray Hill neighborhood. It was completed in 1906 as the private library of the banker J. P. Morgan, who erected the main building between 1902 and 1906 to house thousands of objects he had collected; Belle da Costa Greene served as its first librarian for more than four decades. In accordance with Morgan''s will, his son made the library a public institution in 1924, and expansions followed in 1928, 1962, 1991, and 2006, when it was renamed the Morgan Library & Museum. The complex comprises several structures, including the original McKim, Mead & White building, a 19th-century Italianate brownstone, and a glass entrance pavilion designed by Renzo Piano. The main building and its interior are a New York City and National Historic Landmark. The Morgan''s collection of more than 350,000 objects includes illuminated manuscripts, authors'' original manuscripts, rare books, and sheet music, along with drawings, photographs, paintings, and maps. Beyond its permanent holdings, it hosts temporary exhibitions, concerts, and lectures, and both its collection and its original architecture have long been praised.'
WHERE slug = 'the-morgan-library-museum';

UPDATE poi SET
  summary = 'The Museum Store at 44 West 53rd Street is the MoMA Design Store''s Midtown location, directly across from the Museum of Modern Art. It offers a curated selection of modern design objects—home goods, lighting, tech, jewelry, and accessories—many inspired by or drawn from MoMA''s collection.',
  description = 'The Museum Store on West 53rd Street is the Midtown flagship of the MoMA Design Store, at 44 West 53rd Street between Fifth and Sixth Avenues, directly across from the Museum of Modern Art. It offers a carefully curated selection of modern and contemporary design products—furniture and home décor, lighting, tabletop and kitchen items, tech accessories, jewelry, books, and gifts—with many products exclusive to the store or inspired by works in MoMA''s collection. Long regarded as a destination for design lovers seeking well-made, thoughtfully chosen objects, the store extends the museum''s celebration of modern design into everyday products. As part of MoMA''s major expansion and renovation, the 53rd Street store was reconfigured into a new setting near the museum. Purchases support the Museum of Modern Art''s exhibitions, education programs, and the care of its collection. Together with MoMA''s other locations, including a SoHo branch, the Design Store is a well-known stop for visitors looking to bring home a piece of the modern design sensibility for which the museum is famous.'
WHERE slug = 'the-museum-store';

UPDATE poi SET
  summary = 'The Plaza is a landmark luxury hotel at the southeast corner of Central Park, facing Grand Army Plaza on Fifth Avenue in Midtown Manhattan. Opened in 1907 in a French Renaissance–style building, it is one of New York''s most famous hotels, long associated with high society and popular culture.',
  description = 'The Plaza Hotel is a historic luxury hotel occupying the block at Fifth Avenue and Central Park South, overlooking Grand Army Plaza and the southeast corner of Central Park. Designed by Henry Janeway Hardenbergh in a French Renaissance château style and opened in 1907, the 20-story building is a New York City and National Historic Landmark. Over more than a century it has hosted royalty, presidents, and celebrities, and its opulent public rooms—including the Palm Court, the Oak Room, and the Grand Ballroom—have made it a fixture of the city''s social life. The Plaza has featured prominently in literature and film, from F. Scott Fitzgerald''s "The Great Gatsby" to the "Home Alone" and "Eloise" stories, the latter set in the hotel. In 2008 it was extensively renovated and partly converted to private condominium residences while retaining hotel rooms and its landmark interiors. It remains one of the most recognizable hotels in the world and a landmark at the gateway to Central Park.'
WHERE slug = 'the-plaza-hotel';

UPDATE poi SET
  summary = 'The Pond is a tranquil body of water at the southeastern corner of Central Park, near Grand Army Plaza and Fifth Avenue. Framed by willows and overlooked by the Gapstow Bridge, it is one of the first landscapes visitors encounter entering the park from Midtown.',
  description = 'The Pond is a small, naturalistic lake in the southeastern corner of Central Park, just inside the park near Grand Army Plaza at Fifth Avenue and 59th Street. One of several water bodies created when the park was built in the 19th century, it was shaped by designers Frederick Law Olmsted and Calvert Vaux to appear as a natural, meandering pond, with irregular shorelines planted with willows and other trees. At its northern end, the graceful stone Gapstow Bridge crosses a narrow neck of the water, framing a classic view of the Midtown skyline—including the towers along Central Park South—rising above the trees. The adjacent Hallett Nature Sanctuary, a wooded promontory, borders the Pond and provides habitat for birds and other wildlife. Because it lies at a busy southern entrance, the Pond is often a visitor''s first glimpse of the park''s landscape, offering a sudden sense of calm at the edge of Midtown Manhattan.'
WHERE slug = 'the-pond-central-park';

UPDATE poi SET
  summary = 'The Ramble is a 36-acre woodland in the heart of Central Park, laid out as a wild, naturalistic garden of winding paths, rock outcrops, and dense plantings. A renowned spot for birdwatching, it offers a secluded contrast to the park''s open lawns.',
  description = 'The Ramble is a densely wooded, roughly 36-acre section near the center of Central Park, between the Lake to the south and the larger open areas to the north, about between 73rd and 79th Streets. Conceived by the park''s designers, Frederick Law Olmsted and Calvert Vaux, as a "wild garden," it was deliberately planted and sculpted to feel like untamed forest, with winding, intersecting footpaths, streams, rustic bridges, and rocky outcrops of Manhattan schist. Its layered canopy and varied habitats make it one of the best birdwatching locations in the northeastern United States, drawing birders especially during the spring and fall migrations, when many species pass through. The maze-like paths and secluded glades offer a sense of solitude and discovery unusual in the middle of the city. Long a beloved retreat for nature lovers, the Ramble has been the focus of restoration efforts by the Central Park Conservancy to protect its woodland character and manage erosion.'
WHERE slug = 'the-ramble-central-park';

UPDATE poi SET
  summary = 'The Riverside Church is a large interdenominational church in the Morningside Heights neighborhood of Upper Manhattan, overlooking the Hudson River. Completed in 1930 with support from John D. Rockefeller Jr., its Gothic Revival tower is among the tallest church structures in the United States, and it is known for its history of social activism.',
  description = 'The Riverside Church is an interdenominational Christian church at 490 Riverside Drive in Morningside Heights, near Columbia University and Grant''s Tomb in Upper Manhattan. Built between 1927 and 1930 with major funding from John D. Rockefeller Jr., it was designed in the Gothic Revival style, modeled in part on Chartres Cathedral, and its slender bell tower rises about 392 feet, making it one of the tallest church buildings in the United States; the tower houses a large carillon, among the biggest in the world. Affiliated historically with the American Baptist Churches and the United Church of Christ, Riverside has long been a center of progressive social and political engagement: it was a platform for civil-rights leaders and the site of major addresses, including Martin Luther King Jr.''s 1967 speech against the Vietnam War. Beyond worship, the church hosts concerts, lectures, and community programs. Its soaring nave, stained glass, and observation-level tower make it both an architectural landmark and an active congregation in Upper Manhattan.'
WHERE slug = 'the-riverside-church';

UPDATE poi SET
  summary = 'The Skyscraper Museum is a museum in Battery Park City, Lower Manhattan, dedicated to the study of high-rise buildings and the history of New York''s skyline. It explores skyscrapers as feats of engineering, design, and urban development.',
  description = 'The Skyscraper Museum is a small museum in Battery Park City at the southern tip of Manhattan, devoted to the study of tall buildings—their design, construction, technology, and role in shaping cities. Founded in 1996 and settled into its permanent home at 39 Battery Place in 2004, it examines skyscrapers as products of engineering and architecture as well as of real estate, ambition, and urban growth, with a special focus on New York City''s evolving skyline. Its compact, reflective gallery space—clad in polished stainless steel to evoke a sense of towering height—hosts changing exhibitions on individual buildings, architects, and themes such as supertall towers, historic skyscrapers, and the world''s rising cities. The museum also offers lectures, programs, and online resources. Situated near the World Trade Center and the harbor, the Skyscraper Museum offers an intimate look at the vertical city and the forces that built the modern Manhattan skyline.'
WHERE slug = 'the-skyscraper-museum';

UPDATE poi SET
  summary = 'The Woolworth Building is a landmark early skyscraper at 233 Broadway in Lower Manhattan, completed in 1913 as the headquarters of the F. W. Woolworth retail empire. A Gothic Revival "Cathedral of Commerce," it was the tallest building in the world until 1930.',
  description = 'The Woolworth Building is a 60-story, 792-foot skyscraper at 233 Broadway, opposite City Hall Park in Lower Manhattan. Designed by architect Cass Gilbert and completed in 1913 as the corporate headquarters of Frank W. Woolworth''s five-and-dime retail chain, it was the tallest building in the world at its opening and held that title until the Chrysler Building surpassed it in 1930. Its terracotta-clad Gothic Revival design—with pointed arches, flying buttresses, gargoyles, and a soaring tower—earned it the nickname the "Cathedral of Commerce," and Woolworth famously paid for the building in cash. The lavishly decorated lobby, with marble, mosaics, and whimsical carvings that include caricatures of Woolworth and Gilbert, is one of the finest of its era, though it is not generally open to the public. A designated New York City landmark and National Historic Landmark, the building remains a defining feature of the Lower Manhattan skyline; its upper floors were converted to luxury residences in the 2010s while the lower floors continue as offices.'
WHERE slug = 'the-woolworth-building';

UPDATE poi SET
  summary = 'Theodore Roosevelt Park is a green space on the Upper West Side of Manhattan surrounding the American Museum of Natural History, between 77th and 81st Streets. Named for the president and conservationist, it offers lawns, trees, and a dog run across from Central Park.',
  description = 'Theodore Roosevelt Park is a public park on the Upper West Side of Manhattan that surrounds the American Museum of Natural History, occupying the blocks between Central Park West and Columbus Avenue and 77th and 81st Streets. Named in honor of Theodore Roosevelt—the 26th U.S. president, a noted naturalist and conservationist, and a New York native memorialized at the adjacent museum—the park frames the museum''s grand buildings with lawns, mature trees, benches, and planted areas. It includes a popular dog run and green space used by neighborhood residents, and it sits directly across Central Park West from Central Park itself. Though modest in size compared with the city''s major parks, Theodore Roosevelt Park provides a leafy setting for one of New York''s premier cultural institutions and a pleasant pocket of greenery on the Upper West Side.'
WHERE slug = 'theodore-roosevelt-park';

UPDATE poi SET
  summary = 'Tiffany & Co.''s Fifth Avenue flagship is the landmark New York store of the celebrated luxury jeweler, at the corner of Fifth Avenue and 57th Street in Midtown Manhattan. Open at this location since 1940, it is famous for its diamonds, its signature robin''s-egg blue, and its role in "Breakfast at Tiffany''s."',
  description = 'The Tiffany & Co. Fifth Avenue flagship is the principal New York store of the luxury jeweler Tiffany & Co., at 727 Fifth Avenue on the corner of 57th Street in Midtown Manhattan. Tiffany, founded in New York in 1837, moved to this purpose-built limestone store in 1940, and it has served ever since as the company''s flagship and a symbol of American luxury. The store is renowned for fine jewelry, diamonds, silver, and watches, and for the brand''s trademark "Tiffany Blue," the robin''s-egg color of its boxes and bags. It gained lasting fame from Truman Capote''s novella and the 1961 film "Breakfast at Tiffany''s," whose opening scene shows Audrey Hepburn gazing into its windows. Above the entrance, the store is marked by the "Atlas" clock, a nine-foot statue of the Greek titan bearing a timepiece that has watched over Fifth Avenue since the 19th century. Following a major multi-year renovation, the flagship reopened in 2023 as "The Landmark," with expanded retail, exhibition, and dining space.'
WHERE slug = 'tiffany-co-fifth-avenue';

UPDATE poi SET
  summary = 'Times Square is one of the world''s busiest pedestrian intersections and entertainment hubs, formed by the junction of Broadway, Seventh Avenue, and 42nd Street in Midtown Manhattan. The bowtie-shaped plaza, the physical hub of the Broadway Theater District, is famous for its dense cluster of illuminated digital billboards and its annual New Year''s Eve ball drop.',
  description = 'Times Square is one of the world''s busiest pedestrian intersections, tourist destinations, and entertainment hubs, formed by the junction of Broadway, Seventh Avenue, and 42nd Street in Midtown Manhattan. Together with adjacent Duffy Square, it is a bowtie-shaped plaza running five blocks between 42nd and 47th Streets. As a center of the world''s entertainment industry and the physical hub of the Theater District, where most Broadway theaters are located, it is brightly illuminated by countless digital billboards and lined with businesses offering round-the-clock service. It is one of the world''s most-visited attractions, drawing an estimated 50 million visitors a year, with roughly 330,000 people passing through daily and far more on its busiest days; the adjacent subway stations are consistently the busiest in the city. Formerly called Longacre Square, it was renamed in 1904 after The New York Times moved its headquarters to the newly built Times Building, now One Times Square. That building is the site of the annual New Year''s Eve ball drop, which began on December 31, 1907, and still draws over a million people in person and a worldwide audience of a billion or more. The intersection of Broadway and 42nd Street is the eastern terminus of the Lincoln Highway, the first road across the United States for automobiles. Times Square is sometimes called "the Crossroads of the World" and "the heart of the Great White Way."'
WHERE slug = 'times-square';

UPDATE poi SET
  summary = 'Times Square Church is a large nondenominational Pentecostal congregation in the Theater District of Midtown Manhattan, housed in the former Mark Hellinger Theatre at 237 West 51st Street. Founded by pastor David Wilkerson in 1987, it worships in a landmark former Broadway house.',
  description = 'Times Square Church is a large, nondenominational evangelical and Pentecostal congregation in the Theater District of Midtown Manhattan, worshipping in the former Mark Hellinger Theatre at 237 West 51st Street. It was founded in 1987 by David Wilkerson, the pastor and author known for his ministry among gang members and addicts and for the book "The Cross and the Switchblade." The congregation purchased the Mark Hellinger Theatre—a lavish 1930 Broadway house once home to musicals such as "My Fair Lady"—in 1991, preserving the ornate, gilded auditorium as its sanctuary. Drawing a large and notably diverse, international membership from across the New York region, the church holds multiple weekly services and is known for its music and its outreach ministries. Housed within one of the grand old theaters of Broadway, Times Square Church is an unusual example of a historic entertainment venue repurposed as a place of worship, and it remains an active and prominent congregation in the heart of the Theater District.'
WHERE slug = 'times-square-church';

UPDATE poi SET
  summary = 'Top of the Rock is an observation deck atop 30 Rockefeller Plaza in Midtown Manhattan, spread across the upper floors of the Art Deco skyscraper at the heart of Rockefeller Center. Reopened in its modern form in 2005, it is prized for its head-on views of the Empire State Building and Central Park.',
  description = 'Top of the Rock is an observation deck at the summit of 30 Rockefeller Plaza, the centerpiece skyscraper of Rockefeller Center in Midtown Manhattan. Occupying the building''s upper floors (67th through 70th), roughly 850 feet above the street, it offers sweeping open-air and glass-enclosed views in every direction. The deck first opened to the public in 1933 but closed in the 1980s; it was extensively renovated and reopened in 2005. Its northern outlook takes in Central Park stretching into the distance, while the southern view is dominated by the Empire State Building and the Midtown skyline—vantages that have made it one of the city''s most popular observation experiences and a favorite for photographers. The multi-level design, with tiered outdoor terraces and clear glass safety panels, was intended to give unobstructed sightlines, and its position between Midtown and Central Park offers a perspective the taller Downtown decks cannot match.'
WHERE slug = 'top-of-the-rock-observation-deck';

UPDATE poi SET
  summary = 'Trinity Church is a historic Episcopal parish church at 89 Broadway, opposite Wall Street in the Financial District of Lower Manhattan. The current Gothic Revival building, designed by Richard Upjohn and completed in 1846, was the tallest structure in the United States until 1869. Known for its history, architecture, and large endowment, the parish also maintains St. Paul''s Chapel nearby.',
  description = 'Trinity Church is a historic parish in the Episcopal Diocese of New York, located at 89 Broadway opposite Wall Street in the Financial District of Lower Manhattan. Known for its centuries of history, prominent location, distinguished architecture, and substantial endowment, the "high church" congregation follows the traditions of the Episcopal Church and the worldwide Anglican Communion. The parish maintains two chapels—St. Paul''s Chapel in Lower Manhattan and the Chapel of St. Cornelius the Centurion on Governors Island—and Columbia University was founded on the church''s grounds as King''s College in 1754. The current building is the third for the parish: the first, built in 1698, was destroyed in the Great New York City Fire of 1776; the second was consecrated in 1790; and the present Gothic Revival structure, designed by Richard Upjohn, was erected from 1839 to 1846. It was the tallest building in the United States until 1869 and the tallest in New York City until 1890. The church adjoins Trinity Churchyard, a historic burial ground, and the parish manages real estate worth billions of dollars. Trinity''s main church is a National Historic Landmark, a New York City designated landmark, and a contributing property to the Wall Street Historic District.'
WHERE slug = 'trinity-church';

UPDATE poi SET
  summary = 'Trump Tower is a 58-story, 664-foot mixed-use skyscraper at 721–725 Fifth Avenue in Midtown Manhattan, between East 56th and 57th Streets. It houses the headquarters of the Trump Organization and the penthouse residence of its developer, Donald Trump. Completed in 1983 on the former site of the Bonwit Teller department store, it is known for its brass-and-marble public atrium.',
  description = 'Trump Tower is a 58-story, 664-foot-tall mixed-use condominium skyscraper at 721–725 Fifth Avenue in the Midtown Manhattan neighborhood of New York City, between East 56th and 57th Streets. The building contains the headquarters of the Trump Organization, as well as the penthouse residence of its developer, the businessman and now U.S. president Donald Trump, and several members of the Trump family have lived there. The tower stands on a plot formerly occupied by the flagship store of the Bonwit Teller department-store chain. Der Scutt of Swanke Hayden Connell Architects designed the tower, which Trump developed with the Equitable Life Assurance Company. Though it sits in one of Midtown''s special zoning districts, it was approved as a mixed-use development, and Trump was permitted to add stories in return for additional retail space and privately owned public space on the ground floor, lower level, and two outdoor terraces. Controversies during construction included the destruction of historically important sculptures from the Bonwit Teller store, alleged underpayment of contractors, and a lawsuit Trump filed because the tower was not tax-exempt. Construction began in 1979, and the atrium, apartments, offices, and stores opened on a staggered schedule from February to November 1983; the residential units sold out within months, though commercial tenants were initially few.'
WHERE slug = 'trump-tower';

UPDATE poi SET
  summary = 'Union Square is a historic public square and surrounding neighborhood in Manhattan, where Broadway meets Park Avenue South between 14th and 17th Streets. A longtime hub of commerce, transit, and civic activity, it is known for its greenmarket, its statues, and its role as a gathering and protest site.',
  description = 'Union Square is a prominent public square and neighborhood in Manhattan, centered on the meeting of Broadway and Park Avenue South (the former Bowery Road) between 14th and 17th Streets—the "union" of thoroughfares that gives it its name. Since the 19th century it has been a focal point of the city: a fashionable shopping and theater district, a center of political rallies and labor demonstrations, and a major transit hub above one of the busiest subway stations in New York. At its heart, Union Square Park provides open space, playgrounds, and statues of figures including George Washington and Abraham Lincoln. The square is especially known for the Union Square Greenmarket, one of the city''s largest and most popular farmers'' markets, which fills the north end several days a week with regional produce and goods. Ringed by shops, restaurants, and academic buildings, Union Square remains one of Manhattan''s liveliest civic gathering places.'
WHERE slug = 'union-square';

UPDATE poi SET
  summary = 'Union Square Park is a historic public square and park in Manhattan, at the meeting of Broadway and Park Avenue South between 14th and 17th Streets. Named for the "union" of two major early-19th-century thoroughfares, it is a longtime civic gathering and protest site maintained by the city parks department. The park holds statues of Washington, Lincoln, Lafayette, and Gandhi and hosts a popular greenmarket.',
  description = 'Union Square is a historic intersection, park, and surrounding neighborhood in Manhattan, formed where Broadway and the former Bowery Road—now Park Avenue South—came together in the early 19th century; its name denotes "the union of the two principal thoroughfares of the island." The current Union Square Park is bounded by 14th Street on the south, 17th Street on the north, and Union Square West and East, and is maintained by the New York City Department of Parks and Recreation. It adjoins the Flatiron District, Chelsea, Greenwich Village, the East Village, and Gramercy Park, and is ringed by buildings of The New School and New York University dormitories, the four Zeckendorf Towers, and the mixed-use One Union Square South, whose facade bears the artwork and digital clock "Metronome." The park contains an assortment of public art, including statues of George Washington, the Marquis de Lafayette, Abraham Lincoln, and Mahatma Gandhi. Long a center of civic life and political demonstrations, it also hosts a well-known greenmarket. Beneath the square lies the 14th Street–Union Square subway station, one of the busiest in the city, served by numerous lines.'
WHERE slug = 'union-square-park';

UPDATE poi SET
  summary = 'Village East by Angelika is a historic movie theater at Second Avenue and 12th Street in the East Village of Manhattan, operated as part of the Angelika group. Housed in a landmark former Yiddish theater, it screens a mix of mainstream and independent films beneath an ornate domed auditorium.',
  description = 'Village East by Angelika is a movie theater at Second Avenue and 12th Street in the East Village of Manhattan, run as part of the Angelika Film Center family of cinemas. The building was constructed in 1926 as the Yiddish Art Theatre, a grand playhouse at the heart of the "Yiddish Rialto," the once-thriving Yiddish theater district of the Lower East Side and East Village. Designed with an opulent Moorish-influenced interior crowned by an elaborate domed ceiling, the space later served as a Yiddish and off-Broadway theater before being converted into a multiplex cinema, with its landmark main auditorium preserved beneath the historic dome. Now screening a mix of mainstream Hollywood releases and independent and specialty films, the theater lets moviegoers watch films in a setting of preserved early-20th-century theatrical grandeur. A designated New York City landmark, Village East by Angelika combines a working cinema with one of the finest surviving interiors of the Yiddish theater era.'
WHERE slug = 'village-east-by-angelika';

UPDATE poi SET
  summary = 'The Walter Kerr Theatre, previously the Ritz Theatre, is a Broadway theater at 219 West 48th Street in the Theater District of Midtown Manhattan. Designed by Herbert J. Krapp for the Shubert brothers and opened in 1921, it seats 975 across three levels and is operated by ATG Entertainment. It was renamed in 1990 for theater critic Walter Kerr.',
  description = 'The Walter Kerr Theatre, previously the Ritz Theatre, is a Broadway theater at 219 West 48th Street in the Theater District of Midtown Manhattan. Designed by Herbert J. Krapp and built for the Shubert brothers in 1921, the venue—renamed in 1990 after theatrical critic Walter Kerr—has 975 seats across three levels and is operated by ATG Entertainment. Its facade is plainly designed in patterned brick, and the auditorium contains Adam-style detailing, two balconies, and murals. The Shuberts developed the Ritz after World War I as part of a theatrical complex around 48th and 49th Streets. It opened on March 21, 1921, with the play Mary Stuart and was leased to William Harris Jr. for a decade. After many unsuccessful shows, it was leased to the Works Progress Administration''s Federal Theatre Project from 1936 to 1939, then served as a CBS and NBC broadcasting studio. The Ritz briefly hosted legitimate shows in the early 1940s and again functioned as an ABC studio until 1965. It was abandoned for several years until Eddie Bracken took over in 1970, renovating it and hosting several short-lived shows. During the 1970s the Ritz variously operated as a pornographic theater, vaudeville house, children''s theater, and poster warehouse. Jujamcyn Theaters took over in 1981 and reopened it two years later after an extensive restoration; the theater was renovated again in 1990 and renamed for Kerr. Jujamcyn merged with ATG in 2023, which continues to operate it.'
WHERE slug = 'walter-kerr-theatre';

UPDATE poi SET
  summary = 'The Washington Square Arch is a marble memorial arch at the north end of Washington Square Park in Greenwich Village, Manhattan. Designed by Stanford White and completed in the 1890s, it commemorates the centennial of George Washington''s 1789 inauguration and marks the foot of Fifth Avenue.',
  description = 'The Washington Square Arch, officially the Washington Arch, is a triumphal marble arch standing at the northern edge of Washington Square Park in the Greenwich Village neighborhood of Lower Manhattan, at the foot of Fifth Avenue. Designed by the architect Stanford White of McKim, Mead & White, it was erected to commemorate the centennial of George Washington''s 1789 inauguration as the first president of the United States. A temporary wood-and-plaster arch built for the 1889 celebration proved so popular that a permanent version in Tuckahoe marble was completed in 1892, standing about 77 feet tall. Modeled loosely on ancient Roman triumphal arches and Paris''s Arc de Triomphe, it is adorned with sculptural details, including two statues of Washington—as commander and as president—added on its northern piers in the early 20th century. The arch has become the symbolic gateway to Washington Square Park and a beloved emblem of Greenwich Village, framing views up Fifth Avenue and serving as a backdrop for gatherings, performances, and everyday park life. A designated New York City landmark, it is among the most recognizable monuments in Lower Manhattan.'
WHERE slug = 'washington-square-arch';

UPDATE poi SET
  summary = 'The Westside Theatre is an Off-Broadway performance space at 407 West 43rd Street in the Hell''s Kitchen neighborhood of Manhattan. Housed in a former church, it contains two auditoriums—the roughly 270-seat Upstairs and 249-seat Downstairs theaters.',
  description = 'The Westside Theatre is an Off-Broadway venue at 407 West 43rd Street, between Ninth and Tenth Avenues in the Hell''s Kitchen neighborhood of Manhattan. The building, originally constructed as a church, was converted for theatrical use and now houses two separate auditoriums: the Upstairs Theatre, seating about 270, and the Downstairs Theatre, which features a thrust stage and seats around 249. Formerly known as the Chelsea Theatre Center and later the Westside Arts Theatre, it was renovated in 1991 and has operated since as a well-regarded home for Off-Broadway productions. Its two intimate stages have hosted a wide range of plays, musicals, and long-running commercial productions over the years, making it a fixture of New York''s Off-Broadway scene. The venue''s flexible spaces and location just west of the Theater District have made it a popular home for smaller-scale shows, including comedies and revues that have enjoyed extended runs. As a converted historic building, the Westside Theatre combines an atmospheric setting with a track record of notable Off-Broadway theater.'
WHERE slug = 'westside-theatre';

UPDATE poi SET
  summary = 'The Whitney Museum of American Art is a museum of modern and contemporary American art in the Meatpacking District of Manhattan, by the Hudson River at the southern end of the High Line. Founded in 1930 by Gertrude Vanderbilt Whitney, it focuses on the work of living and 20th-century American artists.',
  description = 'The Whitney Museum of American Art is a leading museum of modern and contemporary American art, located at 99 Gansevoort Street in the Meatpacking District of Manhattan, beside the Hudson River at the southern end of the High Line. It was founded in 1930 by the sculptor, socialite, and patron Gertrude Vanderbilt Whitney, who assembled a collection of American art after the Metropolitan Museum declined her gift, and it has championed living American artists ever since. In 2015 the museum moved downtown to a striking new building designed by architect Renzo Piano, with light-filled galleries, outdoor terraces overlooking the city and river, and flexible spaces for large-scale contemporary work. Its collection spans 20th- and 21st-century American art—painting, sculpture, photography, film, and new media—with significant holdings of artists such as Edward Hopper, Georgia O''Keeffe, and Jasper Johns. The Whitney is especially known for the Whitney Biennial, a closely watched survey of current American art that has helped define contemporary trends since the 1930s. Combining a bold building, a deep collection, and a focus on the new, the Whitney is a centerpiece of the downtown cultural scene.'
WHERE slug = 'whitney-museum-of-american-art';

UPDATE poi SET
  summary = 'The Winter Garden Theatre is a Broadway theater at 1634 Broadway in the Theater District of Midtown Manhattan. Operated by the Shubert Organization, the large house—seating about 1,500—has hosted some of Broadway''s longest-running musicals, including "Cats" and "Mamma Mia!."',
  description = 'The Winter Garden Theatre is a Broadway house at 1634 Broadway, between 50th and 51st Streets, in the Theater District of Midtown Manhattan. The site opened as a theater in 1911, and the venue was substantially remodeled by architect Herbert J. Krapp in the 1920s. Operated by the Shubert Organization, it is one of Broadway''s larger theaters, seating around 1,500, with an unusually wide auditorium well suited to spectacular musicals. Over its history the Winter Garden has been home to landmark long-running productions, most famously Andrew Lloyd Webber''s "Cats," which played there from 1982 to 2000, followed by hits such as "Mamma Mia!" and "School of Rock"; in earlier eras it hosted revues and star vehicles, including those of Al Jolson. Its facade and interior are New York City landmarks, and the Winter Garden remains one of the premier stages for big Broadway musicals.'
WHERE slug = 'winter-garden-theatre';

UPDATE poi SET
  summary = 'Wollman Rink is a public ice rink in the southern part of Central Park in Manhattan, named for the Wollman family, who funded its original construction. It is open for skating from late October to early April. From 2003 to 2019 it also hosted Victorian Gardens, a seasonal children''s amusement park, in the warmer months.',
  description = 'Wollman Rink is a public ice rink in the southern part of Central Park, Manhattan. It is named after the Wollman family, who donated the funds for its original construction. The rink is open for ice skating from late October to early April. From 2003 until 2019, Victorian Gardens, a seasonal amusement park for children, was operated on the site from late May to September. Wollman Rink opened in 1950, having been proposed four years earlier. It was closed for renovations in late 1980 and reopened in November 1986. Following the renovation, the Trump Organization operated the rink under contract with the New York City government until 1995 and again from 2001 until 2021, when control passed to Wollman Park Partners, a joint venture of Harris Blitzer Sports & Entertainment, the Related Companies, and Equinox Group.'
WHERE slug = 'wollman-rink';

COMMIT;
